/* ---------- FLASHCARDS (spaced repetition) ---------- */
const FLASHCARDS = [
  // AI / RAG
  { id:'fc-rag-1', cat:'ai', module:'ai-rag', lesson:'rag-1', q:'When should you NOT build a RAG pipeline for an LLM application?', a:'**Skip RAG when:**\n- Your knowledge base fits in the model\'s context window (Claude Sonnet/Opus 4.6+ ship a 1M-token window GA at standard pricing)\n- Answers don\'t depend on private or fresh data\n\n**Why:** full-context loading + prompt caching is often faster and cheaper than building retrieval infra.' },
  { id:'fc-rag-2', cat:'ai', module:'ai-rag', lesson:'rag-3', q:'When should you use sparse, dense, or hybrid retrieval for a RAG system?', a:'**Sparse (BM25)** -- rare terms, codes, names, exact tokens.\n\n**Dense (vector)** -- paraphrase and semantic intent.\n\n**Hybrid + reciprocal rank fusion** -- the production default.\n\n**On top:** a cross-encoder re-ranker over top-k for the final ordering.' },
  { id:'fc-rag-3', cat:'ai', module:'ai-prompt', lesson:'pr-3', q:'Why do you set temperature=0 for extraction tasks, and what\'s the right range for creative tasks?', a:'**T=0 for extraction:**\n- Determinism\n- Minimum hallucination\n- Pairs naturally with structured outputs + retry-on-invalid\n\n**T=0.5--0.8 for creative tasks** -- writing, ideation, summary variation.' },
  { id:'fc-rag-4', cat:'ai', module:'ai-evals', lesson:'ev-1', q:'What are the three layers of LLM evaluation, and what does each layer test?', a:'**Unit** -- deterministic checks per request.\n- Schema / regex / length / refusal\n\n**System** -- offline golden Q->A sets.\n- LLM-as-judge + human spot-check\n\n**Production** -- online behavior on real traffic.\n- Thumbs / escalation rate / regret' },
  { id:'fc-rag-5', cat:'ai', module:'ai-agents', lesson:'ag-1', q:'What\'s the real distinction between an LLM \'agent\' and an LLM \'chain\'?', a:'**Chain** -- fixed graph; the LLM only fills in steps you defined.\n\n**Agent** -- the LLM chooses the next step, including which tool to call.\n\n**Tradeoff:** agents trade determinism for flexibility. Most things called \'agents\' should actually be chains.' },
  // Decomp
  { id:'fc-dec-1', cat:'decomp', module:'decomp-101', lesson:'d-5', q:'In a Palantir-style FDE problem-decomposition / case interview (e.g. \'design a 911 dispatch triage system\'), what is the #1 instant-reject signal?', a:'**Antipattern:** jumping straight to tools or solutions before scoping the problem.\n\nRed flags that get you rejected:\n- Naming `Kafka`, `Snowflake`, or \'an LLM\' in the first 60 seconds\n- Proposing an architecture before asking who the users are\n- Skipping the success metric, data sources, and constraints\n- Treating the prompt as a complete spec instead of a starting point\n\n**Senior move:** spend the first 10-15 min in the problem space before drawing a single box.' },
  { id:'fc-dec-2', cat:'decomp', module:'decomp-101', lesson:'d-2', q:'What is the 5-step decomposition framework for a Palantir-style FDE case (e.g. designing a 911 dispatch triage tool)?', a:'1. **Clarify** - success metric, users, data available, constraints (latency, budget, regulation)\n2. **Stakeholder map** - dispatchers, callers, on-call engineers, legal/compliance, the person who can kill the project\n3. **Data sources** - call audio, CAD logs, GPS, historical incident outcomes; what is `Inputs` to the system\n4. **Tradeoffs** - two phased options with explicit pros/cons and a recommendation\n5. **Failure modes** - 3 specific failures, each with detection + rollback' },
  // Coding
  { id:'fc-cod-1', cat:'coding', module:'cod-graphs', lesson:'g-1', q:'What are the essential pieces of a BFS template for graph traversal?', a:'**Approach:** Use a `deque` plus a `visited` set. Mark nodes visited at **enqueue time**, not dequeue, to avoid the same node being queued by every neighbor before it\'s processed. Track depth by either a separate counter or by looping over `len(queue)` for one level at a time.\n\n**Complexity:** `O(V + E)` time, `O(V)` space.' },
  { id:'fc-cod-2', cat:'coding', module:'cod-prod', lesson:'p-LC1', q:'How do you implement an LRU cache with O(1) get and put?', a:'**Approach:** Combine a hash map (`key -> node`) with a **doubly linked list** ordered by recency. On `get`/`put`: detach the node from its current spot, splice it at the head, and evict the tail when over capacity.\n\n- Hash map gives `O(1)` lookup\n- Doubly linked list gives `O(1)` detach + insert\n- Use a sentinel head/tail to skip null checks\n\n**Complexity:** `O(1)` get/put, `O(capacity)` space.' },
  // System design
  { id:'fc-sd-1', cat:'sysd', module:'sd-classic', lesson:'sd-1', q:'What 4-step frame should you use to structure a system design interview answer?', a:'**Step 1 - Requirements:** functional needs plus non-functional (`QPS`, latency, consistency, durability).\n\n**Step 2 - Capacity estimate:** back-of-envelope numbers (users, writes/sec, storage growth).\n\n**Step 3 - High-level boxes:** API gateway, services, storage, async pipeline.\n\n**Step 4 - Deep dive:** pick one hard subproblem the interviewer signals interest in and go deep.' },
  { id:'fc-sd-2', cat:'sysd', module:'sd-fde', lesson:'fd-1', q:'When designing a multi-tenant SaaS database, how do silo, pool, and bridge isolation compare?', a:'**Silo** (DB per tenant)\n- Max isolation, easiest compliance story\n- Highest cost, hardest cross-tenant analytics\n\n**Pool** (shared DB + shared schema, `tenant_id` column)\n- Cheapest, easy ops\n- Noisy-neighbor risk; auditors distrust app-level filtering\n\n**Bridge** (shared instance, schema per tenant)\n- Logical isolation, per-tenant migrations\n- Middle-ground cost and isolation\n\nMatch the pattern to the customer\'s compliance posture.' },
  { id:'fc-sd-3', cat:'sysd', module:'sd-fde', lesson:'fd-2', q:'What belongs on a production webhook reliability checklist when you\'re the sender?', a:'- **HMAC sign** every payload over `(timestamp + raw body)`\n- Require client-supplied **idempotency keys**\n- **Exponential backoff** retries with a DLQ for poison messages\n- Dashboard for **manual replay**\n- Signed **timestamp + skew window** (e.g., 5 min) to block replay attacks\n- Documented **delivery-latency SLA** so consumers can alert' },
  // Behavioral
  { id:'fc-beh-1', cat:'behav', module:'b-stories', lesson:'b-6', q:'How should you weight the four STAR sections (Situation, Task, Action, Result) when answering behavioral questions in a Forward Deployed Engineer (FDE) loop?', a:'**Target weighting per beat:**\n\n- **Situation (~10%)** -- 2-3 sentences max of context.\n- **Task (~10%)** -- one line scoping YOUR ownership (FDE rounds probe individual accountability).\n- **Action (~60%)** -- the specific technical and customer decisions you made.\n- **Result (~20%)** -- both the technical outcome and the quantified business impact.' },
  { id:'fc-beh-2', cat:'behav', module:'b-stories', lesson:'b-1', q:'Which five stories should every candidate have rehearsed before a Forward Deployed Engineer (FDE) interview loop?', a:'**The five mandatory FDE stories:**\n\n- 1. Production fix under live customer pressure.\n- 2. Pushing back on a client request.\n- 3. Owning a deployment failure end-to-end.\n- 4. Explaining a hard technical limit to a non-technical stakeholder.\n- 5. Making a decision with incomplete information.' },
  // Client sim
  { id:'fc-cli-1', cat:'client', module:'cli-roleplay', lesson:'c-1', q:'A customer\'s production integration just went down during their launch window and they call you furious. How do you run the ADO framework live?', a:'**Acknowledge:** mirror the impact in their words, not boilerplate.\n- \'I hear this is blocking your launch today.\'\n\n**Diagnose:** think out loud so they see motion.\n- \'Pulling the logs now, can you confirm the last known good time?\'\n\n**Offer:** commit a concrete next checkpoint with an owner.\n- \'Fix or workaround by 4pm, written update either way.\'\n\nNever blame their environment in the moment.' },
  // SQL
  { id:'fc-sql-1', cat:'data', module:'data-sql', lesson:'sq-1', q:'Which SQL window functions show up most in interviews, and what does each do?', a:'- **`ROW_NUMBER()`** -- unique sequential number per partition, arbitrary tiebreak\n- **`RANK()`** -- ties share a rank, leaves gaps\n- **`DENSE_RANK()`** -- ties share a rank, no gaps\n- **`LAG(col, n)` / `LEAD(col, n)`** -- previous/next nth row in the partition\n- **`SUM() / AVG() OVER (PARTITION BY ... ORDER BY ...)`** -- running aggregates without collapsing rows\n\nMost SQL screens hide one of these inside a wordy prompt.' },
  { id:'fc-sql-2', cat:'data', module:'data-pipe', lesson:'pp-3', q:'What is the NULL trap with `NOT IN` vs `NOT EXISTS` in SQL subqueries?', a:'- **`NOT IN`** -- if the subquery returns any `NULL`, the comparison evaluates to unknown, so the whole predicate returns no rows\n- **`NOT EXISTS`** -- NULL-safe and semantically equivalent for antijoins\n\n**Rule:** default to `NOT EXISTS` for antijoin filters.' },
  // Cloud
  { id:'fc-cl-1', cat:'cloud', module:'cl-integ', lesson:'in-1', q:'What are the OAuth 2.1 grant types in 2026 and which ones were removed?', a:'**Active grants:**\n- **Authorization Code + PKCE** required for ALL clients (web, SPA, mobile, native). OAuth 2.1 removed the public/confidential distinction for PKCE.\n- **Client Credentials** for server-to-server.\n- **Device Code** for TV/CLI.\n\n**Removed:**\n- Implicit grant.\n- Resource Owner Password Credentials (ROPC).' },

  // ===== Expansion: 45+ more cards across all categories =====

  // AI / LLM expansion
  { id:'fc-ai-6', cat:'ai', module:'ai-prompt', lesson:'pr-2', q:'Why does chain-of-thought (CoT) prompting improve LLM accuracy on reasoning tasks?', a:'Each token\'s prediction can attend to all prior tokens.\n\n**With CoT** -- reasoning is written FIRST, so the answer benefits from the compute spent on those reasoning tokens.\n\n**Without CoT** -- the answer comes before any reasoning tokens exist, so no reasoning compute can be applied.' },
  { id:'fc-ai-7', cat:'ai', module:'ai-agents', lesson:'ag-4', q:'What\'s the production pattern for getting both chain-of-thought reasoning AND a machine-readable output from one LLM call?', a:'Use the provider\'s native split between thinking and answer:\n- **Anthropic** -- extended thinking blocks\n- **OpenAI** -- Structured Outputs with reasoning models\n\n**Result:** reasoning lives in a separate thinking block; the final answer is schema-validated JSON.\n\n**Operationally:** log reasoning for debugging; return only the validated JSON to users.' },
  { id:'fc-ai-8', cat:'ai', module:'ai-finetune', lesson:'ft-2', q:'When is fine-tuning the right call instead of RAG or better prompting?', a:'**Three legitimate reasons:**\n- Narrow classification with a tight latency budget\n- Proprietary format / jargon / style the base model lacks\n- Distillation -- shrinking a large model into a smaller, cheaper one\n\n**Never:** to \'teach the model facts\' -- that\'s what RAG is for.' },
  { id:'fc-ai-9', cat:'ai', module:'ai-agents', lesson:'ag-3', q:'What are the six controls you use to bound autonomy for a production LLM agent?', a:'- **Action allowlist** -- only pre-approved tools\n- **Per-conversation spend cap** -- hard dollar limit\n- **Max-step budget** -- prevent unbounded loops\n- **Human-in-the-loop** -- required for irreversible actions\n- **Per-step observability** -- log every input/output\n- **Wall-clock limits** -- catch runaway processes' },
  { id:'fc-ai-10', cat:'ai', module:'ai-agents', lesson:'ag-6', q:'What is the dominant failure mode in multi-agent LLM systems, and how do you fix it?', a:'**Failure mode:** inter-agent coordination failures dominate (~37% of multi-agent bug reports per Cemri et al. 2025).\n\n**Biggest sub-pattern:** the receiving agent missing context the sender assumed it had -- wrong assumptions, dropped history, mismatched reasoning vs action.\n\n**Fix:**\n- Full trajectory logging\n- Explicit state passing between agents\n- Shared scratchpads instead of implicit handoffs' },
  { id:'fc-ai-11', cat:'ai', module:'ai-prompt', lesson:'pr-3', q:'Why is temperature=0 not perfectly deterministic on modern LLM APIs?', a:'**Root cause:** floating-point math is non-associative, and batched GPU inference reorders reductions depending on batch size and kernel scheduling.\n\n**Effect:** identical inputs at T=0 can produce slightly different logits and occasionally different tokens.\n\n**Practical rule:** treat T=0 as \'very stable,\' not \'deterministic.\' Always validate output and retry-on-invalid.' },
  { id:'fc-ai-12', cat:'ai', module:'ai-rag', lesson:'rag-4', q:'Which embedding model should you choose for a customer that requires VPC-only deployments with no outbound network egress?', a:'**Pick:** self-hosted open-source models.\n- BGE-M3 (Apache 2.0)\n- Nomic Embed\n- GTE\n\n**Avoid:** API-based embeddings (OpenAI, Cohere, Voyage) -- they need outbound calls.\n\n**Exception:** a provider\'s private-deployment contract that runs their model inside the customer\'s VPC.' },
  { id:'fc-ai-13', cat:'ai', module:'ai-rag', lesson:'rag-6', q:'What is the classic anti-pattern when defending an LLM app against prompt injection?', a:'**Anti-pattern:** relying on the LLM\'s own judgment to enforce policy.\n\n**Why it fails:** the LLM is generative -- it can be fooled by adversarial input.\n\n**Right approach:** add deterministic validators between LLM output and side effects (refunds, emails, deploys). Code, not vibes, gates real-world actions.' },
  { id:'fc-ai-14', cat:'ai', module:'ai-evals', lesson:'ev-5', q:'What are the four RAGAS metrics used to evaluate a RAG pipeline, and what does each measure?', a:'- **Faithfulness** -- answer uses retrieved context, not hallucinated content\n- **Answer relevance** -- response actually addresses the question\n- **Context precision** -- retrieved chunks are on-topic\n- **Context recall** -- retriever surfaces the chunks needed to answer' },
  { id:'fc-ai-15', cat:'ai', module:'ai-rag', lesson:'rag-10', q:'When should you load the entire knowledge base into context instead of building a RAG pipeline?', a:'**When all of these hold:**\n- The corpus fits in the model\'s context window (Claude Sonnet/Opus 4.6+ support 1M tokens GA)\n- Prompt caching is available\n- You can tolerate per-call input cost\n\n**Wins:**\n- Simpler architecture (no retrieval infra)\n- Cache reads ~10% of input price\n- Zero retrieval-miss risk' },

  // Coding expansion
  { id:'fc-cod-3', cat:'coding', module:'cod-arrays', lesson:'a-1', q:'When does the two-pointer pattern apply on an array?', a:'**Trigger conditions:**\n\n- Array is **sorted** (or sortable as a preprocessing step)\n- Each step provably **rules out** one end (e.g., sum too small means move left up)\n- Looking for pairs, palindromes, partitions, or in-place rewrites\n- Want to drop from `O(n^2)` brute force to `O(n)` sweep\n\nIf no monotone rule-out argument exists, prefer hashing or sliding window.' },
  { id:'fc-cod-4', cat:'coding', module:'cod-arrays', lesson:'a-2', q:'Sliding window: when do you pick a fixed-size window versus a variable-size one?', a:'- **Fixed window:** size `k` is given by the problem (e.g., max sum of subarray of size `k`, average of last `k`). Slide as a rigid block.\n- **Variable window:** grow `right` to include more, shrink `left` while an invariant is violated (e.g., longest substring with no repeats, smallest subarray with sum >= target).\n\n**Rule of thumb:** if the question fixes the size, use fixed; if it asks for the longest/shortest/best window satisfying a property, use variable.' },
  { id:'fc-cod-5', cat:'coding', module:'cod-arrays', lesson:'a-3', q:'What is the binary-search-on-the-answer pattern and when does it apply?', a:'**Approach:** When the answer space is **monotonic** (some predicate `can_do(x)` flips from `false` to `true` exactly once), binary-search the boundary by evaluating `can_do(mid)` each step.\n\n- Classic: smallest ship capacity to ship in `D` days\n- Classic: split array into `k` parts minimizing max sum\n- Classic: smallest eating speed for Koko\n\n**Complexity:** `O(log(range) * cost(predicate))`.' },
  { id:'fc-cod-6', cat:'coding', module:'cod-graphs', lesson:'g-6', q:'What two optimizations make Union-Find effectively constant-time?', a:'- **Path compression in `find`:** point every traversed node directly to the root.\n- **Union by rank/size:** attach the smaller tree under the larger one.\n\n**Complexity:** with both, each op runs in `O(alpha(N))` amortized, effectively constant. Without them, naive DSU degrades to `O(N)` per op on adversarial inputs.' },
  { id:'fc-cod-7', cat:'coding', module:'cod-advgraphs', lesson:'ag-cod-1', q:'How do Dijkstra and Bellman-Ford compare for single-source shortest paths?', a:'- **`Dijkstra`:** non-negative weights only, `O((V + E) log V)` with a min-heap. Locks in each node\'s distance the moment it\'s popped.\n- **`Bellman-Ford`:** handles negative weights, `O(V * E)`. Also detects negative cycles via one extra relaxation pass.\n\n**Why negatives break Dijkstra:** the "once-extracted-is-final" invariant assumes future paths can only add cost. A negative edge can later beat the locked-in distance.' },
  { id:'fc-cod-8', cat:'coding', module:'cod-advgraphs', lesson:'ag-cod-3', q:'When should you reach for a monotonic stack?', a:'**Trigger conditions:**\n\n- Asking for **next greater / next smaller** element\n- Need contributions bounded by "how far does this element dominate?"\n- Histograms, rain trap variants, daily temperatures, stock spans\n\n**Mechanics:** maintain a stack monotone in one direction; each incoming element pops violators until order is restored. Each element pushed and popped at most once.\n\n**Complexity:** `O(n)` time, `O(n)` space.' },
  { id:'fc-cod-9', cat:'coding', module:'cod-advgraphs', lesson:'ag-cod-4', q:'How do you find the single non-duplicate value when every other number appears twice?', a:'**Approach:** XOR all values together. Identical pairs cancel (`x ^ x = 0`) and the lone singleton remains because `x ^ 0 = x`.\n\n**Complexity:** `O(n)` time, `O(1)` space. No hash set needed.' },
  { id:'fc-cod-10', cat:'coding', module:'cod-advgraphs', lesson:'ag-cod-2', q:'How does Kahn\'s topological sort detect cycles?', a:'**Approach:** Repeatedly remove nodes with in-degree `0`, appending each to the output. If the final order has **fewer than `N` nodes**, some node never reached in-degree `0`, which means it sits on a cycle.\n\n**Complexity:** `O(V + E)`. Cycle detection comes free with the sort.' },
  { id:'fc-cod-11', cat:'coding', module:'cod-advgraphs', lesson:'ag-cod-4', q:'When does bitmask DP apply?', a:'**Trigger conditions:**\n\n- State must track **which subset** of `N` items has been used/visited\n- `N` is small, roughly `<= 20` (so `2^N` masks fit in memory and time)\n- Subproblems compose: result for mask `m` depends only on results for sub-masks\n\n**Classic examples:** Traveling Salesman, set cover, assignment problems.\n\n**Complexity:** typically `O(2^N * N)` or `O(2^N * N^2)`.' },

  // System Design expansion
  { id:'fc-sd-4', cat:'sysd', module:'sd-classic', lesson:'sd-8', q:'In consistent hashing, what is the cost of adding the Nth node to the ring?', a:'Roughly **`1/N` of keys remap** to the new node.\n\nWith **virtual nodes** (typically 100-200 vnodes per physical server), the load redistributes evenly across all existing nodes instead of being yanked from a single neighbor.\n\nWithout vnodes, the new node would inherit one neighbor\'s slice and create a hot spot.' },
  { id:'fc-sd-5', cat:'sysd', module:'sd-classic', lesson:'sd-9', q:'How do CAP and PACELC differ, and why is PACELC more useful in practice?', a:'**CAP:** during a network partition, you must choose **Consistency or Availability**.\n\n**PACELC:** adds the **E**lse clause: when there\'s no partition, you still trade **Latency vs Consistency**.\n\nPACELC is more useful because it covers the **steady-state** tradeoff (which is 99.9% of the time), not just the failure mode.' },
  { id:'fc-sd-6', cat:'sysd', module:'sd-classic', lesson:'sd-4', q:'When designing a social feed, when do you pick push fan-out, pull fan-out, or a hybrid?', a:'**Push** (fan-out-on-write)\n- Low read latency; precomputed timelines\n- Write amplification for users with millions of followers\n\n**Pull** (fan-out-on-read)\n- Cheap writes\n- Expensive reads for users who follow many accounts\n\n**Hybrid**\n- Push for normal users, pull for celebrities above a follower threshold\n- Best of both; standard at Twitter/Instagram scale' },
  { id:'fc-sd-7', cat:'sysd', module:'sd-classic', lesson:'sd-pay', q:'Why are idempotency keys non-negotiable for any side-effecting API like payments or email sends?', a:'**Mechanism:**\n- Client generates a unique key per logical operation (`charge_card`, `send_email`, `deploy`)\n- Server stores `(key, response)` in a dedupe table\n- Duplicate requests return the **cached response** instead of re-executing\n\n**Without this:** network retries, agent loops, and at-least-once queues cause **double-charges** and duplicate side effects.' },
  { id:'fc-sd-8', cat:'sysd', module:'sd-classic', lesson:'sd-3', q:'Why does naive per-server in-memory rate limiting fail in a load-balanced fleet?', a:'**Symptom:** a client hitting `N` servers can exceed the cap by `N`x. A 100 req/sec limit becomes 1000 req/sec across 10 instances.\n\n**Cause:** each server tracks counters **independently** with no shared state.\n\n**Fix:** centralized `Redis` sliding-window counter, mutated by a **Lua script** so the read-modify-write is atomic across all app servers.' },
  { id:'fc-sd-9', cat:'sysd', module:'sd-fde', lesson:'fd-1', q:'Which multi-tenancy isolation pattern should you propose for a regulated enterprise customer demanding data residency?', a:'**Silo** (DB-per-tenant) is the default safe answer, or at minimum **bridge** (schema-per-tenant).\n\n**Why pool fails:**\n- Tenant separation is enforced in **app code** via `tenant_id` filters\n- Auditors treat this as insufficient for `HIPAA`, `SOC 2 Type II`, or `GDPR` data-residency claims\n- One missing `WHERE tenant_id = ?` clause leaks data across tenants' },

  // SQL & Data expansion
  { id:'fc-sql-3', cat:'data', module:'data-pipe', lesson:'pp-4', q:'Given a composite index on `(a, b)`, which queries can actually use it?', a:'**Leftmost-prefix rule:** the index is usable only when the query references the leftmost column.\n\n- Uses index: `WHERE a = X`, `WHERE a = X AND b = Y`, `ORDER BY a`\n- Uses index: `WHERE a = X AND <anything else>`\n- **Cannot** use index: `WHERE b = Y` alone -- skips the leading column' },
  { id:'fc-sql-4', cat:'data', module:'data-pipe', lesson:'pp-5', q:'What does a Slowly Changing Dimension (SCD) Type 2 schema look like in a warehouse?', a:'Each row carries history columns:\n- **`valid_from`** -- when this version became active\n- **`valid_to`** -- when superseded (`NULL` = current)\n- **`is_current`** -- boolean flag for cheap filtering\n\n**Update flow:** close the old row (`valid_to = now()`), insert a new one. Queries filter to the period of interest.\n\n**Example:** `WHERE valid_from <= \'2026-01-01\' AND (valid_to IS NULL OR valid_to > \'2026-01-01\')`' },
  { id:'fc-sql-5', cat:'data', module:'data-pipe', lesson:'pp-6', q:'What is the difference between Change Data Capture (CDC) and polling for warehouse sync?', a:'**CDC**\n- Reads the DB transaction log (Postgres `WAL`, MySQL `binlog`)\n- Captures `INSERT`, `UPDATE`, and `DELETE` events\n- Low overhead, scales to high write volume\n\n**Polling**\n- Periodic `SELECT ... WHERE updated_at > last_run`\n- Misses deletes entirely\n- Burns DB CPU at scale\n\n**Default:** CDC for anything beyond toy volume.' },
  { id:'fc-sql-6', cat:'data', module:'data-pipe', lesson:'pp-2', q:'What are the 5 tiers of data-quality checks a pipeline should run?', a:'1. **Schema** -- column types present, non-null constraints honored\n2. **Volume** -- row count within expected band vs historical average\n3. **Freshness** -- latest event timestamp within `N` minutes\n4. **Distribution** -- category proportions and numeric ranges in bounds\n5. **Referential** -- foreign keys resolve to a parent row\n\n**Tools:** `dbt tests`, Great Expectations, Soda.' },
  { id:'fc-sql-7', cat:'data', module:'data-pipe', lesson:'pp-1', q:'What is the idempotent partitioned-write pattern for batch pipelines?', a:'For each scheduled run of date `D`:\n1. `DELETE FROM target WHERE date = D`\n2. `INSERT INTO target SELECT ... WHERE date = D`\n\n**Why it works:** re-running the same task converges to the same state -- safe for backfills and retries.\n\n**Anti-pattern:** plain `APPEND` without a partition key -- every backfill duplicates rows.' },

  // Behavioral expansion
  { id:'fc-beh-3', cat:'behav', module:'b-values', lesson:'v-3', q:'Palantir is known for grilling candidates on failure stories. What bar must your story clear, and what openers get you rejected on the spot?', a:'**What clears the bar:** real, specific, owned, with the actual mechanism, the cost incurred, and the systemic change you made afterward.\n\n**Instant-reject openers:**\n\n- `I work too hard`\n- `I\'m a perfectionist`\n- `I helped with...` (signals no ownership)' },
  { id:'fc-beh-4', cat:'behav', module:'b-values', lesson:'v-1', q:'What OpenAI Charter principles and recent corporate context (as of 2026) should you know before an OpenAI Forward Deployed Engineer (FDE) interview?', a:'**Four Charter principles:**\n\n- Broadly Distributed Benefits\n- Long-Term Safety\n- Technical Leadership\n- Cooperative Orientation\n\n**Corporate context:** as of Oct 2025, OpenAI restructured -- the for-profit is now **OpenAI Group PBC** under the **OpenAI Foundation** (nonprofit).\n\nExample: bring a role-specific reason for FDE (customer-facing deployment work), not a generic `I love the mission` line.' },
  { id:'fc-beh-5', cat:'behav', module:'b-values', lesson:'v-2', q:'What Anthropic values and safety artifacts should you be ready to discuss in an Anthropic interview?', a:'**Key artifacts to know:**\n\n- **AI safety + beneficial AI** as the core thesis.\n- **Constitutional AI** -- the training approach.\n- **Responsible Scaling Policy (RSP v3.0, Feb 2026)** -- two-track model (Anthropic-only mitigations + industry-wide map) plus a public Frontier Safety Roadmap.\n\nExpect ethical-dilemma scenarios. Show depth on safety reasoning -- generic concern reads as a miss.' },
  { id:'fc-beh-6', cat:'behav', module:'b-stories', lesson:'b-6', q:'When an interviewer asks why you are leaving your current role, what framing lands best?', a:'**Pull, not push:**\n\n- Lead with what attracts you to the **new** role (scope, mission, problem space).\n- Keep references to your current employer light-positive.\n- Avoid badmouthing -- it signals you will describe the next employer the same way in a year.' },
  { id:'fc-beh-7', cat:'behav', module:'b-fivestories', lesson:'bs-2', q:'Amazon-style `disagree and commit` prompts trip up most candidates. Which half of the arc do they skip, and what does a complete answer look like?', a:'**The half skipped:** the **commit** half. A story where you disagreed AND won is incomplete.\n\n**Stronger arc:**\n\n- 1. Disagreed and brought data.\n- 2. Lost the decision.\n- 3. Executed the team\'s choice fully and visibly.\n- 4. Validated their view in hindsight (or named what you learned).' },
  { id:'fc-beh-8', cat:'behav', module:'b-stories', lesson:'b-1', q:'Name the five stories every Forward Deployed Engineer (FDE) candidate must have ready.', a:'**Five mandatory FDE stories:**\n\n- 1. Production fix under pressure.\n- 2. Pushing back on a customer.\n- 3. Deployment failure ownership.\n- 4. Explaining a technical limit.\n- 5. Decision under incomplete info.' },

  // Cloud expansion
  { id:'fc-cl-2', cat:'cloud', module:'cl-integ', lesson:'in-2', q:'What belongs on a production-grade webhook reliability checklist?', a:'- **HMAC sign** timestamp + body to prove sender identity.\n- **Idempotency** via stable `event_id` per logical event.\n- **Exponential backoff** retries on 5xx and timeouts only (never 4xx).\n- **DLQ** after N fails so bad events do not block the queue.\n- **Replay dashboard** for ops to re-fire events.\n- **Documented SLA** for delivery latency.' },
  { id:'fc-cl-3', cat:'cloud', module:'cl-integ', lesson:'in-4', q:'What are the three pillars of observability and what does each one solve?', a:'- **Logs** answer \'why did this request fail?\' via discrete event records.\n- **Metrics** answer \'is something wrong NOW?\' via aggregate time-series for alerting.\n- **Traces** answer \'where in the call graph is the slow span?\' via per-request causal graphs across services.\n\n**OpenTelemetry** unifies emission across vendors so the backend stays portable.' },
  { id:'fc-cl-4', cat:'cloud', module:'cl-integ', lesson:'in-5', q:'Compare canary, blue-green, and rolling deploys and when to use each.', a:'**Canary**\n- Shift traffic 1% then 10% then 50% with metric checks at each step.\n- Use for risky changes when you have good metrics.\n\n**Blue-green**\n- Stand up a full new environment, flip the LB atomically.\n- Use when you need instant rollback.\n\n**Rolling**\n- Replace one instance at a time in place.\n- Use as the cheap default for low-risk changes.' },
  { id:'fc-cl-5', cat:'cloud', module:'cl-integ', lesson:'in-3', q:'What is the practical difference between SAML and OIDC for enterprise SSO?', a:'**SAML**\n- XML-based assertions, browser SSO.\n- Still common with enterprise IdPs (Okta, Entra ID, Ping).\n- Required for legacy IT.\n\n**OIDC**\n- JWT-based, built on OAuth 2.0.\n- Default for new web, mobile, and API integrations.\n\nFor enterprise SaaS in 2026, support both: SAML for legacy IT, OIDC for everything new.' },
  { id:'fc-cl-6', cat:'cloud', module:'cl-integ', lesson:'in-3', q:'What does SCIM do and why do enterprise customers require it?', a:'**SCIM** is a REST API standard for user and group provisioning lifecycle: create, update, disable.\n\nIt lets the customer\'s IdP (Okta, Entra ID) automatically provision and deprovision users in your system as employees join, change roles, or leave.\n\nUse when: selling to enterprise. It is table-stakes for any deal above ~500 seats.' },
  { id:'fc-cl-7', cat:'cloud', module:'cl-core', lesson:'cl-4', q:'What is a DPA (Data Processing Agreement) and what does it cover?', a:'A **DPA** is a GDPR-required contract specifying how a vendor processes the customer\'s personal data.\n\n**Required clauses:**\n- Sub-processor list and notification of changes.\n- Data residency commitments.\n- Breach notification timelines.\n- Right-to-delete and data-export procedures.' },

  // Decomp expansion
  { id:'fc-dec-3', cat:'decomp', module:'decomp-101', lesson:'d-4', q:'In a 60-min Palantir-style decomposition round (e.g. the 911 dispatch prompt), how long should clarifying questions take?', a:'**Time budget:** 10-15 minutes on clarify alone.\n\n- Most candidates rush in under 3 min and start drawing boxes\n- The interviewer is testing whether you can stay in the problem space before solving\n- Discomfort is the signal you are doing it right\n\n**Senior:** lingers past the point where it feels awkward, then states an assumption and moves on.\n**Junior:** leaves step 1 the moment they have a plausible solution.' },
  { id:'fc-dec-4', cat:'decomp', module:'decomp-101', lesson:'d-3', q:'In a decomp round, what is the `Inputs -> Logic -> Outputs` mental model and what goes in each box?', a:'**Pattern:** describe behavior in three boxes before naming any tech.\n\n- **Inputs** - data sources: logs, APIs, files, sensor streams, user actions\n- **Logic** - transformations, decisions, joins, model calls, business rules\n- **Outputs** - what the user sees or acts on: dashboards, alerts, reports, automated actions\n\nNaming `Airflow` or `Kafka` inside a box before you have scoped the problem is an instant-reject signal. Boxes describe behavior until implementation is explicitly on the table.' },
  { id:'fc-dec-5', cat:'decomp', module:'decomp-101', lesson:'d-8', q:'What are the four \'killer phrases\' that signal senior judgment in a Palantir-style decomp round?', a:'1. **\'Before I propose anything...\'** - signals you scope before solving\n2. **\'The simplest version that delivers value...\'** - signals MVP-first thinking and cost awareness\n3. **\'X over Y because of this specific constraint - if it changes I would flip.\'** - explicit tradeoff with conditional commitment\n4. **\'Let me make an explicit assumption: X; please push back.\'** - operates under ambiguity instead of bouncing it back' },

  // Domain expansion
  { id:'fc-dom-1', cat:'domain', module:'dom-hosp', lesson:'dh-1', q:'In hospitality data (venue bookings, shift reports), what\'s the classic timezone gotcha that produces wrong-day reports?', a:'A venue\'s **Saturday night** crosses UTC midnight, so naive day-of-week filtering on UTC timestamps splits a single service across two days.\n\n**Rule:** always convert to **venue-local time** before bucketing by day-of-week or business-day.\n\n- Store timestamps as UTC `timestamptz`\n- Attach the venue\'s IANA zone (e.g. `America/New_York`) to every venue row\n- Compute `local_date` at query time, not at write time (DST changes)\n- A **business day** often ends at 4am local, not midnight' },
  { id:'fc-dom-2', cat:'domain', module:'dom-mkt', lesson:'dm-1', q:'What\'s the standard cold-start playbook for launching a two-sided marketplace?', a:'Two-sided liquidity is the single hardest marketplace problem, so the playbook is to **collapse it into a one-sided problem first**.\n\n- **Pre-seed one side** manually (recruit suppliers door-to-door, or fake demand with concierge ops)\n- **Drive demand to that seeded side** in a single concentrated geo, not nationally\n- **Prove utility in one metro** (NYC, SF) before expanding\n- **Expand city-by-city**, repeating the seed-then-demand loop\n\n**Implication:** spend on supply acquisition early; spend on demand only once supply density clears a usability threshold.' },
  { id:'fc-dom-3', cat:'domain', module:'dom-dev', lesson:'dh-4', q:'When deploying an AI product into a hospital, what\'s the biggest non-technical hurdle and how does it shape your architecture?', a:'The hospital\'s **security and compliance review**, typically **8 to 16 weeks**, gates every deployment regardless of code quality.\n\n- Bake the review window into your project timeline from day one\n- Multi-tenant SaaS is usually **DOA** with hospital infosec\n- Standard pattern is **single-tenant in the customer\'s VPC** (or on-prem)\n- Expect questionnaires (HECVAT, SIG), pen-test reports, and a signed **BAA**\n\n**Implication:** your deploy story (Terraform into customer cloud, air-gap mode) is part of the product, not an afterthought.' },

  // Meta expansion
  { id:'fc-meta-1', cat:'meta', module:'meta-prep', lesson:'me-3', q:'What is the single highest-leverage interview-prep activity per hour invested?', a:'**Record yourself in mocks and watch back at 1.5x speed.**\n\nPainful in week 1, transformative within a week. Catches what self-reflection misses:\n\n- **Speech tics** (filler words, trailing \'right?\', vocal fry)\n- **Length-of-answer issues** (rambling past the point)\n- **Body language** (eye contact, hand jitter, slouching)\n- **Pacing** (where you race, where you stall)' },
  { id:'fc-meta-2', cat:'meta', module:'meta-prep', lesson:'me-8', q:'After a rejection, when (and how) should you ask the recruiter for interview feedback?', a:'**Always, exactly once, professionally.** Most recruiters decline; the few who reply give priceless intel.\n\n**Timing:** within 24h of the rejection email, same thread.\n\n**Script:**\n- **You:** "Thanks for letting me know, I appreciate the update. If you have any feedback from the team on the interview, I would genuinely value even 1-2 sentences to help me improve for next time."\n\nDo not push past one ask. Do not argue the decision.' },
  { id:'fc-meta-3', cat:'meta', module:'meta-prep', lesson:'me-5', q:'On a first recruiter call, how do you respond when asked \'What comp are you looking for?\'', a:'**Deflect to fit first, then anchor with a market band, never a single number.**\n\n- **Recruiter:** "What are you looking for comp-wise?"\n- **You:** "I want to focus on whether the role is a strong fit before talking numbers. That said, market for FDE roles at companies your size is roughly $X to $Y total comp. Happy to get more specific once we are aligned."\n\nThen **stop talking**. Silence after your band is the strongest tool you have.' },
  { id:'fc-meta-4', cat:'meta', module:'meta-prep', lesson:'me-6', q:'What is the resume-bullet formula for FDE / forward-deployed engineering roles?', a:'**[Action verb] [system you owned] [specific technical mechanism] [quantified customer or business outcome].**\n\nRecruiters skim each bullet for 6-20 seconds, so the **verb** and the **number** carry the signal; everything else is supporting context.\n\n- **Good:** "Shipped Postgres -> ClickHouse pipeline cutting customer p95 from 4s to 380ms"\n- **Bad:** "Was responsible for working on database performance improvements"' },

  /* Flashcard bulk expansion — 150+ more cards across categories */
  // Decomp
  { id:'fc-dec-6', cat:'decomp', module:'decomp-101', lesson:'d-8', q:'Senior signal: in a 60-min decomp round, how long should clarifying-question time feel uncomfortable before you start drawing?', a:'**Senior:** stays in clarify for 10-15 min, past the point where they want to start drawing. The discomfort is the signal.\n**Junior:** leaves step 1 the moment they have a plausible solution, usually under 3 min.\n\n- Drawing too early commits you to a shape before you understand the requirements\n- Interviewers explicitly probe whether you can sit in ambiguity\n- The cure for the urge to draw is to state an explicit assumption out loud, then keep clarifying' },
  { id:'fc-dec-7', cat:'decomp', module:'decomp-101', lesson:'d-4', q:'In a decomp round, when the interviewer says \'you decide\' or \'it\'s up to you\' on a scoping question, what do you do?', a:'**Pattern:** make an assumption explicit, write it down, invite pushback.\n\nExample dialog:\n- Interviewer: \'You decide whether it is batch or real-time.\'\n- You: \'I will assume daily batch for the v1, since the SLA is next-day dispatch review. Flag me if you want me to design for real-time.\'\n\nAsking back (\'what would you prefer?\') signals you cannot operate without a spec. Write the assumption on the board so the interviewer can correct it later.' },
  { id:'fc-dec-8', cat:'decomp', module:'decomp-101', lesson:'d-4', q:'What is the structure of a good clarifying question in a decomp round?', a:'**Pattern:** `Are we doing A or B? Because if A, I would do X; if B, I would do Y.`\n\nExample on the 911 dispatch prompt:\n- \'Are we triaging calls in real-time during the call, or post-hoc for QA review? Because if real-time, I would design around sub-second latency and a confidence threshold; if post-hoc, I would batch overnight and optimize for recall.\'\n\nGood clarifying questions are **specific**, **falsifiable**, and **branch into design-relevant alternatives**.' },
  { id:'fc-dec-9', cat:'decomp', module:'decomp-101', lesson:'d-2', q:'How many failure modes should you name in a decomp answer, and what does each need to include?', a:'**Target:** 3 specific failure modes, each with a detection mechanism and a rollback plan.\n\n- \'Add monitoring\' alone is a junior signal - it names no failure and no response\n- One failure mode signals naive optimism\n- Five-plus signals you cannot prioritize\n\n**Senior template:** `Failure X -> detect via Y -> roll back via Z.` Example: \'GPS dropout -> detect via stale-timestamp check -> fall back to last known route.\'' },
  { id:'fc-dec-10', cat:'decomp', module:'decomp-101', lesson:'d-2', q:'In a decomp answer, how many solution options should you present and in what shape?', a:'**Pattern:** present **two** phased options with explicit tradeoffs, then a recommendation with rationale.\n\n- **One option** - signals no tradeoff awareness, no awareness of alternatives\n- **Two options** - the sweet spot: forces a tradeoff conversation\n- **Three or more** - signals indecision and inability to commit\n\nClose with: `I recommend Option A because of constraint X - if X changes, I would flip to B.`' },
  { id:'fc-dec-11', cat:'decomp', module:'decomp-101', lesson:'d-8', q:'What is one senior-signal phrase in a decomp round and why does it work?', a:'**Phrase:** `X over Y because of this specific constraint - if it changes I would flip the decision.`\n\nWhy it works:\n- **Explicit tradeoff** - you named the alternative you rejected\n- **Conditional commitment** - you committed but bounded the commitment to a constraint\n- **Invites correction** - if the interviewer disagrees on the constraint, the whole answer updates cleanly\n\nExample: \'Postgres over `DynamoDB` because the join patterns are relational - if write volume crossed 50k/s I would flip.\'' },
  { id:'fc-dec-12', cat:'decomp', module:'decomp-101', lesson:'d-2', q:'Hospital prompt: a clinical decision-support tool has 12% adoption after 90 days. What is the first analytical split before proposing fixes?', a:'**Pattern:** product gaps vs adoption gaps - different root causes need different fixes.\n\n- **Product gap** - the tool does not solve the actual workflow problem; fix is product changes (UX, accuracy, integration)\n- **Adoption gap** - the tool works but no one uses it; fix is training, change management, champions, or incentives\n\n**Senior move:** name the split out loud before proposing any fix. Asking \'is this a product or adoption problem?\' shapes the next 20 minutes of the conversation.' },
  { id:'fc-dec-13', cat:'decomp', module:'decomp-101', lesson:'d-3', q:'In a Palantir-style decomp round, what should you draw FIRST on the whiteboard, and what counts as too early?', a:'**Draw:** `Inputs -> Logic -> Outputs` as three behavior boxes.\n\n- Boxes describe **behavior**, not tech, until implementation choices are explicitly on the table\n- Label inputs with data (\'call audio, GPS, CAD logs\'), not systems (`Kafka`)\n- Label logic with decisions (\'classify urgency, route to nearest unit\'), not frameworks\n\n**Antipattern:** writing `Kafka`, `Airflow`, or `OpenAI API` inside a box before scoping is an instant-reject signal - it commits you to a stack before you understand the problem.' },
  // AI
  { id:'fc-ai-16', cat:'ai', module:'ai-prompt', lesson:'pr-2', q:'What is the \'tagged thinking\' prompt pattern for combining CoT with a structured output?', a:'**Pattern:**\n- Model emits `<thinking>...</thinking>` then `<answer>{json}</answer>`\n- Parser extracts only the `<answer>` block\n- Thinking is logged for debugging, never returned to the user\n\n**Why:** keeps reasoning out of user-facing output while preserving its quality benefit.' },
  { id:'fc-ai-17', cat:'ai', module:'ai-prompt', lesson:'pr-5', q:'If you have a stable system prompt sent on every request, what single technique cuts cost by ~90%?', a:'**Prompt caching.**\n\n**Mechanism:** the provider caches the model\'s internal KV-state for the stable prefix. Subsequent requests reuse that computation instead of recomputing it.\n\n**Pricing:** cache reads typically ~10% of normal input token cost.' },
  { id:'fc-ai-18', cat:'ai', module:'ai-rag', lesson:'rag-3', q:'What is the correct pipeline order when using a cross-encoder reranker in RAG?', a:'**Pipeline:**\n- Fast retrieval (BM25 + dense) -- top 50\n- Cross-encoder rerank -- score query+doc jointly\n- Take top 5\n- Inject into LLM prompt\n\n**Why staged:** cross-encoders are too slow to run over the full corpus, but cheap over a small candidate set.' },
  { id:'fc-ai-19', cat:'ai', module:'ai-rag', lesson:'rag-2', q:'What\'s the best chunking strategy for a structured contract with numbered clauses and sub-clauses?', a:'**Strategy:** structural splitting on the clause hierarchy, with a recursive splitter as fallback for unusually long clauses.\n\n**Why it wins:**\n- Preserves legal/semantic meaning per chunk\n- Makes citations precise (e.g. \'Section 4.2(b)\')\n- Avoids cutting mid-sentence or mid-clause' },
  { id:'fc-ai-20', cat:'ai', module:'ai-agents', lesson:'ag-5', q:'What\'s the difference between native function calling and MCP (Model Context Protocol)?', a:'**Function calling** -- each provider\'s native tool-use API (OpenAI, Anthropic, Google). Tightly coupled to the model.\n\n**MCP** -- open standard (donated to the Linux Foundation\'s Agentic AI Foundation in Dec 2025) for LLM<->tool integration. Supported by OpenAI, Anthropic, Google, Microsoft.\n\n**When to use which:**\n- MCP -- portable tool servers reused across models/clients\n- Function calling -- in-prompt one-offs tied to a single provider' },
  { id:'fc-ai-21', cat:'ai', module:'ai-agents', lesson:'ag-2', q:'Why do agent tool calls that have side effects need idempotency keys?', a:'**Scenario:** network blip -> response is lost -> the LLM retries the tool call.\n\n**Without idempotency keys:** the side effect (charge, email, deploy) fires twice.\n\n**With idempotency keys:** the downstream service deduplicates by key and the retry is safely a no-op.' },
  { id:'fc-ai-22', cat:'ai', module:'ai-evals', lesson:'ev-2', q:'How do you detect drift in an LLM-as-judge over time?', a:'**Routine:**\n- Monthly, re-grade ~30 examples by hand\n- Confirm judge-vs-human agreement stays >=85%\n\n**If drift is detected:**\n- Rewrite the rubric with sharper, example-grounded criteria, OR\n- Swap to a different judge model' },
  { id:'fc-ai-23', cat:'ai', module:'ai-rag', lesson:'rag-4', q:'For a customer running entirely inside a VPC with no egress, which embedding model should you pick?', a:'**Pick self-hostable open-source:**\n- BGE-M3 -- 2026 default; multilingual; dense + sparse\n- Voyage-law-2, voyage-code-3 -- domain-specific, self-hostable for enterprise\n\n**Avoid API-only embedders:**\n- OpenAI `text-embedding-3`\n- Cohere\n\nThey require outbound calls and break VPC isolation.' },
  { id:'fc-ai-24', cat:'ai', module:'ai-rag', lesson:'rag-5', q:'When does pgvector beat Pinecone as the vector DB for a RAG system?', a:'**pgvector wins when:**\n- Customer is already on Postgres\n- Corpus is under ~10M vectors (HNSW handles this on a well-provisioned instance)\n- You want zero new infra and SQL filters that compose with vector search\n\n**Migrate to Pinecone/Qdrant/etc. when:**\n- Corpus exceeds ~50M vectors\n- You need horizontal autoscaling' },
  { id:'fc-ai-25', cat:'ai', module:'ai-prompt', lesson:'pr-1', q:'What three Anthropic-specific concepts should you review before interviewing at a Claude-shop?', a:'- **Constitutional AI** -- Claude\'s training approach and harms-reduction philosophy\n- **Responsible Scaling Policy (RSP)** -- current ASL tiers and what they gate\n- **Production stack** -- 1M-token context, prompt caching, extended thinking, MCP for tools\n\n**Tip:** skim the latest RSP and Claude docs in the week leading up to the interview.' },
  { id:'fc-ai-26', cat:'ai', module:'ai-rag', lesson:'rag-6', q:'How do you mitigate indirect prompt injection from content the model retrieves or browses?', a:'**Pattern:**\n- Wrap external content in `<untrusted_content>...</untrusted_content>` tags\n- Instruct the model to treat anything inside as DATA, never instructions\n\n**Caveat:** imperfect -- still pair with deterministic validators on side effects. Reduces risk; does not eliminate it.' },
  { id:'fc-ai-27', cat:'ai', module:'ai-agents', lesson:'ag-9', q:'What is speculative decoding and why does it speed up LLM inference?', a:'**Mechanism:**\n- A small, fast \'draft\' model proposes a sequence of tokens\n- The big target model validates them all in parallel in one forward pass\n- Accepted drafts are kept; rejected ones fall back to normal decoding\n\n**Result:** 2--3x speedup at the big model\'s quality, since most drafts pass.' },
  { id:'fc-ai-28', cat:'ai', module:'ai-agents', lesson:'ag-8', q:'What is the hardest UX problem for production voice agents in 2026?', a:'**Turn-taking and interruption handling.**\n\n- **End-of-utterance detection** -- needs prosody + semantics, not just VAD silence thresholds\n- **Adaptive interruption** -- distinguish backchannels (\'mm-hmm\', \'right\') from real barge-ins\n\n**Latency baseline:** under ~600--700ms end-to-end is necessary but not sufficient for \'feels human.\'' },
  // Coding
  { id:'fc-cod-12', cat:'coding', module:'cod-graphs', lesson:'g-4', q:'Why use `collections.deque` instead of a list as the BFS queue in Python?', a:'- `list.pop(0)` is `O(n)` because it shifts every remaining element left.\n- `deque.popleft()` is `O(1)` (doubly linked block layout).\n\nAt graph scale, the difference is **asymptotic**, not constant: a list-backed queue turns an `O(V + E)` BFS into `O(V^2 + V*E)`.' },
  { id:'fc-cod-13', cat:'coding', module:'cod-graphs', lesson:'g-1', q:'In BFS, should you mark a node visited at enqueue or at dequeue?', a:'**At enqueue.** Marking on dequeue lets the same node be pushed by every neighbor before it\'s processed, blowing up memory and time in dense graphs.\n\n- Enqueue-mark: each node enters the queue at most once\n- Dequeue-mark: up to `deg(v)` duplicates per node\n\nFor weighted variants (Dijkstra), the dequeue check is correct because distances can improve.' },
  { id:'fc-cod-14', cat:'coding', module:'cod-dp', lesson:'dp-4', q:'What is the optimal complexity for Longest Increasing Subsequence and how is it achieved?', a:'**Approach:** **Patience sort.** Maintain a `tails` array where `tails[i]` is the smallest possible tail of an increasing subsequence of length `i+1`. For each value, binary-search its insertion point in `tails` and overwrite.\n\n**Complexity:** `O(N log N)` time, `O(N)` space. The pure 2D DP variant is `O(N^2)`.\n\nNote: `tails` is **not** the actual LIS; reconstruct via parent pointers if needed.' },
  { id:'fc-cod-15', cat:'coding', module:'cod-select', lesson:'sel-1', q:'How do you find the K-th largest element in an unsorted N-element array?', a:'- **`Quickselect`:** average `O(N)`, worst `O(N^2)`. Partition around a pivot and recurse on one side.\n- **Min-heap of size `K`:** `O(N log K)` time, `O(K)` space. Streaming-friendly.\n- **Full sort:** `O(N log N)`, strictly worse.\n\nPick quickselect for one-shot in-memory; pick the heap when `K` is small or data streams in.' },
  { id:'fc-cod-16', cat:'coding', module:'cod-select', lesson:'sel-2', q:'What data structure tracks the top K elements of a stream?', a:'**Approach:** A **min-heap of size `K`**. For each incoming item: if the heap has fewer than `K` elements, push it; otherwise if the item is larger than the heap\'s root, pop and push.\n\n**Complexity:** `O(log K)` per item, `O(K)` memory. The root is the K-th largest seen so far, and the heap holds the top `K`.' },
  { id:'fc-cod-17', cat:'coding', module:'cod-misc', lesson:'m-LC1', q:'How do you maintain the running median of a streaming sequence?', a:'**Approach:** Two heaps: a **max-heap `lo`** for the smaller half and a **min-heap `hi`** for the larger half. Keep `len(lo) - len(hi)` in `{0, 1}` by rebalancing after each insert.\n\n- Odd count: median = `lo.top()`\n- Even count: median = `(lo.top() + hi.top()) / 2`\n\n**Complexity:** `O(log N)` per insert, `O(1)` per query.' },
  { id:'fc-cod-18', cat:'coding', module:'cod-graphs', lesson:'g-5', q:'How do you count connected components in an undirected graph?', a:'**Approach:** Loop over every node; if it isn\'t visited yet, run a DFS or BFS from it and increment a component counter. Each traversal marks every reachable node visited.\n\n**Complexity:** `O(V + E)` time, `O(V)` space. Union-Find also works and is preferable when edges arrive online.' },
  { id:'fc-cod-19', cat:'coding', module:'cod-advgraphs', lesson:'ag-cod-2', q:'How do you detect a cycle in a directed graph?', a:'- **DFS with three colors / on-stack set:** mark nodes `WHITE` (unseen), `GRAY` (on current DFS path), `BLACK` (finished). Encountering a `GRAY` node = back-edge = cycle.\n- **Kahn\'s topological sort:** if the produced order has fewer than `N` nodes, a cycle exists.\n\nBoth are `O(V + E)`. For undirected graphs, use union-find or parent-aware DFS instead.' },
  { id:'fc-cod-20', cat:'coding', module:'cod-misc', lesson:'m-LC2', q:'What is the optimal way to merge K sorted lists into one sorted list?', a:'**Approach:** Min-heap of `K` head pointers. Pop the smallest, append it to the output, and push its `.next` (if any).\n\n**Complexity:** `O(N log K)` time, `O(K)` space, where `N` is total elements.\n\nStrictly better than pairwise merge (`O(N*K)`) or concatenating-then-sorting (`O(N log N)`) when `K << N`.' },
  { id:'fc-cod-21', cat:'coding', module:'cod-arrays', lesson:'a-2', q:'What invariant must hold for a sliding-window approach to work?', a:'**Monotonicity:** extending the window must not be able to "un-break" the property once it\'s broken, and shrinking must not be able to re-break it.\n\n- Longest substring with no repeats: extending only adds chars (monotone)\n- Subarray sum >= target with positives: monotone\n- Subarray with negatives included: **not** monotone, sliding window fails\n\nWithout monotonicity, a window can\'t be slid in one pass.' },
  { id:'fc-cod-22', cat:'coding', module:'cod-arrays', lesson:'a-1', q:'What time and space complexity does the two-pointer technique give on a sorted array?', a:'**Complexity:** `O(N)` time, `O(1)` extra space.\n\nEach pointer moves forward at most `N` steps (they never go backward), so total work is linear. Strictly better than hash-set approaches on space, and matches them on time when the input is already sorted.' },
  { id:'fc-cod-23', cat:'coding', module:'cod-arrays', lesson:'a-3', q:'When does binary-search-on-the-answer apply, and what are canonical examples?', a:'**Trigger:** the answer space is **monotonic**, meaning a predicate `feasible(x)` flips from `false` to `true` exactly once over the candidate range. Binary-search the boundary, calling the predicate each step.\n\n**Canonical examples:**\n\n- Min ship capacity to deliver in `D` days\n- Smallest max-page when splitting books across `K` students\n- Koko\'s minimum eating speed\n- Min largest sum splitting array into `K` parts' },
  { id:'fc-cod-24', cat:'coding', module:'cod-arrays', lesson:'a-4', q:'What problems do prefix sums solve, and at what cost?', a:'**Approach:** Precompute `prefix[i] = A[0] + ... + A[i-1]` once in `O(N)`. Then any range sum `A[l..r]` is `prefix[r+1] - prefix[l]` in `O(1)`.\n\n**Use for:**\n\n- Range-sum queries (immutable array)\n- **"Subarray sum equals K"** via `prefix_count` hash map\n- 2D variants for submatrix sums\n- Difference arrays for range updates\n\n**Complexity:** `O(N)` build, `O(1)` query.' },
  { id:'fc-cod-25', cat:'coding', module:'cod-advgraphs', lesson:'ag-cod-4', q:'What does the bit operation `x & (x - 1)` compute?', a:'**It clears the lowest set bit of `x`.** Subtracting `1` flips the lowest set bit to `0` and all lower zeros to `1`s; the AND then zeros out everything from that bit down.\n\n**Uses:**\n\n- **Brian Kernighan\'s** bit count: loop `x &= x - 1` until zero; iterations = popcount\n- Check power of two: `x > 0 and (x & (x - 1)) == 0`\n- Enumerate set bits one at a time' },
  { id:'fc-cod-26', cat:'coding', module:'cod-advgraphs', lesson:'ag-cod-4', q:'How do you find the two unique numbers when every other value in the array appears twice?', a:'**Approach:** XOR all values to get `x = a ^ b`. Since `a != b`, `x` has at least one set bit; isolate the lowest one with `x & -x`. Partition the array by whether each element has that bit set, and XOR each partition separately. Each side cancels its pairs and isolates one of `a, b`.\n\n**Complexity:** `O(N)` time, `O(1)` space.' },
  { id:'fc-cod-27', cat:'coding', module:'cod-advgraphs', lesson:'ag-cod-1', q:'Why does Dijkstra\'s algorithm fail on graphs with negative edge weights?', a:'**Reason:** Dijkstra locks in a node\'s distance the moment it\'s popped from the priority queue, relying on the invariant that future paths can only add cost. A negative edge could later offer a shorter route to the locked node, but the algorithm has already moved on.\n\n**Fix:** use `Bellman-Ford` (`O(V*E)`, handles negatives) or `SPFA`. For all-pairs with negatives, use `Floyd-Warshall`.' },
  { id:'fc-cod-28', cat:'coding', module:'cod-advgraphs', lesson:'ag-LC1', q:'What is Bellman-Ford\'s complexity, and what does it buy you over Dijkstra?', a:'**Complexity:** `O(V * E)` time, `O(V)` space.\n\n**Benefits:**\n\n- Handles **negative edge weights**\n- Detects **negative cycles**: run one extra relaxation pass after `V-1` rounds; any further relaxation proves a negative cycle exists\n- Simpler to implement than Dijkstra (no heap)\n\nPay the slower runtime when negatives are possible or when you need cycle detection.' },
  { id:'fc-cod-29', cat:'coding', module:'cod-advgraphs', lesson:'ag-LC4', q:'What is the key invariant in the monotonic-stack solution to Largest Rectangle in Histogram?', a:'**Approach:** Maintain a stack of bar indices with **strictly increasing heights**. When a shorter bar arrives, pop bars taller than it; for each popped bar, compute the rectangle bounded by its height with width from the new stack top `+ 1` to the current index `- 1`.\n\n- Stack top after pop = left boundary (first shorter bar to the left)\n- Current index = right boundary (first shorter bar to the right)\n\n**Complexity:** each bar pushed and popped once, `O(N)`.' },
  { id:'fc-cod-30', cat:'coding', module:'cod-advgraphs', lesson:'ag-cod-1', q:'How does A* differ from Dijkstra for shortest-path search?', a:'**A\\* = Dijkstra + a heuristic `h(n)`** estimating cost to goal. Priority becomes `g(n) + h(n)` instead of just `g(n)`.\n\n- If `h` is **admissible** (never overestimates), A\\* still finds the optimal path\n- If `h` is also **consistent**, A\\* expands each node at most once like Dijkstra\n- With a good heuristic, A\\* prunes huge swaths of the search space when the target is known\n\nUse A\\* for single-target search with geometry/domain knowledge; Dijkstra for multi-target or no heuristic.' },
  // SysD
  { id:'fc-sd-10', cat:'sysd', module:'sd-classic', lesson:'sd-4', q:'In a hybrid feed system, what celebrity-threshold heuristic flips a user from push to pull fan-out?', a:'Above some follower count (commonly **`1M+`**), switch that user from push to pull.\n\n**How it works:**\n- The celebrity\'s posts are NOT fanned out at write time\n- Their followers **query the celebrity\'s timeline** at read time\n- The follower\'s feed merges their pushed feed with pulled celebrity posts\n\nThis caps write amplification per post at the threshold.' },
  { id:'fc-sd-11', cat:'sysd', module:'sd-classic', lesson:'sd-9', q:'When does the CAP tradeoff actually bind a distributed system?', a:'**Only during a network partition.**\n\nOn a healthy network you can have strong consistency AND availability simultaneously.\n\nThe CAP choice is what your system does when nodes **can\'t talk to each other**:\n- **AP:** serve stale or divergent data\n- **CP:** refuse writes until quorum is restored\n\nMost of the time you\'re not partitioned, so PACELC matters more.' },
  { id:'fc-sd-12', cat:'sysd', module:'sd-classic', lesson:'sd-9', q:'How do you classify Cassandra vs Spanner under PACELC?', a:'**`Cassandra` = PA/EL**\n- During Partition: Available (tunable per-query consistency)\n- Else: Latency-optimized (eventual consistency by default)\n\n**`Spanner` = PC/EC**\n- During Partition: Consistent (refuses writes without quorum)\n- Else: Consistent via `TrueTime` + Paxos (pays latency cost)\n\nDifferent defaults, different workloads: high-throughput writes vs global strong consistency.' },
  { id:'fc-sd-13', cat:'sysd', module:'sd-classic', lesson:'sd-8', q:'Why do consistent-hashing implementations use virtual nodes instead of one slot per server?', a:'**Without vnodes:**\n- Adding one node pulls `~1/N` of load **from a single neighbor**\n- Creates hot spots during scale events\n- Variance in slice sizes leads to uneven baseline load\n\n**With vnodes** (~100-200 per physical node):\n- New node draws load **evenly from every existing node**\n- Removal is the inverse: load spreads across all survivors\n- Smoothes out hash-ring variance' },
  { id:'fc-sd-14', cat:'sysd', module:'sd-classic', lesson:'sd-kafka', q:'Why is true exactly-once delivery impossible across system boundaries, and what do you do instead?', a:'**Why impossible:** network failures make it indistinguishable whether the message was delivered and the ack was lost, or the message was lost.\n\n**Practical answer:**\n- **At-least-once delivery + idempotent receivers** (the standard pattern)\n- At-most-once only if loss is acceptable\n\n**`Kafka`\'s \'exactly-once\':** scoped to a single Kafka transaction (producer to consumer within Kafka), not end-to-end across external systems.' },
  { id:'fc-sd-15', cat:'sysd', module:'sd-classic', lesson:'sd-5', q:'What two patterns prevent a cache stampede when a popular key expires?', a:'**Pattern 1 - Singleflight / request coalescing**\n- Only one request rebuilds the value\n- All other concurrent requests **wait on the in-flight result**\n- Prevents `N` duplicate origin calls\n\n**Pattern 2 - Refresh-ahead**\n- Rebuild the value **before TTL expires**\n- Serve the stale value during recomputation\n- No thundering herd because the cache is never empty' },
  { id:'fc-sd-16', cat:'sysd', module:'sd-classic', lesson:'sd-5', q:'When one key in Redis becomes a hot key, how do you fix it?', a:'**Symptom:** one `Redis` node CPU-pegged while the rest sit idle.\n\n**Cause:** consistent hashing maps a single key to a single node; traffic concentration on that key can\'t be sharded away.\n\n**Fix:** **replicate the hot key** across `N` shards as `key_1..key_N`.\n- Clients pick a random replica for reads\n- Writes fan out to all `N` (acceptable for read-heavy hot keys)\n- Scales read throughput linearly with replica count' },
  { id:'fc-sd-17', cat:'sysd', module:'sd-classic', lesson:'sd-3', q:'Why use Redis with Lua scripts for a global rate limiter instead of in-memory counters?', a:'**Lua scripts run atomically on the Redis server**, so the read-modify-write of a sliding-window counter happens in a single hop with no race condition across `N` application servers.\n\n**Why in-memory fails:**\n- Each app server tracks its own counter\n- Client hitting 10 servers gets 10x the intended limit\n- No global enforcement is possible without shared state' },
  { id:'fc-sd-18', cat:'sysd', module:'sd-classic', lesson:'sd-3', q:'When rate-limiting an API, when do you pick token bucket over sliding-window counter?', a:'**Token bucket**\n- Allows **bursts up to bucket size**, then refills at a steady rate\n- Good for API quotas that should absorb spikes (e.g., batch jobs)\n\n**Sliding-window counter**\n- Cheap and approximate (`O(1)` memory per key)\n- **Smooths traffic** but rejects bursts\n- Good for protecting fragile backends\n\n**Rule:** pick by how much burstiness you want to tolerate.' },
  { id:'fc-sd-19', cat:'sysd', module:'sd-fde', lesson:'fd-2', q:'How do you size the idempotency-key TTL on a webhook receiver?', a:'**Rule:** TTL must exceed the **sender\'s max retry window**.\n\n**Reference points:**\n- `Stripe` retries up to ~3 days\n- Some platforms retry for up to a week\n\n**Failure modes:**\n- **TTL too short:** late retries slip past the dedupe table and cause **duplicate processing**\n- **TTL too long:** storage grows unboundedly\n\nCheck the docs for every sender you ingest from.' },
  { id:'fc-sd-20', cat:'sysd', module:'sd-classic', lesson:'sd-7', q:'When two users send messages in a chat conversation simultaneously, how do you order them deterministically?', a:'**Server-assigned monotonic per-conversation sequence number**, issued by whichever shard owns that conversation.\n\n**Why not wall-clock timestamps:**\n- Client clocks drift\n- Server clocks across regions drift\n- Ties are common at millisecond resolution\n\nA deterministic per-conversation sequence guarantees **the same ordering for every viewer** of the chat.' },
  { id:'fc-sd-21', cat:'sysd', module:'sd-classic', lesson:'sd-db', q:'Range sharding vs hash sharding: when do you pick range?', a:'**Range sharding** (pick when):\n- Queries need ordered scans (`BETWEEN`, `ORDER BY date`)\n- Time-series or pagination workloads\n- Risk: **hot partitions** when writes concentrate on a recent range (today\'s date)\n\n**Hash sharding** (default):\n- Distributes load evenly\n- Destroys range queries; scatter-gather across all shards\n- Use a **composite key** (hash + range) to get both' },
  { id:'fc-sd-22', cat:'sysd', module:'sd-classic', lesson:'sd-raft', q:'Read replicas break read-your-writes consistency for a user who just posted; what\'s the standard fix?', a:'**Session pinning.**\n\n**Mechanism:**\n1. User writes through the primary, server captures the LSN (or sets a timer for `N` seconds)\n2. For that user\'s subsequent reads, route to the **primary** until the LSN reaches the replica (or the timer expires)\n3. Other users keep reading from replicas\n\n**Result:** the writer sees their own update; you preserve read scale for everyone else.' },
  { id:'fc-sd-23', cat:'sysd', module:'sd-classic', lesson:'sd-pay', q:'What is the saga pattern for distributed transactions, and when do you use it?', a:'**Mechanism:**\n1. Break a transaction into a sequence of **local steps**, each owned by one service\n2. Each step has a **compensating action** that semantically undoes it\n3. On failure mid-sequence, run compensations **in reverse order**\n\n**When to use:**\n- 2PC is impractical (cross-service, cross-region, third-party APIs)\n- You can tolerate **eventual consistency** between steps\n- Standard for microservices and payment flows' },
  { id:'fc-sd-24', cat:'sysd', module:'sd-classic', lesson:'sd-reliable', q:'What does a circuit breaker do, and what are its three states?', a:'**Goal:** prevent cascading failures when a downstream dependency is unhealthy.\n\n**States:**\n1. **CLOSED:** calls pass through normally; track failure rate\n2. **OPEN:** after `N` failures or `X%` failure rate, fast-fail without calling downstream\n3. **HALF_OPEN:** after a cooldown, allow limited probe traffic; success closes the breaker, failure re-opens it\n\nProtects upstream from running out of threads/connections waiting on a dead dependency.' },
  { id:'fc-sd-25', cat:'sysd', module:'sd-fde', lesson:'fd-7', q:'In an event-sourced system, where is the source of truth and how do reads work?', a:'**Source of truth:** an **append-only event log**. Current state is derived by **replaying events**.\n\n**Reads (CQRS):**\n- **Read-model projections** consume the log and build query-optimized views\n- **Snapshots** speed up replay (skip ahead, replay from snapshot)\n- Projections can be **rebuilt from scratch** at any time by re-reading the log\n\nLog retention = your history; projections = your indexes.' },
  // SQL & Data
  { id:'fc-sql-8', cat:'data', module:'data-sql', lesson:'sq-1', q:'Which SQL pattern computes a running total without collapsing per-row detail?', a:'Use a window aggregate, not `GROUP BY`.\n\n**Example:** `SELECT date, amount, SUM(amount) OVER (PARTITION BY group_id ORDER BY date) AS running_total FROM t`\n\n- **`GROUP BY`** -- collapses rows, loses per-row context\n- **`SUM() OVER (...)`** -- keeps every row, attaches the cumulative value' },
  { id:'fc-sql-9', cat:'data', module:'data-sql', lesson:'sq-2', q:'What is the canonical SQL pattern for selecting the top N rows per group?', a:'1. Assign a rank inside each group with `ROW_NUMBER()`\n2. Filter to `rn <= N` in an outer query or CTE\n\n**Example:** `SELECT * FROM (SELECT *, ROW_NUMBER() OVER (PARTITION BY group_id ORDER BY metric DESC) AS rn FROM t) x WHERE rn <= 3`\n\nUse `DENSE_RANK()` instead if ties should all count.' },
  { id:'fc-sql-10', cat:'data', module:'data-sql', lesson:'sq-1', q:'What do the SQL `LAG()` and `LEAD()` window functions do, and when do you reach for them?', a:'- **`LAG(col, n)`** -- value from the previous nth row in the partition\n- **`LEAD(col, n)`** -- value from the next nth row\n\n**Common uses:**\n- Period-over-period diffs (`value - LAG(value)`)\n- Session deltas between events\n- Funnel conversion (next step timestamp)\n\n**Example:** `LAG(amount, 1) OVER (PARTITION BY user_id ORDER BY event_ts)`' },
  { id:'fc-sql-11', cat:'data', module:'data-pipe', lesson:'pp-4', q:'Can a composite index on `(a, b, c)` serve a query with `WHERE b = X` alone?', a:'**No.** The leftmost-prefix rule requires the query to use the leading column.\n\n- Usable: `WHERE a = X`, `WHERE a = X AND b = Y`, `WHERE a = X AND b = Y AND c = Z`\n- Not usable: `WHERE b = X`, `WHERE c = X`, `WHERE b = X AND c = Y`\n\n**Fix:** add a separate index on `(b)` if that filter pattern is hot.' },
  { id:'fc-sql-12', cat:'data', module:'data-pipe', lesson:'pp-4', q:'What is a covering index and why is it faster than a normal index?', a:'A **covering index** contains every column the query needs -- key columns plus `INCLUDE` columns.\n\n- Database satisfies the query from the index alone\n- No heap/table fetch for the row data\n- Reduces I/O significantly on wide rows\n\n**Example:** `CREATE INDEX idx ON orders (user_id) INCLUDE (status, total)`' },
  { id:'fc-sql-13', cat:'data', module:'data-pipe', lesson:'pp-4', q:'What is the relationship between Postgres MVCC and `VACUUM`?', a:'**MVCC** keeps multiple row versions so readers never block writers.\n\n- `UPDATE` and `DELETE` leave **dead tuples** behind (the old version)\n- `VACUUM` reclaims the dead-tuple space for reuse\n- `ANALYZE` refreshes planner statistics used for query plans\n- `VACUUM FULL` rewrites the table to release disk back to the OS (locks)\n\n**Symptom of skipping it:** bloated tables, slow scans, stale plans.' },
  { id:'fc-sql-14', cat:'data', module:'data-sql', lesson:'sq-5', q:'What is the fundamental difference between OLTP and OLAP databases?', a:'**OLTP** (transactional)\n- Row-oriented storage\n- Single-record reads and writes\n- Normalized schema\n- Examples: Postgres, MySQL\n\n**OLAP** (analytical)\n- Columnar storage\n- Batch aggregates over many rows\n- Denormalized (star schema)\n- Examples: Snowflake, BigQuery, ClickHouse' },
  { id:'fc-sql-15', cat:'data', module:'data-warehouse', lesson:'wh-1', q:'What is the difference between a star schema and a snowflake schema in a warehouse?', a:'**Star schema**\n- One fact table joined to denormalized dimension tables\n- Fewer joins, faster analytical queries\n- Default for BI workloads\n\n**Snowflake schema**\n- Dimensions normalized into sub-dimensions\n- More joins, smaller storage\n- Useful when dim hierarchies change often\n\n**Default:** star, unless you have a clear normalization reason.' },
  { id:'fc-sql-16', cat:'data', module:'data-pipe', lesson:'pp-1', q:'What is the `MERGE` / `UPSERT` pattern for idempotent loads?', a:'Use the engine\'s atomic merge construct keyed on a stable natural key.\n\n**ANSI / Snowflake / BigQuery:** `MERGE INTO target USING source ON keys WHEN MATCHED THEN UPDATE WHEN NOT MATCHED THEN INSERT`\n\n**Postgres:** `INSERT INTO target (...) VALUES (...) ON CONFLICT (key) DO UPDATE SET ...`\n\n**Why it works:** combined with a deterministic key, re-runs converge to the same state -- safe to replay.' },
  { id:'fc-sql-17', cat:'data', module:'data-sql', lesson:'sq-5', q:'What should you do when analytics queries on a 1TB Postgres table slow to a crawl?', a:'Row-store Postgres is poor at full-table aggregate scans. Options:\n\n- Move the analytics workload to a columnar engine: **Snowflake**, **BigQuery**, **ClickHouse**, **DuckDB**\n- Replicate hot tables via CDC to the warehouse, query there\n- Stay in-Postgres with a columnar extension: **`pg_duckdb`** or **`pg_mooncake`**\n- Partition + `BRIN` index time-series tables for cheap pruning\n\n**Default move:** ship to a columnar warehouse.' },
  { id:'fc-sql-18', cat:'data', module:'data-pipe', lesson:'pp-1', q:'What are the layers of the medallion architecture used in lakehouses?', a:'Standard layering for Delta Lake / Iceberg pipelines:\n\n- **Bronze** -- raw ingest, schema-on-read, immutable\n- **Silver** -- cleaned, deduped, type-cast, joined to references\n- **Gold** -- business-ready aggregates and marts consumed by BI\n\n**Why:** each layer is reprocessable from the prior layer, isolating quality fixes from consumers.' },
  { id:'fc-sql-19', cat:'data', module:'data-warehouse', lesson:'wh-2', q:'What is the purpose of a schema registry in a streaming system?', a:'A central service that stores Avro / Protobuf / JSON schemas with compatibility rules.\n\n- **Backward compat** -- new consumer can read old messages\n- **Forward compat** -- old consumer can read new messages\n- **Full compat** -- both\n\n**Why it matters:** producers and consumers can deploy independently without breaking each other. Confluent Schema Registry is the canonical example.' },
  { id:'fc-sql-20', cat:'data', module:'data-warehouse', lesson:'wh-1', q:'What is the 2026 state of open table formats -- Iceberg vs Delta vs Hudi?', a:'Three open table formats over Parquet adding ACID, time travel, and schema evolution.\n\n- **Iceberg** -- industry consolidation winner. Databricks acquired Tabular (2024); AWS S3 Tables, Snowflake, BigQuery support it natively\n- **Delta** -- still leads inside Databricks / Spark; **Delta UniForm** publishes Iceberg metadata for interop\n- **Hudi** -- specializes in record-level upserts and streaming ingestion\n- **Apache XTable** -- translates metadata across all three\n\n**Default for greenfield:** Iceberg.' },
  // Behavioral
  { id:'fc-beh-9', cat:'behav', module:'b-values', lesson:'v-3', q:'What are the biggest behavioral red flags Palantir interviewers screen for, even when the technical signal is strong?', a:'**Four reject-on-sight signals:**\n\n- 1. **Fake-failure dodges** (`I work too hard`, `I don\'t really fail`).\n- 2. **Surface-level `why Palantir`** -- citing comp/perks/`cool problems` instead of a specific product or customer.\n- 3. **Mixing up Foundry (commercial) and Gotham (gov/intel)** -- signals no research.\n- 4. **Inability to justify a technical choice** under follow-up.\n\nCultural-fit weight is high enough that these reject strong technical candidates.' },
  { id:'fc-beh-10', cat:'behav', module:'b-stories', lesson:'b-6', q:'When asked why you are leaving, what is the difference between `pull` and `push` framing, and why does the choice matter?', a:'**Pull vs push:**\n\n- **Pull (do this):** name the specific role, scope, or mission attracting you.\n- **Push (the trap):** badmouthing your current employer.\n\nInterviewers read push framing as a **predictor** of how you will describe them next year.' },
  { id:'fc-beh-11', cat:'behav', module:'b-stories', lesson:'b-6', q:'Within the STAR framework for a Forward Deployed Engineer (FDE) story, which section should be the largest and what must it contain?', a:'**Action -- about 60% of the answer.**\n\nBe specific about both moves:\n\n- **Technical moves** -- the rollback you ran, the query you wrote, the system you instrumented.\n- **Interpersonal moves** -- the call you made to the customer, the escalation, the tradeoff you proposed.\n\nThe Action section is where individual ownership shows up.' },
  { id:'fc-beh-12', cat:'behav', module:'b-stories', lesson:'b-1', q:'List the five stories required for a Forward Deployed Engineer (FDE) loop.', a:'**Five required FDE stories:**\n\n- 1. Production fix under pressure.\n- 2. Pushing back on a customer.\n- 3. Deployment failure ownership.\n- 4. Explaining a technical limit.\n- 5. Decision under incomplete info.' },
  { id:'fc-beh-13', cat:'behav', module:'b-values', lesson:'v-1', q:'What OpenAI cultural cues and updated Charter principles should you tune your stories to as of 2026?', a:'**Updated Charter principles (2026):**\n\n- Democratization\n- Empowerment\n- Universal Prosperity\n- Resilience\n- Adaptability\n\n**Cultural signal:** intensity, scale, and shipping products users love.\n\nExample: bring a **role-specific** reason for FDE (e.g., enterprise rollout work), not a mission quote.' },
  { id:'fc-beh-14', cat:'behav', module:'b-values', lesson:'v-2', q:'What signals does Anthropic look for in interviews as of 2026, and which artifacts should you be able to discuss in depth?', a:'**Artifacts to engage with:**\n\n- **RSP v3.0 (Feb 2026)** -- replaced hard pauses with a public Frontier Safety Roadmap plus recurring risk assessments.\n- **Constitutional AI** -- the training method.\n- **Acceptable Use Policy** -- product-level enforcement.\n\nGeneric `I try to do the right thing` answers fail the ethical-dilemma probes -- show the specific tradeoffs you weighed.' },
  { id:'fc-beh-15', cat:'behav', module:'b-fivestories', lesson:'bs-2', q:'When asked `tell me about a time you disagreed with your manager`, what half of the answer do most candidates skip?', a:'**The commit half.**\n\nA strong arc closes with:\n\n- Executing fully on the team\'s decision, even after losing the argument.\n- Often **stronger** if you were partly wrong and acknowledge that you did your share to make their choice succeed.' },
  { id:'fc-beh-16', cat:'behav', module:'b-stories', lesson:'b-6', q:'What makes a `tell me about mentoring someone` story land as strong rather than generic?', a:'**Four specificity hooks:**\n\n- 1. A **specific person** (anonymized).\n- 2. A **specific gap** (skill, behavior, or judgment).\n- 3. **Your approach** -- the actual moves you made.\n- 4. A **measurable outcome** -- promotion, project shipped, observable behavior change.' },
  // Cloud
  { id:'fc-cl-8', cat:'cloud', module:'cl-integ', lesson:'in-4', q:'Logs vs metrics vs traces: when do you reach for each in an incident?', a:'- **Metrics**: aggregate numeric time-series, cheap to store, drive alerts. Answer \'is something wrong now?\'\n- **Logs**: discrete events with high-cardinality detail. Answer \'why did this request fail?\'\n- **Traces**: per-request causal graph across services. Find the slow span.\n\n**Order:** use metrics to detect, traces to localize, logs to explain.' },
  { id:'fc-cl-9', cat:'cloud', module:'cl-integ', lesson:'in-4', q:'What is OpenTelemetry and why does it matter?', a:'**OpenTelemetry (OTel)** is a vendor-neutral instrumentation library that emits logs, metrics, and traces in a standard wire format.\n\nBackends are pluggable: Datadog, Jaeger, Honeycomb, Grafana Cloud, etc.\n\nUse when: starting a new service or wanting to keep the observability backend swappable without re-instrumenting every app.' },
  { id:'fc-cl-10', cat:'cloud', module:'cl-integ', lesson:'in-4', q:'What debugging order does a senior engineer use during an incident?', a:'1. **Metrics** to identify what is wrong and narrow to a service.\n2. **Traces** to find the slow or failing span across services.\n3. **Logs** to read the exception and explain root cause.\n\nLogs-first is a junior tell: grepping logs without knowing which service or request is broken wastes time.' },
  { id:'fc-cl-11', cat:'cloud', module:'cl-core', lesson:'cl-4', q:'What is BYOK (Bring Your Own Keys) and why do enterprises demand it?', a:'**BYOK** means the customer holds the encryption key in their own KMS (AWS KMS, Cloud KMS, on-prem HSM).\n\n**Key property:** if they revoke the key, your service cannot decrypt their data even if you wanted to.\n\nUse when: selling to regulated enterprise (finance, healthcare, government) that requires a strong cryptographic trust boundary against the vendor.' },
  { id:'fc-cl-12', cat:'cloud', module:'cl-core', lesson:'cl-4', q:'What is the standard PCI-DSS scope reduction strategy for a SaaS app?', a:'**Do not touch raw card data.** Use a tokenization provider (Stripe, Adyen, Braintree) that returns a token your system stores instead of the PAN.\n\n**Result:**\n- PCI scope collapses from full PCI-DSS to SAQ-A (the lightest tier).\n- Compliance burden, audit cost, and breach blast-radius all shrink dramatically.' },
  { id:'fc-cl-13', cat:'cloud', module:'cl-core', lesson:'cl-4', q:'What does GDPR data residency actually require in practice?', a:'EU personal data must stay in the EU unless the destination country has an **adequacy decision** OR you use **SCCs** (Standard Contractual Clauses) plus a transfer impact assessment.\n\n**Practical implementation:**\n- Run an EU region (Frankfurt, Ireland) and pin EU-tenant data to it.\n- Block silent replication of logs or backups to `us-east-1`.\n- Document sub-processors and their regions in the DPA.' },
  { id:'fc-cl-14', cat:'cloud', module:'cl-integ', lesson:'in-3', q:'What is the most common root cause of intermittent SAML SSO failures?', a:'**Clock skew.** SAML assertions arrive with `NotBefore` and `NotOnOrAfter` timestamps outside the SP\'s tolerance window.\n\n**Fix:**\n- Allow 60s tolerance on `NotBefore` / `NotOnOrAfter`.\n- Run NTP on both IdP and SP hosts.\n- Log the assertion timestamps when you reject so the next failure is one-glance debuggable.' },
  { id:'fc-cl-15', cat:'cloud', module:'cl-integ', lesson:'in-3', q:'What are the four SCIM 2.0 endpoints that matter for provisioning?', a:'- `POST /Users` to create a new user.\n- `PATCH /Users/{id}` to update attributes (name, email, manager).\n- `PATCH /Users/{id}` with `active=false` to deprovision/disable.\n- `/Groups` for role and team membership.\n\nThe customer\'s IdP (Okta, Entra ID) calls these on a schedule so HR -> IdP -> your app stays in sync with zero manual user management.' },
  { id:'fc-cl-16', cat:'cloud', module:'cl-core', lesson:'cl-2', q:'How do you ship an air-gapped on-prem deploy to a customer?', a:'- Ship a **Helm chart** the customer installs in their own Kubernetes cluster.\n- Mirror all container images into their internal registry (Harbor, Artifactory) so nothing is pulled from your servers at runtime.\n- No outbound network calls from the workload to your servers.\n- License + telemetry via offline files the customer uploads back to you on a schedule.' },
  { id:'fc-cl-17', cat:'cloud', module:'cl-integ', lesson:'in-5', q:'Compare blue-green and canary deploys: when do you choose which?', a:'**Blue-green**\n- Two parallel environments, atomic cutover via LB flip.\n- Use for atomic rollback when a bad deploy must be reversed in one step.\n\n**Canary**\n- Gradual percentage traffic shift with metric gates between steps.\n- Use for risk: catch a regression before 100% of users see it.\n\nMany teams combine: canary the new version, then blue-green flip on success.' },
  { id:'fc-cl-18', cat:'cloud', module:'cl-core', lesson:'cl-2', q:'What is the standard pattern for TLS certificate auto-renewal?', a:'Use the **ACME protocol** (Let\'s Encrypt, ZeroSSL) plus an automation agent:\n- In Kubernetes: `cert-manager` with an `Issuer` / `ClusterIssuer`.\n- On VMs: `certbot` or `caddy`.\n\n**Why automate:** manual rotation always fails when certs expire on weekends, holidays, or during incidents. ACME + cert-manager renews ~30 days before expiry without human touch.' },
  { id:'fc-cl-19', cat:'cloud', module:'cl-integ', lesson:'in-5', q:'What tools support auto-rollback on metric regression after a deploy?', a:'- **Argo Rollouts** and **Flagger**: K8s-native, GitOps-friendly.\n- **Harness**: commercial, broad CI/CD with built-in verification.\n- **LaunchDarkly** for flag-based rollback (kill switch, not redeploy).\n- **Spinnaker** still works but is fading.\n\n**Pattern:** watch error rate, latency, and saturation for N minutes post-deploy and auto-revert on regression.' },
  { id:'fc-cl-20', cat:'cloud', module:'cl-core', lesson:'cl-4', q:'How do you rotate a secret (DB password, API key) without downtime?', a:'Use a **dual-credential window**:\n\n1. Add the new credential alongside the old; both are valid.\n2. Roll services so they pick up the new credential from the secrets store.\n3. Verify no service is still using the old credential (audit logs).\n4. Remove the old credential.\n\nResult: zero-downtime rotation with a safe rollback at each step.' },
  { id:'fc-cl-21', cat:'cloud', module:'cl-core', lesson:'cl-2', q:'What value does a service mesh add and when is it worth the operational cost?', a:'**Value:** sidecars handle `mTLS`, retries, circuit-breaking, and L7 observability without app code changes.\n\nUse when:\n- 50+ microservices where retry and timeout logic is duplicated everywhere.\n- Zero-trust mTLS is a compliance requirement.\n- You need traffic-shaping (canary, mirroring) across the fleet.\n\nSkip when: under ~20 services. The control-plane ops cost outweighs the benefit.' },
  // Domain
  { id:'fc-dom-4', cat:'domain', module:'dom-dev', lesson:'dh-4', q:'What is a HIPAA Business Associate Agreement (BAA) and when does your company need one?', a:'A **BAA** is a contract required whenever a vendor handles **PHI** (protected health information) on a covered entity\'s behalf. It binds the vendor to HIPAA\'s privacy and security rules and assigns breach-notification duties.\n\n- **No BAA == no PHI** can legally flow to you\n- Covered entities = providers, payers, clearinghouses; their vendors are **business associates**\n- Most cloud and LLM vendors (AWS, GCP, Azure, OpenAI, Anthropic) offer BAAs only on **specific (often higher-tier) plans**\n- Confirm BAA coverage for **every** subprocessor in your stack before architecting' },
  { id:'fc-dom-5', cat:'domain', module:'dom-dev', lesson:'dh-5', q:'What infrastructure and personnel requirements does a defense or federal-government FDE deployment add on top of a normal enterprise SaaS deploy?', a:'Public-sector workloads layer **three hard requirements** on top of commercial deployments.\n\n- **Air-gapped on-prem deploys** (no outbound internet; updates via approved media)\n- **FedRAMP High** for civilian agencies, **DoD IL5** (or IL6 for classified) for defense\n- **Cleared engineers** (Secret / TS / TS-SCI) on the deploy and support path\n\n**Implication:** procurement cycles are **months to years**, contracts are vehicle-based (GSA, OTA, SBIR), and your build/release pipeline needs a separate sovereign-cloud variant.' },
  { id:'fc-dom-6', cat:'domain', module:'dom-mkt', lesson:'dm-3', q:'What are the non-negotiable properties of a production fintech ledger?', a:'A correct ledger is **double-entry, append-only, and idempotent**. These three properties are load-bearing for audit and dispute resolution.\n\n- **Double-entry:** every transaction posts equal-and-opposite debits and credits; balances are derived, never stored as truth\n- **Append-only:** never `UPDATE` or `DELETE`; corrections are **offsetting entries** (reversal + new posting)\n- **Idempotent writes:** every API call carries an idempotency key so retries can\'t double-post\n- **Audit trail is sacred:** regulators and disputes both replay history from the log' },
  { id:'fc-dom-7', cat:'domain', module:'dom-ai', lesson:'dai-3', q:'What\'s the core UX and infrastructure challenge unique to multimodal generative AI (image, video, audio synthesis)?', a:'Inference takes **seconds to minutes**, not milliseconds, so synchronous request/response breaks down and the whole stack shifts to a **long-running-job pattern**.\n\n- **Async job queue** with durable job IDs (so refresh/disconnect is safe)\n- **Progress channel:** WebSocket push or client polling against a status endpoint\n- **Content moderation pre-gen** (prompt) and **post-gen** (output)\n- **Cancellation tokens** so users can kill expensive in-flight jobs and free GPU\n- Aggressive **caching** of identical prompts and **resumable** multi-step pipelines' },
  { id:'fc-dom-8', cat:'domain', module:'dom-ai', lesson:'dai-2', q:'What\'s the hardest UX problem in real-time voice AI today, and what\'s the current target latency?', a:'**Turn-taking and barge-in** (letting the user interrupt the model) are the hardest problems. Naive systems either talk over the user or leave awkward pauses.\n\n- Industry target is **sub-500ms end-to-end** via streaming **STT to LLM to TTS** overlap\n- **Neural turn-prediction** models have replaced VAD-only silence detection\n- Server-side **interruption handling** must cut TTS audio within ~100ms of detected speech\n- Low latency is **necessary but not sufficient**: natural turn boundaries are what make it feel human' },
  { id:'fc-dom-9', cat:'domain', module:'dom-dev', lesson:'dh-6', q:'Between PLG (product-led growth) and SLG (sales-led growth) motions, which one actually needs Forward Deployed Engineers and why?', a:'**SLG** needs FDEs; **PLG** generally does not.\n\n**SLG (sales-led, enterprise contracts)**\n- Deals are 6- to 7-figure, deployments are bespoke\n- FDE is the **customer-engineering arm**: integrations, custom workflows, on-site enablement\n- Without FDE, sold deals stall in pilot purgatory\n\n**PLG (self-serve, bottom-up adoption)**\n- Onboarding is the product; docs and DX replace humans\n- Support is community + tiered CSMs, not embedded engineers\n\n**Implication:** Palantir, Scale, Anthropic-enterprise = FDE-heavy; Linear, Vercel = PLG-light.' },
  { id:'fc-dom-10', cat:'domain', module:'dom-mkt', lesson:'dm-2', q:'In marketplace matching, when do you use greedy ranking versus ML ranking, and why does pure greedy fail?', a:'Pure **greedy by rating** maximizes short-term match quality but **starves new entrants**: they never accumulate ratings, so the supply pool calcifies and eventually shrinks.\n\n- **Greedy:** simple, explainable, good for early-stage when liquidity is low\n- **Bipartite (Hungarian, Gale-Shapley):** when matches are scarce and global optimality matters (ride-share dispatch, kidney exchange)\n- **ML rank with diversity injection** (5 to 10% traffic routed to newer or lower-ranked suppliers) keeps the supply side healthy and discovers latent winners\n\n**Implication:** treat exploration as a fixed cost of marketplace health, not a leak.' },
  // Meta
  { id:'fc-meta-5', cat:'meta', module:'meta-prep', lesson:'me-1', q:'Which prep activity has the lowest return-on-time during an active job search?', a:'**Re-reading concepts you already know.**\n\nIt feels productive (highlighting, nodding) but builds zero new retrieval pathways. Higher-leverage per hour:\n\n- **Active recall** (closed-book recitation, flashcards)\n- **Mock interviews under time pressure**\n- **Drilling your single weakest round-type**\n\nIf you can already teach the topic aloud, you are past the point of diminishing returns.' },
  { id:'fc-meta-6', cat:'meta', module:'meta-prep', lesson:'me-1', q:'What is the kill-criterion for deciding you have studied a topic enough and should move on?', a:'**If you can teach it aloud and answer 3 follow-ups inside 5 minutes, move on.**\n\n- Past that point, deeper study has sharply diminishing returns\n- The same hour spent on a **weaker topic** clears more loop-variance\n- Variance in your interview outcome is set by your **worst round**, not your best\n\nRe-test the topic in 1 week via flashcard, not by re-reading.' },
  { id:'fc-meta-7', cat:'meta', module:'meta-prep', lesson:'me-1', q:'How much does writing an implementation intention (\'when X, then Y\') actually improve prep follow-through?', a:'**Roughly 2x follow-through versus goal-setting alone** (Gollwitzer meta-analyses across 90+ studies).\n\nMechanism: \'when-then\' plans convert intentions into **automatic environmental triggers** that fire without willpower on low-motivation days.\n\n- **Weak:** "I will study more this week."\n- **Strong:** "When I finish my morning coffee, then I open LeetCode and do one medium."\n\nBind the trigger to an existing daily anchor (coffee, commute, lunch).' },
  { id:'fc-meta-8', cat:'meta', module:'meta-prep', lesson:'me-4', q:'How many concurrent interview processes should you keep active during a serious job search?', a:'**3-5 active processes at any given time.**\n\nWhy this band:\n\n- **Below 3:** any single rejection feels like a verdict; no competing-offer leverage\n- **3-5:** rejections become data; phone screens run in parallel; timeline compresses\n- **Above 5:** prep quality collapses, you confuse company details, calendar fragments\n\nTreat the pipeline as a portfolio, not a sequence.' },
  { id:'fc-meta-9', cat:'meta', module:'meta-prep', lesson:'me-9', q:'When comparing two offers, what is the single strongest predictor of your 2-year outcome in the role?', a:'**Manager quality.** Weight it heavily, often above $40-60k of comp delta.\n\nWhy it dominates:\n\n- **Growth:** great managers create scope, advocate for promo, unblock politically\n- **Learning rate:** weekly 1:1 quality compounds across 100+ weeks\n- **Tenure:** people quit managers, not companies; bad manager = 12-month exit\n- **Reference value:** the next role uses this manager as your top reference\n\nDo backchannel reference calls on the manager before signing.' },
  { id:'fc-meta-10', cat:'meta', module:'meta-prep', lesson:'me-5', q:'What is the one-line salary deflection when a recruiter pushes you for a specific number on the first call?', a:'**Anchor with a market band, then go silent.**\n\n- **Recruiter:** "We really need a number to move forward, what are you targeting?"\n- **You:** "I want to focus on whether the role is a fit first. Market for FDE at your size is roughly $X to $Y total comp. Happy to get specific once we are aligned."\n\nThen **stop talking** and let them respond. Whoever speaks next loses the anchor.' },
  { id:'fc-meta-11', cat:'meta', module:'meta-prep', lesson:'me-6', q:'Which two tokens in a resume bullet do recruiters actually read during a 6-20 second skim?', a:'**The leading verb and the trailing number.**\n\nEverything in the middle is filler the eye skips during initial triage.\n\n- **Front-load the verb:** Shipped, Cut, Rebuilt, Owned (not \'Was responsible for\')\n- **Back-load the metric:** end with the number that matters (latency, revenue, users)\n- **Example:** `Shipped X cutting p95 latency 40%` beats `Was responsible for working on latency improvements`\n\nIf a bullet has no number, it has no signal.' },
  { id:'fc-meta-12', cat:'meta', module:'meta-prep', lesson:'me-9', q:'What is Bezos\'s 70% rule and how does it apply to accepting interview offers?', a:'**When you have ~70% of the info you need, decide. Waiting for 90% costs more than acting on 70%.**\n\n- **Reversible decisions** (accepting an offer, picking a manager) should be made at 70%; you can still renege or leave in 6 months\n- **Irreversible decisions** (one-way doors) deserve closer to 90%\n- Holding for full info burns **optionality** (other offers expire) and **momentum** (the team moves on)\n\nMost engineers over-deliberate reversible calls and under-deliberate irreversible ones.' },
  { id:'fc-meta-13', cat:'meta', module:'meta-prep', lesson:'me-5', q:'When in your career should you negotiate equity refresh grants?', a:'**At offer time AND at every annual performance review.**\n\nMost engineers ask once at hire and never again, leaving real money on the table.\n\n- **At offer time:** get refresh-grant language explicitly in writing, not as a verbal \'we usually refresh top performers\'\n- **At each review cycle:** ask directly, anchored to your impact and external market\n- **After a promo:** refresh is almost always negotiable as part of the promo package\n\nRefresh grants are negotiable, not automatic.' },
  { id:'fc-meta-14', cat:'meta', module:'meta-prep', lesson:'me-1', q:'What is a complete atomic-habits stack for daily interview prep that survives motivation collapse?', a:'**Four-layer stack, deployed together:**\n\n- **Implementation intention:** "When morning coffee finishes, then 25 min of LeetCode."\n- **2-minute rule:** make start-cost under 30 seconds (laptop open, tab pinned night before)\n- **Habit stacking:** anchor prep to an existing daily ritual (coffee, commute, lunch)\n- **Environment design:** phone in another room, single-purpose browser profile, distractions off by default\n\nMotivation decays; infrastructure compounds.' },
  { id:'fc-meta-15', cat:'meta', module:'meta-prep', lesson:'me-8', q:'What is the discipline for processing an interview rejection without losing a week of prep momentum?', a:'**One scheduled 30-minute \'feel bad\' block, then resume normal prep the next day.**\n\n- Give yourself the block, do not suppress the feeling; suppressed it leaks into prep for days\n- **Do not check email obsessively** the day after; fix a single check time\n- **Maintain 3-5 concurrent processes** so any single rejection is data, not a verdict\n- **Re-route energy** into the next-stage live pipelines, not into rumination\n\nA rejection is a low-resolution signal from one team on one day.' },
  // Client Sim
  { id:'fc-cli-2', cat:'client', module:'cli-roleplay', lesson:'c-1', q:'Interviewer asks you to demonstrate ADO with one literal sentence per phase. What do you say?', a:'**Acknowledge:**\n- \'I hear this is blocking your launch.\'\n\n**Diagnose:**\n- \'Checking the logs now, can you confirm when it last worked?\'\n\n**Offer:**\n- \'I\'ll have a fix or a workaround by 4pm, and I\'ll send a written update either way.\'\n\nEach sentence names impact, action, or a time-bound commit, never feelings or filler.' },
  { id:'fc-cli-3', cat:'client', module:'cli-roleplay', lesson:'c-2', q:'Your live demo crashes mid-presentation in front of the customer\'s executive team. How do you recover?', a:'**Acknowledge:** name it, do not minimize.\n- \'That\'s not the experience I wanted to show, let me get you a working view.\'\n\n**Diagnose + show progress on two tracks:**\n- Visible track: switch to recorded demo or screenshots.\n- Backend track: someone debugs in parallel.\n\n**Offer:**\n- Written RCA within 24 hours, do not blame their network in the room.' },
  { id:'fc-cli-4', cat:'client', module:'cli-roleplay', lesson:'c-3', q:'A customer demands 6 weeks of work in 3 days. How do you respond without saying yes or no on the spot?', a:'**Diagnose the real deadline first:**\n- \'What happens on day 4 if this isn\'t done?\' Stated deadlines are often softer than real ones.\n\n**Decompose to the 20% that unblocks them:**\n- Find the minimum slice that hits their actual outcome.\n\n**Offer with explicit tradeoffs:**\n- Two options, cut scope or slip date, written so they choose.' },
  { id:'fc-cli-5', cat:'client', module:'cli-roleplay', lesson:'c-6', q:'You fixed a customer-facing bug yesterday and the exact same symptom returns 2 hours later. How do you respond?', a:'**Acknowledge as Sev1, not as a regression debate:**\n- \'Treating this as Sev1, the prior fix did not hold.\'\n\n**Diagnose visibly:**\n- Commit to specific timeline, status update every 4 hours.\n\n**Offer:**\n- Written RCA covering why the first fix missed.\n\nDefending the original fix in the moment kills trust faster than the bug did.' },
  { id:'fc-cli-6', cat:'client', module:'cli-roleplay', lesson:'c-8', q:'How should you format a weekly written status update so a busy customer actually reads it?', a:'Four labeled bullets, lead with outcomes not activity:\n\n- **Shipped this week:** what landed in their hands.\n- **In flight:** what\'s moving, with owner.\n- **Risks / blockers:** what could slip and what you need.\n- **Next week:** the one or two things that matter.\n\nFive short bullets beat three paragraphs every time.' },
  { id:'fc-cli-7', cat:'client', module:'cli-roleplay', lesson:'c-5', q:'The customer\'s IT or security team is blocking your integration on policy grounds. How do you move forward?', a:'**Acknowledge their mandate, do not route around them:**\n- \'You own this risk, I want to make it easy to clear.\'\n\n**Diagnose what they actually need:**\n- Ask which control or framework, SOC2 vs internal policy.\n\n**Offer a structured security review:**\n- SOC2 docs, architecture diagram, sub-processor list, named security contact.\n\nBypassing IT wins the week and loses the account.' },
  { id:'fc-cli-8', cat:'client', module:'cli-roleplay', lesson:'c-7', q:'Your main customer-side champion just told you they\'re leaving the company in 3 weeks. What do you do?', a:'- Treat champion loss as a **retention risk event**, not a goodbye email.\n- Ask for a warm intro to the replacement before they leave.\n- Re-confirm scope, timeline, and success metrics with the new owner in writing.\n- Get the outgoing champion to forward the last status update with context.\n- Flag the transition internally so account and exec sponsors know.' },
  { id:'fc-cli-9', cat:'client', module:'cli-roleplay', lesson:'c-4', q:'A CFO asks why your AI model gave a different number this week than last week on the same input. How do you explain stochastic variability?', a:'- Lead with a **weather forecast analogy**, same inputs, distribution of outcomes.\n- Show the **confidence range**, not just the point estimate.\n- Anchor on the **95th-percentile worst case** so they can plan around it.\n- Point to **leading indicators** that tell you when the range is widening.\n\nCFOs trust quant ranges, not adjectives.' },
  { id:'fc-ai-29', cat:'ai', module:'ai-rag', lesson:'rag-2', q:'What chunk size and overlap should you start with for a prose-document RAG pipeline?', a:'**Defaults:**\n- ~500--1000 tokens per chunk\n- 10--20% overlap between adjacent chunks\n\n**Why:**\n- Too small -- fragments meaning, hurts answer quality\n- Too large -- dilutes the retrieval signal\n\n**Rule:** chunk on natural boundaries (paragraph, section) first; only fall back to a recursive splitter when those run too long.' },
  { id:'fc-ai-30', cat:'ai', module:'ai-rag', lesson:'rag-3', q:'What can a cross-encoder reranker do that a bi-encoder embedding model cannot?', a:'**Cross-encoder** -- reads the query and candidate doc jointly in one forward pass. Captures token-level interactions and fine-grained relevance.\n\n**Bi-encoder** -- embeds query and doc independently, compares with cosine. Fast at scale but loses joint signal.\n\n**Use both:** bi-encoders for retrieval over the full corpus; cross-encoders to rerank the top 20--100.' },
  { id:'fc-ai-31', cat:'ai', module:'ai-rag', lesson:'rag-3', q:'What is reciprocal rank fusion (RRF) and why is it the default for hybrid retrieval?', a:'**Mechanism:** for each candidate doc, sum `1 / (k + rank_i)` across each retriever\'s ranked list.\n\n**Why it\'s the default:**\n- Score-agnostic -- fuses BM25 + dense ranks without normalizing raw scores\n- Constant `k=60` works out of the box\n- Beats most learned fusion in practice with zero training data' },
  { id:'fc-ai-32', cat:'ai', module:'ai-rag', lesson:'rag-1', q:'What is the \'lost in the middle\' problem in long-context LLM prompts?', a:'**Phenomenon:** LLMs attend most strongly to the start and end of the prompt; recall of items in the middle is the worst.\n\n**Implications for RAG:**\n- Place the most relevant retrieved chunks first or last\n- Keep retrieved context tight -- more chunks past a threshold can hurt accuracy' },
  { id:'fc-ai-33', cat:'ai', module:'ai-rag', lesson:'rag-4', q:'How do you pick an embedding model when starting a new RAG project?', a:'**Process:**\n- Build a retrieval eval -- a few hundred query/document pairs from your domain\n- Score recall@k and MRR\n- Start with a strong general model: Voyage-3, `text-embedding-3-large`, or BGE-M3\n- Only switch to a domain-specific or fine-tuned embedder if the eval shows a real gap\n\n**Final tiebreaker:** latency and self-host requirements.' },
  { id:'fc-ai-34', cat:'ai', module:'ai-rag', lesson:'rag-5', q:'When do you pick HNSW vs IVF as the ANN index for a vector DB?', a:'**HNSW** -- best recall/latency tradeoff for in-memory corpora up to ~100M vectors.\n- Default in pgvector, Qdrant, Weaviate\n\n**IVF (or IVF+PQ)** -- wins when memory cost matters and slightly lower recall is acceptable.\n- Typical for billion-scale corpora in FAISS or Milvus' },
  { id:'fc-ai-35', cat:'ai', module:'ai-rag', lesson:'rag-10', q:'Even with a 1M-token context window, why would you still build a RAG system?', a:'**Cost/latency:** input cost and TTFB scale with tokens even with caching -- stuffing 1M tokens per call is wasteful when most queries need a few KB.\n\n**Capabilities RAG gives you for free:**\n- Citations back to source chunks\n- Per-document access control\n- Freshness via incremental reindexing\n\nAll of these are hard to bolt onto a full-context approach.' },
  { id:'fc-ai-36', cat:'ai', module:'ai-rag', lesson:'rag-7', q:'Your RAG retrieves correct chunks but the model ignores them. What\'s the first thing you check?', a:'**Step 1 -- inspect the actual rendered prompt:**\n- Are chunks truncated?\n- Are they buried under a long system message?\n- Are they in the middle (lost-in-the-middle)?\n\n**Step 2 -- check the system prompt:**\n- Does it explicitly tell the model to answer only from provided context?\n- Does it instruct the model to say \'I don\'t know\' otherwise?' },
  { id:'fc-ai-37', cat:'ai', module:'ai-rag', lesson:'rag-8', q:'How do you enforce document-level access control in a multi-tenant RAG system?', a:'**Rule:** filter at the vector DB query layer using metadata tags (tenant, ACL group, sensitivity). Never trust the LLM to honor \'don\'t show this user X.\'\n\n**Implementation tips:**\n- Index a chunk multiple times if it has multiple ACLs\n- Pass tenant/ACL filters as query params, not prompt text\n\n**Verify:** offline test that user A cannot retrieve user B\'s docs.' },
  { id:'fc-ai-38', cat:'ai', module:'ai-evals', lesson:'ev-1', q:'What does each catch -- offline evals vs online evals -- and why do you need both?', a:'**Offline (golden sets, replay)** -- catches regressions before deploy. Lets you A/B prompts and models head-to-head with stable inputs.\n\n**Online (thumbs, escalation rate, task completion, regret)** -- catches real-user distribution shift and long-tail failures the golden set never covers.\n\n**Both required:** offline guards quality; online guards reality.' },
  { id:'fc-ai-39', cat:'ai', module:'ai-evals', lesson:'ev-2', q:'What are the four common ways LLM-as-judge gives you misleading scores?', a:'- **Position bias** -- prefers the first or last option\n- **Length bias** -- rewards longer, more verbose answers\n- **Self-preference** -- models rate outputs from their own family higher\n- **Rubric drift** -- vague rubrics yield inconsistent grades\n\n**Mitigations:** randomize order, length-normalize, judge with a different model family, write rubrics grounded in concrete examples.' },
  { id:'fc-ai-40', cat:'ai', module:'ai-evals', lesson:'ev-3', q:'You have no labeled data. How do you bootstrap a golden eval set in one sitting?', a:'**Steps:**\n- Mine real or synthetic user queries\n- Have a strong model draft candidate answers\n- Hand-correct 50--200 of them in one focused session\n- Stratify by intent so every failure mode is represented\n\n**Operate:** track per-category accuracy from day one. A small high-quality set beats a noisy large one.' },
  { id:'fc-ai-41', cat:'ai', module:'ai-evals', lesson:'ev-4', q:'Beyond task success, which eval dimensions matter most for an agent that spends money?', a:'**Additional metrics:**\n- False-positive action rate\n- Cost-per-resolved-task\n- Unauthorized-action rate (action outside the allowlist)\n- Human-escalation rate\n\n**Mandatory red-team cases:** adversarial inputs that try to trigger spend.\n\n**Hard fail rule:** any unauthorized irreversible action.' },
  { id:'fc-ai-42', cat:'ai', module:'ai-prompt', lesson:'pr-1', q:'What are the standard sections of a production system prompt?', a:'- **Role and goal** -- who the model is, what it\'s solving\n- **Operating constraints** -- what it must not do\n- **Tool / output schema** -- structured contract\n- **Retrieved context block** -- clearly delimited\n- **Few-shot examples** -- for tricky cases\n- **Final instruction** -- restate the task\n\n**Caching tip:** keep the stable prefix (role, constraints, tools, examples) at the top so prompt caching reuses it.' },
  { id:'fc-ai-43', cat:'ai', module:'ai-prompt', lesson:'pr-2', q:'When should you use a reasoning model vs a non-reasoning model with a CoT prompt?', a:'**Reasoning model (Claude extended thinking, GPT-5 thinking, Gemini 2.5 thinking):**\n- Multi-step math, code, planning, hard tool decisions\n- Trained reasoning beats prompted CoT\n- Avoids reasoning-leak into user-visible output\n\n**Non-reasoning model:**\n- Short extraction, classification, chat\n- Latency and thinking-token cost aren\'t worth it' },
  { id:'fc-ai-44', cat:'ai', module:'ai-prompt', lesson:'pr-5', q:'What\'s the typical minimum prefix size for prompt caching, and how do you maximize the cache hit rate?', a:'**Minimum:** ~1024+ tokens of stable prefix (provider-dependent).\n\n**Maximize hits:**\n- Put variable content (user input, retrieved chunks) at the END of the prompt\n- Keep tools, system prompt, and few-shots byte-identical across calls\n- Watch for whitespace, ordering, or JSON-key churn -- any change invalidates the cache' },
  { id:'fc-ai-45', cat:'ai', module:'ai-prompt', lesson:'pr-4', q:'What\'s the difference between direct and indirect prompt injection?', a:'**Direct** -- a user types adversarial instructions into the chat.\nExample: \'ignore previous instructions and...\'\n\n**Indirect** -- malicious instructions arrive via retrieved content, a webpage the agent browses, or a tool response.\n\n**Why indirect is harder:** the user is benign and the payload looks like data, so naive policy checks miss it.' },
  { id:'fc-ai-46', cat:'ai', module:'ai-agents', lesson:'ag-1', q:'When does a problem actually require an agent instead of a chain?', a:'**Need an agent when:** the next step depends on prior tool outputs in ways you can\'t enumerate up front.\n- Investigation\n- Research\n- Multi-step debugging\n- Open-ended planning\n\n**Stick with a chain when:** you can draw the DAG of steps before runtime. Cheaper, more debuggable, easier to eval.' },
  { id:'fc-ai-47', cat:'ai', module:'ai-agents', lesson:'ag-2', q:'What are the top failure modes for LLM tool calling in production, and how do you mitigate them?', a:'**Failures:**\n- Hallucinated tool names or arguments\n- Wrong arg types (string vs number)\n- Skipping required args\n- Calling the right tool with stale context\n- Infinite tool-call loops\n- Ignoring the tool result and answering from priors\n\n**Mitigations:** strict JSON Schema, structured outputs, step budget, post-tool reflection step.' },
  { id:'fc-ai-48', cat:'ai', module:'ai-agents', lesson:'ag-4', q:'Why use JSON Schema with strict structured outputs instead of just instructing the model to \'return JSON\'?', a:'**Strict structured outputs constrain decoding** to the schema\'s grammar:\n- Response is guaranteed parseable and typed\n- No retries on malformed JSON\n- No prompt-injection-driven schema escape\n\n**Bonus:** doubles as a security boundary. An `action` field typed as an enum cannot be spoofed by adversarial input.' },
  { id:'fc-ai-49', cat:'ai', module:'ai-agents', lesson:'ag-7', q:'What two things should every well-designed MCP server expose?', a:'- **A small set of focused tools** -- clear typed schemas + human-readable descriptions the model can reason about\n- **Auth and per-tool permission scopes** -- so the host (Claude Desktop, IDE, agent) can enforce least privilege\n\n**Optional extras:** resources and prompts. Don\'t lead with these.' },
  { id:'fc-ai-50', cat:'ai', module:'ai-agents', lesson:'ag-9', q:'What are the three highest-leverage cost levers for an LLM-powered product?', a:'- **Prompt caching** on stable prefixes -- up to 90% off input tokens\n- **Model routing** -- cheap small model for easy queries, escalate only when needed\n- **Output length control** -- cap `max_tokens` and prompt for terseness\n\n**Next tier:** Batch API and structured outputs (fewer retries).' },
  { id:'fc-ai-51', cat:'ai', module:'ai-agents', lesson:'ag-9', q:'How does a model-routing or cascading setup work, and what\'s the failure mode to watch?', a:'**Mechanism:**\n- Cheap classifier or small model handles the request first\n- A confidence score or self-grader decides whether to escalate\n- Large model only runs on the hard tail\n\n**Typical mix:** 60--90% of traffic stays on the small model.\n\n**Watch:** eval the router separately -- a bad router silently degrades quality with no visible error.' },
  { id:'fc-ai-52', cat:'ai', module:'ai-finetune', lesson:'ft-1', q:'What\'s the decision tree for choosing between prompting, RAG, and fine-tuning?', a:'**1. Start with prompting.** Cheapest to iterate.\n\n**2. Add RAG** if the model lacks domain facts or freshness.\n\n**3. Fine-tune** only if -- after good prompting -- it still can\'t follow a proprietary format, tone, or narrow task at the required latency.\n\n**Why fine-tune last:** slow to iterate, bakes in mistakes, expensive to redo.' },
  { id:'fc-ai-53', cat:'ai', module:'ai-finetune', lesson:'ft-2', q:'How much training data do you actually need to fine-tune an LLM for a narrow task in 2026?', a:'**Volume:** 500--5000 high-quality examples usually beats 50k noisy ones for supervised fine-tuning of an instruction-tuned model.\n\n**Tooling:** LoRA / QLoRA make this cheap.\n\n**What matters more than count:**\n- Data quality\n- Schema consistency\n- Coverage of edge cases' },
  { id:'fc-ai-54', cat:'ai', module:'ai-finetune', lesson:'ft-2', q:'What is RLHF, and where does it sit relative to SFT and DPO?', a:'**SFT (Supervised Fine-Tuning)** -- trains on (prompt, ideal answer) pairs.\n\n**RLHF** -- trains a reward model from human preference pairs, then uses PPO to push the policy toward preferred outputs.\n\n**DPO (Direct Preference Optimization)** -- skips the reward model and optimizes preferences directly. Simpler; now the common default for preference tuning.' },
  { id:'fc-ai-55', cat:'ai', module:'ai-evals', lesson:'ev-1', q:'What is a \'regret\' metric in online LLM evaluation, and why is it valuable?', a:'**Definition:** regret measures how often a user signal indicates the response was wrong or unhelpful.\n\n**Signals counted:**\n- Thumbs-down\n- Re-asked question\n- Edit-and-resubmit\n- Escalation to a human\n- Task abandonment\n\n**Why valuable:** cheapest, highest-signal online metric -- users produce it for free, and it tracks real harm rather than vibes.' },
  { id:'fc-ai-56', cat:'ai', module:'ai-agents', lesson:'ag-3', q:'Why must irreversible agent actions require human-in-the-loop confirmation?', a:'**Risk:** hallucinations and prompt injections are non-zero, and irreversible actions (payments, deletes, external emails) have no undo.\n\n**Mitigation:** a confirmation step over a typed action schema.\n\n**Two wins:**\n- Turns catastrophic failures into a UX speed bump\n- Generates labeled data on when the agent was wrong, which feeds future evals' },
  { id:'fc-beh-17', cat:'behav', module:'b-stories', lesson:'b-6', q:'Within a STAR behavioral answer, what fraction should be Action, and how should the remaining time split across Situation, Task, and Result?', a:'**Target split:**\n\n- **Situation + Task (~20%)** -- 2-3 sentences of context plus a one-line scope of YOUR ownership.\n- **Action (~60%)** -- specific technical and interpersonal moves you personally made.\n- **Result (~20%)** -- technical outcome plus quantified business impact.' },
  { id:'fc-beh-18', cat:'behav', module:'b-stories', lesson:'b-6', q:'Why does using `we` instead of `I` weaken behavioral answers, and how do you correct it mid-story?', a:'**Why it weakens:** `we` hides individual ownership -- the exact thing Forward Deployed Engineer (FDE) rounds probe.\n\n**How to fix mid-story:**\n\n- Switch to **`I`** for every decision and action: `I escalated to the on-call`, `I wrote the rollback script`.\n- Reserve **`we`** only for true group context (team headcount, org-wide goals).' },
  { id:'fc-beh-19', cat:'behav', module:'b-values', lesson:'v-3', q:'At Palantir, what three elements separate a real failure story from a sanitized humblebrag?', a:'**Three required elements:**\n\n- 1. **Concrete mechanism** -- what actually broke and why.\n- 2. **Real cost** -- dollars, users, downtime, or trust lost.\n- 3. **Systemic change afterward** -- process, monitoring, or design fix so it cannot recur.\n\nWithout all three, the story reads as performative.' },
  { id:'fc-beh-20', cat:'behav', module:'b-values', lesson:'v-3', q:'What are three failure-story openers that get you instantly rejected at Palantir?', a:'**Instant-reject openers:**\n\n- 1. `I work too hard.`\n- 2. `I\'m a perfectionist.`\n- 3. `I don\'t really fail / I can\'t think of one.`\n\nAll signal lack of self-awareness or unwillingness to own a real mistake.' },
  { id:'fc-beh-21', cat:'behav', module:'b-stories', lesson:'b-1', q:'When telling a `production fix under pressure` story, what single detail most strengthens it?', a:'**A timestamped sequence of decision points.**\n\nExample: `At T+4min I rolled back the deploy. At T+11min I patched the config. At T+23min traffic recovered.`\n\nSpecificity at this resolution proves you actually owned the incident rather than narrating someone else\'s.' },
  { id:'fc-beh-22', cat:'behav', module:'b-fivestories', lesson:'bs-2', q:'When telling a `pushing back on a customer` story, what must the Action section contain beyond just saying no?', a:'**Required Action content:**\n\n- The **alternative** you proposed.\n- **Why** it served the customer\'s underlying goal better than their original ask.\n- How you **preserved the relationship** -- often by reframing as a smaller scoped pilot or a different mechanism hitting the same outcome.\n\n`I said no` alone reads as rigid, not principled.' },
  { id:'fc-beh-23', cat:'behav', module:'b-fivestories', lesson:'bs-3', q:'In a deployment-failure story, what distinguishes true ownership from mere involvement?', a:'**Ownership vs involvement:**\n\n- **Ownership:** you ran the rollback, the customer comms, AND the postmortem -- and the systemic fix shipped under your name.\n- **Involvement:** `I helped the on-call.`\n\nInterviewers listen for first-person verbs on every step of the recovery.' },
  { id:'fc-beh-24', cat:'behav', module:'b-fivestories', lesson:'bs-4', q:'How do you explain a hard technical limit to a non-technical stakeholder without sounding dismissive?', a:'**Three-step move:**\n\n- 1. **Translate** the constraint into their unit of value -- revenue, user latency, regulatory risk.\n- 2. **Offer 2-3 ranked alternatives** with explicit tradeoffs.\n- 3. **Let them choose.**\n\nNever close with `it\'s impossible`. Close with `here are the options and what each costs`.' },
  { id:'fc-beh-25', cat:'behav', module:'b-fivestories', lesson:'bs-5', q:'What separates a strong `decision under incomplete information` story from a weak one?', a:'**Strong vs Weak:**\n\n- **Strong:** you name the specific unknowns, the cheapest experiment you ran to reduce them, your decision criteria, and what you would do differently in hindsight.\n- **Weak:** `I went with my gut and it worked out` -- gives no signal on judgment.' },
  { id:'fc-beh-26', cat:'behav', module:'b-stories', lesson:'b-6', q:'Why is preparing 3-5 deep stories better than 20 shallow ones for a behavioral loop?', a:'**Why depth wins:**\n\n- Each deep story can be **retold from multiple angles** (failure, conflict, leadership, customer-first) to cover ~80% of prompts.\n- Twenty shallow stories **crumble under follow-up** because you cannot recall the mechanism, metric, or sequence.\n\nInterviewers probe; rehearsed surface-level scripts collapse on the second question.' },
  { id:'fc-beh-27', cat:'behav', module:'b-stories', lesson:'b-6', q:'What four specificity hooks make a behavioral answer feel real rather than rehearsed?', a:'**Four specificity hooks:**\n\n- 1. **Named people or teams** (anonymized if needed).\n- 2. **Dates or durations** -- `over six weeks`, `in Q3 2024`.\n- 3. **Quantified metrics** -- dollars, percent, users, latency.\n- 4. **Exact tool or system named** -- `Postgres replica`, `Terraform module`.' },
  { id:'fc-beh-28', cat:'behav', module:'b-stories', lesson:'b-6', q:'How do you signal that you prioritize customer outcome over engineering aesthetics when telling a story?', a:'**Tell a story where you:**\n\n- Shipped a **less elegant** solution because the customer needed it Friday.\n- **Scheduled the refactor** as a follow-up that you owned and delivered.\n\nThe signal: you optimized for customer outcome on the critical path, not for your own technical pride.' },
  { id:'fc-beh-29', cat:'behav', module:'b-fivestories', lesson:'bs-2', q:'What is the strongest pattern for a `leading without authority` story?', a:'**Four-step influence pattern:**\n\n- 1. Identify a cross-team gap nobody owned.\n- 2. Write the doc or spec yourself.\n- 3. **Pre-wire** 2-3 key stakeholders in 1:1s before any group meeting.\n- 4. Run the meeting against your draft.\n\nThe Action is **influence work** (written artifacts + pre-wiring), not formal authority.' },
  { id:'fc-beh-30', cat:'behav', module:'b-stories', lesson:'b-6', q:'If you realize mid-interview that you just gave a weak behavioral answer, how should you recover?', a:'**Recovery steps:**\n\n- 1. **Name it:** `That answer rambled -- let me give you the 30-second version.`\n- 2. **Deliver tight STAR** on the same prompt.\n\nSelf-awareness plus correction is a **positive signal**. Pretending it went well is worse than acknowledging.' },
  { id:'fc-beh-31', cat:'behav', module:'b-values', lesson:'v-1', q:'How do you tailor the same underlying story for OpenAI, Anthropic, and Palantir interviews?', a:'**Same arc, different emphasis:**\n\n- **OpenAI** -- shipping velocity and user impact at scale.\n- **Anthropic** -- the safety/risk reasoning and tradeoffs you weighed.\n- **Palantir** -- ownership, on-the-ground customer work, and explicit failure-mechanism honesty.' },
  { id:'fc-beh-32', cat:'behav', module:'b-values', lesson:'v-3', q:'What two Palantir-specific `why us` traps should you avoid in interviews?', a:'**Two traps:**\n\n- 1. **Confusing Foundry with Gotham** -- Foundry is the commercial data platform; Gotham is the government/intel product. Mixing them up signals you did not do basic research.\n- 2. **Citing comp, perks, or `cool problems`** instead of a specific product, customer segment, or mission angle you can defend with detail.' },
  { id:'fc-cli-10', cat:'client', module:'cli-roleplay', lesson:'c-1', q:'Walk through what each letter of ADO actually means in a client-sim round.', a:'**Acknowledge:**\n- Mirror impact in the customer\'s words, not \'sorry for the inconvenience.\'\n\n**Diagnose:**\n- Think out loud so they see progress and can add context.\n\n**Offer:**\n- A concrete next step with a named owner and a time, even if the step is just \'I\'ll write back by 5pm.\'' },
  { id:'fc-cli-11', cat:'client', module:'cli-roleplay', lesson:'c-1', q:'Mid-roleplay, the interviewer asks a technical question you genuinely don\'t know. How do you recover without bluffing?', a:'- Say **\'I don\'t know yet\'**, not \'I don\'t know.\'\n- State **what you would check** to find out, e.g. \'I\'d pull the request logs and check the auth layer.\'\n- Commit to a **time** you\'ll come back with the answer.\n- Move the conversation forward, do not stall on the unknown.\n\nBluffing is the single fastest way to fail the round.' },
  { id:'fc-cli-12', cat:'client', module:'cli-roleplay', lesson:'c-3', q:'A customer asks for something you think is a mistake. When do you push back and when do you just do it?', a:'**Push back when it hurts their outcome:**\n- Bad data, unsafe rollout, wrong success metric.\n\n**Acquiesce on low-cost preference items:**\n- UI choices, report format, naming.\n\n**Always name the tradeoff out loud:**\n- \'If we ship it that way, here\'s the risk, the call is yours.\'\n\nThe choice stays theirs, the framing stays yours.' },
  { id:'fc-cli-13', cat:'client', module:'cli-roleplay', lesson:'c-8', q:'You need to tell a customer that a promised feature is going to slip by 2 weeks. How do you structure the message?', a:'- **Lead with the headline and impact** in sentence one, not the backstory.\n- State **what you\'re doing about it** and who owns each piece.\n- Name the **next checkpoint** with a date.\n- Offer a workaround if one exists.\n\nBurying bad news mid-paragraph or waiting for the next standing meeting is the anti-pattern interviewers flag.' },
  { id:'fc-cli-14', cat:'client', module:'cli-roleplay', lesson:'c-1', q:'What are the top anti-patterns that fail candidates in a client simulation round?', a:'- **Defensiveness:** \'well, actually...\' or arguing the customer\'s framing.\n- **Blaming their environment** or team in the live moment.\n- **Over-promising a fix time** you cannot hit.\n- **Ending the turn without a committed next step** (no owner, no time).\n\nAny one of these is usually a no-hire signal on its own.' },
  { id:'fc-cli-15', cat:'client', module:'cli-roleplay', lesson:'c-9', q:'You\'re 3 weeks into an engagement and something is going sideways. When and how should you escalate to your manager?', a:'**Escalate when:**\n- The issue threatens the contract or renewal.\n- It needs a resource or policy decision above your level.\n- You\'ve missed a committed timeline twice.\n\n**How to escalate:**\n- Lead with a **recommendation**, not a problem dump.\n- \'Here\'s what\'s happening and what I\'d like to do, I need X from you.\'\n- Escalate early, surprises cost more than asks.' },
  { id:'fc-cli-16', cat:'client', module:'cli-roleplay', lesson:'c-3', q:'Halfway through the engagement, you realize the original scope won\'t fit the deadline. How do you renegotiate without losing trust?', a:'- **Re-anchor on the business outcome**, not the feature list.\n- Show the **current burn-down** so the math is shared, not asserted.\n- Present **two options with explicit tradeoffs**:\n- Cut scope X, hit the original date.\n- Keep scope X, slip the date by N weeks.\n- Let the customer pick. **Never silently de-scope**, that is how trust dies.' },
  { id:'fc-cli-17', cat:'client', module:'cli-roleplay', lesson:'c-10', q:'Your data shows the project the customer wants to build won\'t hit their business goal. How do you recommend killing it gracefully?', a:'- Frame the recommendation as **protecting their outcome**, not retreating.\n- Show the **data** on why the current path misses the goal.\n- Propose the **smaller bet** that would hit it instead.\n- Offer to **keep the relationship warm** even if they pause.\n\nCredibility goes up, not down, when you can say \'we shouldn\'t build this.\'' },
  { id:'fc-cli-18', cat:'client', module:'cli-roleplay', lesson:'c-1', q:'What signals are client-sim interviewers actually grading you on behind the rubric?', a:'- **Composure under pressure:** no flinching, no filler words, no defensive tone.\n- **Customer-first framing:** their outcome named before your product.\n- **Concrete next step:** owner + time + written follow-up committed in the turn.\n- **Clean ADO loop:** every reply ends with an Offer, not a feeling.\n\nPolish matters less than landing the loop.' },
  { id:'fc-cl-22', cat:'cloud', module:'cl-integ', lesson:'in-3', q:'SAML vs OIDC vs OAuth 2.0: when do you reach for each?', a:'**SAML**\n- Enterprise browser SSO into a SaaS app. XML assertions, IdP-initiated common.\n\n**OIDC**\n- Modern SSO + identity. JWT `id_token`. Mobile, SPA, and API friendly. Built on OAuth.\n\n**OAuth 2.0**\n- Delegated authorization. `access_token` to call an API on a user\'s behalf. It is NOT authentication.\n\n**Rule:** SAML and OIDC answer \'who is the user?\'; OAuth answers \'what can this token do?\'' },
  { id:'fc-cl-23', cat:'cloud', module:'cl-integ', lesson:'in-1', q:'Why is Authorization Code + PKCE the default in OAuth 2.1?', a:'**PKCE (Proof Key for Code Exchange)** binds the auth code to the original client via a `code_verifier` / `code_challenge` pair.\n\n**What it defeats:** code interception attacks on public clients (mobile, SPA) where the client secret cannot be safely stored.\n\n**OAuth 2.1 changes:**\n- PKCE is mandatory for ALL clients (public and confidential).\n- Implicit grant removed.\n- ROPC (Resource Owner Password Credentials) removed.' },
  { id:'fc-cl-24', cat:'cloud', module:'cl-core', lesson:'cl-1', q:'S3 vs GCS vs Azure Blob: what are the key differences?', a:'**S3 (AWS)**\n- Richest ecosystem: Athena, Glacier tiers, S3 Select. Strongest tooling.\n\n**GCS (GCP)**\n- Cleanest consistency model. Dual-region buckets for built-in geo-redundancy.\n\n**Azure Blob**\n- Tight Entra ID integration. Mandatory in Microsoft-heavy enterprises.\n\nAll three: 11 nines durability, lifecycle policies, IAM, encryption at rest. **Pick by where the rest of your stack lives.**' },
  { id:'fc-cl-25', cat:'cloud', module:'cl-core', lesson:'cl-1', q:'PrivateLink vs VPN vs Direct Connect: which connectivity option for which use case?', a:'**PrivateLink / Private Service Connect**\n- Expose a single service privately across VPCs or accounts without peering.\n- Best for SaaS-to-customer connectivity.\n\n**Site-to-site VPN**\n- Encrypted tunnel over the public internet. Fast to set up, ~1 Gbps.\n- Use for low-volume hybrid connectivity.\n\n**Direct Connect / Cloud Interconnect**\n- Dedicated fiber. 10-100 Gbps, predictable latency.\n- Use for big enterprise hybrid at scale.' },
  { id:'fc-cl-26', cat:'cloud', module:'cl-core', lesson:'cl-1', q:'What does IAM least-privilege look like in practice?', a:'- **Roles not users.** One role per workload.\n- **Scope actions to specific resources** (`arn:aws:s3:::bucket/prefix/*`), never `*`.\n- **Permission boundaries** and **session policies** to cap blast radius.\n- **Access Analyzer** / **IAM Recommender** runs periodically to prune unused permissions.\n- **No long-lived access keys.** Use IAM Roles for Service Accounts (EKS) or Workload Identity (GKE).' },
  { id:'fc-cl-27', cat:'cloud', module:'cl-core', lesson:'cl-1', q:'KMS key rotation: when is it automatic vs manual?', a:'**Automatic**\n- AWS KMS auto-rotates symmetric CMKs yearly. Old key material stays for decrypt, so no re-encrypt step is needed.\n\n**Manual**\n- Asymmetric keys.\n- Customer-managed BYOK keys.\n\n**Audit** via CloudTrail `kms:GenerateDataKey` events.\n\n**Rule of thumb:** rotating the data-encryption key (DEK) is cheap and frequent; rotating the master key (KEK) is rare and ceremonial.' },
  { id:'fc-cl-28', cat:'cloud', module:'cl-core', lesson:'cl-1', q:'Secrets management: how do Vault, AWS Secrets Manager, and Doppler compare?', a:'**HashiCorp Vault**\n- Multi-cloud. Dynamic short-lived DB creds. Strongest model, ops-heavy.\n\n**AWS Secrets Manager / GCP Secret Manager**\n- Cloud-native, IAM-integrated, automatic rotation hooks. Cheap for single-cloud.\n\n**Doppler / 1Password Secrets**\n- Developer-friendly UX. Good for app config across environments.\n\n**Universal rule:** never commit secrets; use OIDC federation from CI so no static keys touch disk.' },
  { id:'fc-cl-29', cat:'cloud', module:'cl-integ', lesson:'in-4', q:'CloudWatch vs Datadog vs Honeycomb: what are the tradeoffs?', a:'**CloudWatch / Cloud Monitoring**\n- Cheapest, native. Weak cross-account UX, slow dashboards.\n\n**Datadog**\n- Best dashboards, APM, unified logs+metrics+traces. Cost scales painfully past ~100 hosts.\n\n**Honeycomb / Grafana Cloud**\n- Strong on traces and high-cardinality data.\n\n**Rule:** start native, move to Datadog when you have on-call rotations, build on OTel so backend choice stays portable.' },
  { id:'fc-cl-30', cat:'cloud', module:'cl-integ', lesson:'in-4', q:'SLI vs SLO vs SLA: what are the precise definitions?', a:'- **SLI**: the measurement (e.g., \'fraction of requests with latency < 300ms\').\n- **SLO**: the internal target (e.g., \'SLI >= 99.9% over 30 days\').\n- **SLA**: the customer contract with penalties (e.g., \'99.5% or 10% credit\').\n\n**Invariants:**\n- SLO is always tighter than SLA.\n- Error budget = 1 - SLO. When burned, freeze risky deploys until it recovers.' },
  { id:'fc-cl-31', cat:'cloud', module:'cl-integ', lesson:'in-5', q:'Terraform vs CDK: when do you pick which?', a:'**Terraform**\n- Declarative HCL, multi-cloud, huge module ecosystem.\n- State file is the source of truth.\n- Best for infra teams managing many accounts.\n\n**CDK (AWS CDK / CDKTF)**\n- Write infra in TypeScript or Python with loops and conditionals.\n- Compiles to CloudFormation or Terraform under the hood.\n- Best for app teams who want infra colocated with code.\n\n**Default:** Terraform for org-wide platforms, CDK for product squads.' },
  { id:'fc-cl-32', cat:'cloud', module:'cl-core', lesson:'cl-1', q:'Which autoscaling metric should you use for which workload?', a:'- **Stateless web/API**: target CPU 60-70% or requests-per-target (ALB).\n- **Queue workers**: scale on queue depth or age of oldest message (SQS `ApproximateAgeOfOldestMessage`).\n- **GPU inference**: scale on in-flight request count or token-throughput, not CPU.\n\n**Avoid:** memory-based scaling for JVM and Python. They hoard heap and never scale down.' },
  { id:'fc-cl-33', cat:'cloud', module:'cl-core', lesson:'cl-1', q:'What is the playbook for mitigating Lambda or Cloud Run cold-starts?', a:'1. **Provisioned concurrency** (Lambda) or `min-instances=1` (Cloud Run) for latency-critical paths.\n2. **Trim the deploy artifact**: bundle, tree-shake, drop unused SDKs.\n3. **Lazy-load** heavy deps after the handler returns its first byte.\n4. Prefer **SnapStart** (Lambda) or **CPU-always-allocated** (Cloud Run gen2).\n5. Move to a **long-running container** if p99 cold-start dominates the SLO.' },
  { id:'fc-cl-34', cat:'cloud', module:'cl-core', lesson:'cl-1', q:'Multi-region failover: active-active vs active-passive tradeoffs?', a:'**Active-passive**\n- Primary serves traffic; standby replicates async. Route 53 or Cloud DNS health-check failover.\n- RTO minutes, RPO seconds-to-minutes. Cheap.\n\n**Active-active**\n- Both regions serve traffic. Requires conflict-free writes (CRDTs, region-pinned tenants, or a global DB like Spanner or DynamoDB Global Tables).\n- RTO near zero, RPO near zero. 2x cost and a much harder consistency story.' },
  { id:'fc-cl-35', cat:'cloud', module:'cl-core', lesson:'cl-1', q:'Eventually-consistent reads: when do they bite you and how do you fix it?', a:'**Where it bites:** a read on a different replica returns stale data (DynamoDB eventually-consistent reads, S3 cross-region replication, Postgres read replicas).\n\n**Failure modes:**\n- Create resource then immediately GET it.\n- Dashboard undo flows.\n- Balance or quota checks before a critical write.\n\n**Fix:** strong/consistent read for the immediate follow-up, or a write-through cache keyed by request id.' },
  { id:'fc-cl-36', cat:'cloud', module:'cl-core', lesson:'cl-4', q:'SOC 2 Type I vs Type II: what difference do enterprise buyers care about?', a:'**Type I**\n- Point-in-time snapshot: controls were designed correctly on date X.\n- Acceptable only as a year-one bridge.\n\n**Type II**\n- Controls operated effectively over a period (typically 6-12 months) with auditor sampling.\n- Enterprise procurement almost always demands Type II.\n\n**Five Trust Services Criteria:** Security (always required), Availability, Confidentiality, Processing Integrity, Privacy (pick based on product).' },
  { id:'fc-cl-37', cat:'cloud', module:'cl-core', lesson:'cl-4', q:'HIPAA compliance: what does a SaaS vendor actually have to implement?', a:'- **Sign a BAA** (Business Associate Agreement) with each covered entity.\n- **Administrative safeguards:** access reviews, workforce training, incident response.\n- **Physical safeguards:** facility access, device controls (inherited from cloud provider).\n- **Technical safeguards:** unique user IDs, auto-logoff, audit logs of PHI access, encryption at rest and in transit.\n- **Breach notification** within 60 days.\n\nUse the cloud\'s HIPAA-eligible service list; a single non-eligible service in the data path breaks compliance.' },
  { id:'fc-cl-38', cat:'cloud', module:'cl-core', lesson:'cl-4', q:'FedRAMP Moderate vs High: when do you need which and what does authorization cost?', a:'**FedRAMP Moderate**\n- Most federal SaaS handling Controlled Unclassified Information (CUI).\n- ~325 controls from NIST 800-53.\n\n**FedRAMP High**\n- Law enforcement, emergency services, financial systems.\n- ~410 controls plus stricter background checks and US-citizen operator requirements.\n\n**Practical path:** build on AWS GovCloud or Azure Government, inherit their ATO, get a 3PAO audit. Timeline 12-18 months, cost $1-2M minimum.' },
  { id:'fc-cl-39', cat:'cloud', module:'cl-core', lesson:'cl-1', q:'VPC peering vs Transit Gateway: when do you graduate from one to the other?', a:'**VPC peering**\n- 1:1, non-transitive (A-B and B-C does NOT give A-C).\n- Free data transfer in-region.\n- Fine for 2-5 VPCs.\n\n**Transit Gateway / Network Connectivity Center**\n- Hub-and-spoke, transitive routing.\n- Supports VPN and Direct Connect attachments.\n- Mandatory once you have 10+ VPCs or a multi-account org.\n\n**Cost:** per-attachment per-hour plus data; budget for it explicitly.' },
  { id:'fc-cl-40', cat:'cloud', module:'cl-core', lesson:'cl-2', q:'Service mesh basics: Istio vs Linkerd, which should you pick?', a:'Both inject a sidecar proxy that handles `mTLS`, retries, circuit-breaking, and L7 telemetry with no app code changes.\n\n**Istio**\n- Feature-rich (Envoy-based, WASM extensions, traffic mirroring).\n- Heavier control plane, steep ops cost.\n\n**Linkerd**\n- Rust-based \'micro-proxy\'. Simpler, lower CPU/memory overhead, fewer knobs.\n\n**Default:** Linkerd for most teams. Pick Istio only if you need its specific traffic-policy or extension features.' },
  { id:'fc-cl-41', cat:'cloud', module:'cl-integ', lesson:'in-2', q:'Webhook idempotency: what is the receiver-side dedupe pattern?', a:'1. Sender includes a stable `event_id` (UUID) per logical event and retries with the same id.\n2. Receiver stores processed `event_id`s in a dedupe table with a TTL longer than the sender\'s retry window (24-48h).\n3. On replay, look up the id. If seen, return 200 immediately without re-running side effects.\n4. Combine with **HMAC signature** + **timestamp tolerance** (~5 min) to block replay attacks from outside the sender.' },
  { id:'fc-cl-42', cat:'cloud', module:'cl-core', lesson:'cl-3', q:'Terraform state: why do remote backends and state locking matter?', a:'The state file holds the mapping from HCL to real resource IDs plus any embedded secrets.\n\n**Problems with local state:**\n- Breaks team workflows (whose laptop has the latest state?).\n- Leaks credentials into git if accidentally committed.\n\n**Remote backend** (S3+DynamoDB, GCS, Terraform Cloud) gives:\n- Shared state across the team.\n- Encryption at rest.\n- A lock so two engineers cannot `apply` concurrently and corrupt the file.\n\nAlways enable versioning on the backend bucket so a botched apply is rollback-able.' },
  { id:'fc-cod-31', cat:'coding', module:'cod-graphs', lesson:'g-2', q:'What traversal finds the shortest path between two users in a 10M-node social graph?', a:'**Approach:** **Bidirectional BFS** from both endpoints, alternating expansion of the smaller frontier each round. Stop when the two frontiers intersect.\n\n**Why:** plain BFS explores `b^d` nodes; bidirectional cuts that to roughly `2 * b^(d/2)`, which is decisive on high-fanout social graphs.\n\n**Complexity:** `O(b^(d/2))` instead of `O(b^d)`, where `b` is branching factor and `d` is path length.' },
  { id:'fc-cod-32', cat:'coding', module:'cod-graphs', lesson:'g-3', q:'How do you seed the queue for multi-source BFS (e.g., infection spread or 0-1 matrix)?', a:'**Approach:** Push **every source** onto the queue at the start, all with distance `0`, and mark them all visited up front. Then run standard BFS.\n\nThe first time BFS reaches any node, that\'s its distance to the **nearest** source, because all sources expanded in lockstep from layer `0`.\n\n**Complexity:** single pass, `O(V + E)`. Far better than running BFS from each source separately.' },
  { id:'fc-cod-33', cat:'coding', module:'cod-graphs', lesson:'g-LC2', q:'Shortest path in a grid with up to K obstacle removals: what\'s the BFS state?', a:'**Approach:** Augment the state with the **remaining eliminations**: `(row, col, k_left)`. Visited is keyed on the full triple so the same cell can be reached with different elimination budgets.\n\n- Still BFS (not Dijkstra) because every move costs `1`\n- Without `k_left` in the key, you\'d prune optimal paths that need more obstacle credit\n\n**Complexity:** `O(R * C * K)` time and space.' },
  { id:'fc-cod-34', cat:'coding', module:'cod-graphs', lesson:'g-LC3', q:'Bus Routes (minimum buses to reach destination): what\'s the right graph to BFS over?', a:'**Approach:** Build a graph of **routes**, not stops. Two routes are connected iff they share at least one stop. BFS over routes from any route containing the source to any route containing the target; the level count `+ 1` is the answer.\n\n**Why not stops:** each stop has many neighbors via its routes, blowing up the edge count. Routes are far fewer than stop-edges in practice.' },
  { id:'fc-cod-35', cat:'coding', module:'cod-advgraphs', lesson:'ag-LC3', q:'What is the bridge condition in Tarjan\'s bridge-finding algorithm?', a:'**Approach:** DFS while tracking two values per node:\n\n- `disc[u]` = discovery time of `u`\n- `low[u]` = lowest `disc` reachable from `u`\'s DFS subtree via tree edges plus at most one back-edge\n\n**Bridge condition:** edge `(u, v)` (where `v` is a child of `u`) is a bridge iff `low[v] > disc[u]`. That means `v`\'s subtree has **no alternative route** back to `u` or its ancestors.\n\n**Complexity:** `O(V + E)`.' },
  { id:'fc-cod-36', cat:'coding', module:'cod-arrays', lesson:'a-LC1', q:'Trapping Rain Water with two pointers: why is it safe to advance the lower side?', a:'**Approach:** Water at index `i` is `min(maxLeft, maxRight) - height[i]`. If `leftMax <= rightMax`, the left side is the binding constraint, so water at `L` is exactly `leftMax - height[L]` regardless of what lies between -- some bar `>= leftMax` exists on the right.\n\n**Therefore:** advance the lower pointer; the running max on that side can only grow, preserving the invariant.\n\n**Complexity:** `O(N)` time, `O(1)` space.' },
  { id:'fc-cod-37', cat:'coding', module:'cod-arrays', lesson:'a-LC2', q:'Sliding Window Maximum: what structure gives O(N)?', a:'**Approach:** A **monotonic deque** of indices with strictly decreasing corresponding values.\n\n- Before pushing index `i`, pop from the **back** while the back\'s value is `<= A[i]`\n- Pop from the **front** when its index falls out of the window (`< i - k + 1`)\n- The front always holds the current window\'s max\n\n**Complexity:** each index pushed and popped at most once, `O(N)` time, `O(k)` space.' },
  { id:'fc-cod-38', cat:'coding', module:'cod-arrays', lesson:'a-LC4', q:'Subarrays with Exactly K Distinct Integers: what\'s the inclusion-exclusion trick?', a:'**Approach:** Compute `atMost(K) - atMost(K - 1)`. Each `atMost` is a standard sliding-window count of subarrays whose distinct count stays `<= K`, which is **monotone** and windowable in `O(N)`.\n\n**Why not direct "exactly K":** the property "distinct count == K" is not monotone (adding chars can push you above or below), so no single window works.\n\n**Complexity:** `O(N)` total.' },
  { id:'fc-cod-39', cat:'coding', module:'cod-hashing', lesson:'h-LC1', q:'Minimum Window Substring: when do you shrink the window?', a:'**Approach:** Maintain a `need` count map and a `matched` counter equal to the number of distinct chars currently satisfied at their required count.\n\n- Expand `right`, incrementing `matched` when a char hits its required count\n- While `matched == required_distinct`, record the window and shrink `left`, decrementing `matched` only when a char drops **below** its need\n\n**Complexity:** `O(|s| + |t|)` time.' },
  { id:'fc-cod-40', cat:'coding', module:'cod-hashing', lesson:'h-LC3', q:'First Missing Positive in O(N) time and O(1) space: what\'s the core trick?', a:'**Approach:** Use the array itself as a hash. For each index, while `1 <= A[i] <= N` and `A[A[i] - 1] != A[i]`, swap `A[i]` to position `A[i] - 1`. Each swap places one value in its correct slot.\n\n**Then scan:** the first index where `A[i] != i + 1` gives the answer; if all match, return `N + 1`. Values outside `[1, N]` are ignored.\n\n**Complexity:** `O(N)` time, `O(1)` extra space.' },
  { id:'fc-cod-41', cat:'coding', module:'cod-intervals', lesson:'iv-3', q:'Meeting Rooms II (minimum rooms needed): how does the sweep-line approach work?', a:'**Approach:** Create `+1` events at start times and `-1` events at end times. Sort all events; on ties, **process ends before starts** (a room frees before being re-occupied). Sweep and track the running maximum of the prefix sum.\n\n**Equivalent heap version:** sort meetings by start; min-heap of end times; for each meeting, pop ends `<= start`, then push current end. Heap size = rooms.\n\n**Complexity:** `O(N log N)`.' },
  { id:'fc-cod-42', cat:'coding', module:'cod-intervals', lesson:'iv-4', q:'Non-overlapping intervals (max kept): why sort by end time, not start?', a:'**Greedy by earliest end** leaves the most room for what comes next. An exchange argument: any optimal schedule can be transformed (one swap at a time) into the earliest-end choice without losing intervals.\n\n**Why not sort by start:** a long interval with the earliest start can block many short ones that fit after a slightly later, shorter pick.\n\n**Complexity:** `O(N log N)` sort, `O(N)` sweep.' },
  { id:'fc-cod-43', cat:'coding', module:'cod-trees', lesson:'tr-2', q:'How do you find the Lowest Common Ancestor in a generic (non-BST) binary tree?', a:'**Approach:** Recurse left and right.\n\n- If both sides return non-null, the **current node is the LCA**\n- Otherwise, propagate up whichever side returned non-null\n- Base cases: `null` returns `null`; finding `p` or `q` returns that node\n\n**Complexity:** `O(N)` time, `O(H)` recursion stack. Works without parent pointers; for repeated queries, preprocess with Euler tour + RMQ for `O(1)` queries.' },
  { id:'fc-cod-44', cat:'coding', module:'cod-trees', lesson:'tr-4', q:'Validate BST: what is the most common bug, and how do you fix it?', a:'**Common bugs:**\n\n- Only comparing each node to its **direct children**, missing grandchildren violations (e.g., a `7` in the left subtree of `5`)\n- Using `<=` instead of `<` for a strict BST (or vice versa, depending on definition)\n- Forgetting `INT_MIN` / `INT_MAX` edge cases when nodes can hit those values\n\n**Fix:** pass `(lo, hi)` bounds down the recursion, or do an **in-order traversal** and verify the sequence strictly increases.' },
  { id:'fc-cod-45', cat:'coding', module:'cod-trees', lesson:'tr-6', q:'Binary Tree Maximum Path Sum: how do you split what to return versus what to track?', a:'**Approach:** At each node, recursively compute the best **one-armed extension** (`node.val + max(0, max(leftGain, rightGain))`). Update a global `best` with `node.val + leftGain + rightGain` -- the path that **bends** at this node.\n\n**Return only the one-armed value:** a parent can extend through this node but cannot use a path that already bent.\n\n**Complexity:** `O(N)` time, `O(H)` recursion.' },
  { id:'fc-cod-46', cat:'coding', module:'cod-trees', lesson:'t-LC2', q:'Reconstruct binary tree from preorder + inorder: what makes it O(N)?', a:'**Approach:** Preorder\'s first element is the root. Locate it in inorder to split left and right subtree ranges; recurse on each.\n\n**The trick:** pre-build a hash map `inorder_value -> index` so each root lookup is `O(1)`. Pass index ranges (not list slices) to avoid copying.\n\n**Complexity:** `O(N)` time, `O(N)` space. Without the hash map (linear scan each call), it degrades to `O(N^2)`.' },
  { id:'fc-cod-47', cat:'coding', module:'cod-dp', lesson:'dp-3', q:'0/1 Knapsack with 1D rolling array: why iterate capacity in reverse?', a:'**Reason:** Each item may be used **at most once**. Iterating capacity **descending** ensures `dp[c - w]` still reflects the previous row (item not yet considered), so the update doesn\'t double-use the item.\n\n**Ascending iteration** lets `dp[c - w]` already include the current item, which is the **unbounded knapsack** form (unlimited copies per item).\n\n**Complexity:** `O(N * W)` time, `O(W)` space.' },
  { id:'fc-cod-48', cat:'coding', module:'cod-dp', lesson:'dp-LC1', q:'Burst Balloons: what\'s the DP state, and why "last to burst"?', a:'**State:** `dp[l][r]` = max coins obtainable by bursting every balloon strictly between sentinels at positions `l` and `r`.\n\n**Transition:** pick which balloon `i` in `(l, r)` is the **last** to burst:\n\n`dp[l][r] = max over i of (nums[l] * nums[i] * nums[r] + dp[l][i] + dp[i][r])`\n\n**Why last-to-burst:** it pins balloon `i`\'s neighbors to `l` and `r`, decoupling the two subproblems. "First to burst" leaves the neighbors of subproblems entangled.\n\n**Complexity:** `O(N^3)` time, `O(N^2)` space.' },
  { id:'fc-cod-49', cat:'coding', module:'cod-misc', lesson:'m-3', q:'How do you recognize that a problem needs dynamic programming?', a:'**Trigger conditions:**\n\n- **Overlapping subproblems:** naive recursion revisits the same `(state)` many times\n- **Optimal substructure:** the optimal solution decomposes into optimal sub-solutions\n- Answer is a min/max/count over a sequence of choices with bounded state\n\n**If subproblems don\'t repeat,** it\'s plain **divide-and-conquer**. If a local greedy choice provably leads to global optimum, it\'s **greedy**, not DP.' },
  { id:'fc-cod-50', cat:'coding', module:'cod-misc', lesson:'m-3', q:'What is the most common dynamic-programming bug?', a:'**Common bugs:**\n\n- **Off-by-one in base case or transition indexing** -- especially confusing "`i` means first `i` chars" vs "first `i + 1` chars." Pick one convention and let base cases follow it.\n- **Forgetting to memoize a parameter that varies between calls** (e.g., remaining budget), turning `dp` into a function of the wrong subset of state\n- Mutating shared state (lists, dicts) inside the recursion\n- Wrong iteration order in 1D rolling DP (knapsack-style)' },
  { id:'fc-cod-51', cat:'coding', module:'cod-strings', lesson:'sm-1', q:'KMP string matching: what does the failure function store, and how does it speed up matching?', a:'**Failure function:** `f[i]` = length of the longest **proper prefix** of `pattern[0..i]` that is also a **suffix** of `pattern[0..i]`.\n\n**On mismatch** at text position while at pattern position `i`: jump pattern back to `f[i - 1]` instead of restarting. The text pointer never moves backward.\n\n**Complexity:** `O(M)` to build the failure table, `O(N)` to match. Total `O(M + N)` time, `O(M)` space.' },
  { id:'fc-cod-52', cat:'coding', module:'cod-strings', lesson:'sm-2', q:'Rabin-Karp: what makes the hash "rolling," and why does that matter?', a:'**Approach:** Treat each window as a base-`B` number mod prime `p`. Sliding right by one char:\n\n`new_hash = ((old_hash - leftChar * B^(L-1)) * B + rightChar) mod p`\n\nThis is `O(1)` per slide instead of `O(L)` for recomputing from scratch.\n\n**Verify on hash hit:** compare strings directly to dodge collisions, or use a double hash.\n\n**Complexity:** `O(N + M)` expected, `O(N * M)` worst case.' },
  { id:'fc-cod-53', cat:'coding', module:'cod-strings', lesson:'str-LC4', q:'Longest Duplicate Substring: which two patterns combine to solve it?', a:'**Approach:** Binary-search on the answer length `L`, plus rolling hash to test "does any substring of length `L` repeat?" in `O(N)` per check via a hash set.\n\n- Predicate is monotone: if length `L` has a duplicate, so does every length `<= L`\n- Each predicate call is `O(N)` rolling hash\n\n**Complexity:** `O(N log N)` expected. Handle collisions with a double hash or by verifying matches directly.' },
  { id:'fc-cod-54', cat:'coding', module:'cod-linked', lesson:'ll-3', q:'Floyd\'s tortoise-and-hare: how do you find the cycle start in a linked list?', a:'**Phase 1:** advance `slow` by `1` and `fast` by `2` until they meet inside the cycle (or `fast` hits null = no cycle).\n\n**Phase 2:** reset one pointer to the head; advance both one step at a time. They meet at the **cycle entry**.\n\n**Proof sketch:** let `a` = head-to-entry distance, `b` = entry-to-meeting distance, `c` = rest of cycle. Then `2(a + b) = a + b + k(b + c)`, which gives `a = (k - 1)(b + c) + c`. So the head-walker and the meeting-walker land together at the entry.\n\n**Complexity:** `O(N)` time, `O(1)` space.' },
  { id:'fc-cod-55', cat:'coding', module:'cod-linked', lesson:'ll-LC1', q:'Reverse Nodes in K-Group: what\'s the structural trick?', a:'**Approach:** Walk `k` nodes ahead first to **verify a full group exists**. If not, leave the tail untouched. Otherwise, reverse those `k` in place, then splice the previous group\'s tail to the new head and the new tail to whatever came after the group.\n\n- Use a sentinel `dummy` node to handle the first group uniformly\n- Iterate, don\'t recurse, to keep space `O(1)`\n\n**Complexity:** `O(N)` time, `O(1)` space (iterative).' },
  { id:'fc-cod-56', cat:'coding', module:'cod-linked', lesson:'ll-LC3', q:'LFU Cache: which data structures give O(1) get and put?', a:'**Approach:** Three structures working together:\n\n- Hash `key -> node` for `O(1)` lookup\n- Hash `freq -> doubly linked list of nodes at that frequency` ordered by recency\n- An integer `min_freq` pointer\n\n**On access:** detach the node from its current freq\'s list and append it to the `(freq + 1)` list. If the old list is now empty and was at `min_freq`, bump `min_freq`.\n\n**Eviction:** remove the tail of the `min_freq` list. Each op `O(1)`.' },
  { id:'fc-cod-57', cat:'coding', module:'cod-backtrack', lesson:'bt-LC3', q:'Word Search II: why does a trie beat running per-word DFS?', a:'**Approach:** Insert all words into a **trie**. Run **one DFS per board cell**, walking the trie alongside the path; immediately stop a branch when no trie child matches the current letter.\n\n**Why it\'s faster:**\n\n- Shared prefixes are explored **once** instead of per word\n- Pruning happens at every step, not just at word end\n\n**Complexity:** roughly `O(cells * 4^L)` vs `O(W * cells * 4^L)` for naive per-word DFS, where `L` is max word length.' },
  { id:'fc-cod-58', cat:'coding', module:'cod-stack', lesson:'st-LC2', q:'Sum of Subarray Minimums: what\'s the monotonic-stack counting trick?', a:'**Approach:** For each index `i`, find `PLE` (previous less element index) and `NLE` (next less element index) using a monotonic stack.\n\n**Contribution of `A[i]`** as the min of subarrays = `A[i] * (i - PLE) * (NLE - i)`.\n\n**Key detail:** make one side **strict** and the other **non-strict** when there are ties (e.g., PLE strict, NLE non-strict). This avoids double-counting subarrays whose minimum appears more than once.\n\n**Complexity:** `O(N)` time.' },
  { id:'fc-cod-59', cat:'coding', module:'cod-select', lesson:'sel-LC3', q:'Kth smallest in a row+column sorted matrix: binary search on what?', a:'**Approach:** Binary-search on the **value**, not on indices. For a candidate `v`, count cells `<= v` in `O(N)` using the **staircase walk** from the bottom-left corner: move up when current cell `> v`, right otherwise.\n\n- If count `< K`, raise `lo`\n- If count `>= K`, lower `hi`\n\n**Complexity:** `O(N log(maxVal - minVal))`. Heap-based alternative is `O(K log N)` but loses on large `K`.' },
  { id:'fc-cod-60', cat:'coding', module:'cod-greedy', lesson:'gr-LC3', q:'Minimum Refueling Stops: how does the "borrow from the past" heap-greedy work?', a:'**Approach:** Drive forward without stopping, but **drop each reachable station\'s fuel into a max-heap** as you pass it. When you run out of fuel before the next station (or before the target), **pop the largest remembered tank** and add it to your fuel -- that\'s one stop.\n\n**Repeat** until you reach the target or the heap is empty (impossible).\n\n**Why it\'s optimal:** any optimal strategy can be exchanged into one that always takes the largest available past tank when forced to refuel.\n\n**Complexity:** `O(N log N)` time, `O(N)` space.' },
  { id:'fc-sql-21', cat:'data', module:'data-sql', lesson:'sq-1', q:'How do `ROW_NUMBER()`, `RANK()`, and `DENSE_RANK()` differ on a tie?', a:'Two rows tied at position 2 produce different sequences:\n\n- **`ROW_NUMBER()`** -- `1, 2, 3, 4` -- arbitrary tiebreak, always unique\n- **`RANK()`** -- `1, 2, 2, 4` -- ties share the rank, skips the next number\n- **`DENSE_RANK()`** -- `1, 2, 2, 3` -- ties share the rank, no gap\n\n**Pick:** `ROW_NUMBER` for top-N (one winner per group), `DENSE_RANK` when ties should all qualify.' },
  { id:'fc-sql-22', cat:'data', module:'data-sql', lesson:'sq-1', q:'What does the SQL `NTILE(4)` window function do?', a:'Divides an ordered partition into roughly equal buckets and labels each row.\n\n- **`NTILE(4)`** -- quartiles, label 1 to 4\n- **`NTILE(10)`** -- deciles\n- **`NTILE(100)`** -- percentile bands\n\n**Example:** `NTILE(4) OVER (ORDER BY revenue) AS quartile`\n\n**Use case:** customer segmentation, percentile rankings, A/B test bucketing.' },
  { id:'fc-sql-23', cat:'data', module:'data-sql', lesson:'sq-1', q:'What is the difference between `ROWS` and `RANGE` in a SQL window frame?', a:'- **`ROWS BETWEEN N PRECEDING AND CURRENT ROW`** -- counts physical rows in the partition\n- **`RANGE BETWEEN N PRECEDING AND CURRENT ROW`** -- counts logical values of the `ORDER BY` column; ties are grouped\n\n**Gotcha:** the default frame when you omit it is `RANGE UNBOUNDED PRECEDING TO CURRENT ROW`. On duplicate timestamps this lumps tied rows together -- a subtle bug source.\n\n**Rule of thumb:** if you want exactly N rows, always say `ROWS` explicitly.' },
  { id:'fc-sql-24', cat:'data', module:'data-sql', lesson:'sq-2', q:'What SQL pattern deduplicates rows while keeping the latest version per key?', a:'1. Assign a row number per natural key, ordered by recency\n2. Keep `rn = 1` in an outer query or CTE\n\n**Example:** `SELECT * FROM (SELECT *, ROW_NUMBER() OVER (PARTITION BY natural_key ORDER BY updated_at DESC) AS rn FROM events) x WHERE rn = 1`\n\n**Use case:** CDC stream landing tables, replayed Kafka events, late-arriving updates.' },
  { id:'fc-sql-25', cat:'data', module:'data-pipe', lesson:'pp-3', q:'How do you write an antijoin in SQL -- rows in `A` with no match in `B`?', a:'Two safe patterns:\n\n- **`LEFT JOIN` + `IS NULL`** -- `SELECT a.* FROM a LEFT JOIN b ON a.id = b.a_id WHERE b.a_id IS NULL`\n- **`NOT EXISTS`** -- `SELECT a.* FROM a WHERE NOT EXISTS (SELECT 1 FROM b WHERE b.a_id = a.id)`\n\n**Avoid `NOT IN`:** breaks the moment `B` contains any `NULL` -- predicate becomes unknown and returns zero rows.\n\n**Default:** `NOT EXISTS`.' },
  { id:'fc-sql-26', cat:'data', module:'data-pipe', lesson:'pp-3', q:'Why does a `LEFT JOIN` sometimes inflate the row count, and how do you fix it?', a:'The right table has multiple matching rows per left key, so each left row fans out into a Cartesian-style multiplication.\n\n**Fixes:**\n- Pre-aggregate the right side in a CTE before joining\n- Join on a column that is unique in the right table\n- `DISTINCT ON (key)` in Postgres to keep one match\n- Window-then-filter: `ROW_NUMBER()` + `WHERE rn = 1`\n\n**Diagnose:** check the count of the right table grouped by the join key.' },
  { id:'fc-sql-27', cat:'data', module:'data-pipe', lesson:'pp-3', q:'When should you use a CTE vs a subquery vs a temp table?', a:'- **Subquery / CTE** -- inline; the planner usually fuses them into the outer plan (Postgres 12+ inlines non-recursive CTEs)\n- **Temp table** -- materialized; statistics are collected; reused across multiple queries in the session\n- **Materialized CTE** -- force materialization via `WITH ... AS MATERIALIZED` when the same expensive intermediate is referenced multiple times\n\n**Pick temp table when:** the intermediate is large, expensive, and reused.' },
  { id:'fc-sql-28', cat:'data', module:'data-pipe', lesson:'pp-4', q:'When do you pick B-tree, hash, GIN, or BRIN indexes in Postgres?', a:'- **B-tree** -- equality and range queries; the default choice\n- **Hash** -- equality only; rarely beats B-tree, mostly legacy\n- **GIN** -- multi-value columns: arrays, `jsonb`, full-text search via `tsvector`\n- **BRIN** -- huge tables where rows are physically ordered (time-series, append-only logs); tiny on disk\n\n**Rule:** start with B-tree; reach for GIN/BRIN when the data shape demands it.' },
  { id:'fc-sql-29', cat:'data', module:'data-pipe', lesson:'pp-4', q:'What is index selectivity and why does it matter for query performance?', a:'**Selectivity** = distinct values / total rows.\n\n- **High selectivity** (e.g. `user_id`, `email`) -- index is effective, planner uses it\n- **Low selectivity** (e.g. `is_active` boolean, `country` with 5 values) -- index is mostly useless; planner correctly picks a sequential scan\n\n**Fix for low selectivity:** partial indexes (`WHERE is_active = true`) or covering indexes that include the hot columns.' },
  { id:'fc-sql-30', cat:'data', module:'data-pipe', lesson:'pp-4', q:'What is the difference between `EXPLAIN` and `EXPLAIN ANALYZE` in Postgres?', a:'- **`EXPLAIN`** -- shows the planner\'s estimated plan and cost without running the query\n- **`EXPLAIN ANALYZE`** -- actually executes the query and prints real row counts and timings per node\n- **`EXPLAIN (ANALYZE, BUFFERS)`** -- adds shared/local buffer hits and reads -- the I/O signal\n\n**Why it matters:** estimate-vs-actual skew is the usual root cause of bad plans. Only `ANALYZE` exposes it.' },
  { id:'fc-sql-31', cat:'data', module:'data-pipe', lesson:'pp-3', q:'What is the N+1 query problem and how do you fix it?', a:'**Bug:** code fetches a list of N parent rows, then issues one child query per parent -- `N + 1` round trips total.\n\n**Example:** loading 100 users, then 100 separate queries for each user\'s orders.\n\n**Fixes:**\n- A single `JOIN` returning parents and children\n- One batch `WHERE child.parent_id IN (...)` query\n- ORM eager loading: SQLAlchemy `selectinload`, Django `prefetch_related`, ActiveRecord `includes`' },
  { id:'fc-sql-32', cat:'data', module:'data-sql', lesson:'sq-1', q:'What is the difference between `WHERE`, `GROUP BY`, and `HAVING`?', a:'Execution order:\n\n1. **`WHERE`** -- filter individual rows before grouping\n2. **`GROUP BY`** -- collapse rows by key\n3. **`HAVING`** -- filter aggregated groups after grouping\n\n**Gotcha:** you cannot reference an aggregate (`SUM`, `COUNT`) in `WHERE` -- only in `HAVING`.\n\n**Example:** `SELECT city, COUNT(*) FROM users WHERE active = true GROUP BY city HAVING COUNT(*) > 10`' },
  { id:'fc-sql-33', cat:'data', module:'data-sql', lesson:'sq-1', q:'What is the difference between `ROLLUP`, `CUBE`, and `GROUPING SETS`?', a:'All emit multiple grouping levels in a single pass instead of `UNION ALL`.\n\n- **`ROLLUP (a, b, c)`** -- hierarchical subtotals: `(a,b,c)`, `(a,b)`, `(a)`, `()` -- ends at grand total\n- **`CUBE (a, b, c)`** -- every subset, `2^n` combinations\n- **`GROUPING SETS ((a,b),(a,c),())`** -- explicit list of grouping combos\n\n**Use case:** reporting dashboards that need subtotals + totals together.' },
  { id:'fc-sql-34', cat:'data', module:'data-sql', lesson:'sq-5', q:'Why is columnar storage so much faster than row storage for analytics queries?', a:'- Each column is stored contiguously on disk\n- `SELECT SUM(amount) FROM big_table` reads only the `amount` column\'s pages -- not the whole row\n- Adjacent values compress well (RLE, dictionary, delta encoding)\n- Vectorized execution processes column chunks in CPU SIMD instructions\n\n**Row stores** must read every column of every row -- huge I/O waste on wide tables for analytic scans.' },
  { id:'fc-sql-35', cat:'data', module:'data-warehouse', lesson:'wh-1', q:'What is the difference between partitioning and sharding a database?', a:'**Partitioning**\n- One database splits a table into segments by key (date, hash, range)\n- Same node, same instance\n- Enables prune-on-scan -- planner skips irrelevant partitions\n\n**Sharding**\n- Data split across multiple nodes / databases\n- Horizontal scale across machines\n- Requires routing logic and cross-shard query handling\n\n**Rule:** partition first; shard only when one node can\'t hold the data or handle the write rate.' },
  { id:'fc-sql-36', cat:'data', module:'data-pipe', lesson:'pp-6', q:'What is the transactional outbox pattern, and what problem does it solve?', a:'**Problem:** dual-write race -- updating the DB and publishing to Kafka in two steps risks one succeeding and the other failing.\n\n**Pattern:**\n1. In the same DB transaction, write the business row **and** an `outbox` row\n2. A separate relay process tails the outbox table (or via CDC on it)\n3. Relay publishes to Kafka and marks the outbox row sent\n\n**Guarantee:** the event ships if and only if the transaction committed -- no dual-write race.' },
  { id:'fc-sql-37', cat:'data', module:'data-warehouse', lesson:'wh-2', q:'What is the difference between Lambda and Kappa architectures for real-time analytics?', a:'**Lambda**\n- Parallel batch layer (Spark/Hive) and speed/streaming layer (Flink/Kafka Streams)\n- Results merged at query time\n- Logic must be implemented twice -- maintenance burden\n\n**Kappa**\n- Single streaming pipeline\n- Reprocess history by replaying the log from offset 0\n- One codebase\n\n**Modern stacks** (Flink, Materialize, RisingWave) favor Kappa.' },
  { id:'fc-sql-38', cat:'data', module:'data-pipe', lesson:'pp-1', q:'What is the standard dbt model layering convention?', a:'1. **`staging`** -- one model per source table; cleanup, renames, type casts only (1:1)\n2. **`intermediate`** -- joins, business logic, reusable derived models\n3. **`marts`** -- fact and dim tables consumed by BI and downstream apps\n\n**Conventions:**\n- Tests and docs live alongside models in YAML\n- `ref()` between models builds the DAG\n- `sources` define external tables and their freshness SLAs' },
  { id:'fc-sql-39', cat:'data', module:'data-pipe', lesson:'pp-5', q:'What is the difference between SCD Type 1, Type 2, and Type 4?', a:'- **Type 1** -- overwrite the row in place; no history retained. Use when only the current value matters\n- **Type 2** -- insert a new row per change with `valid_from` / `valid_to`; full history. **Default for analytics**\n- **Type 4** -- keep the current row in the main table and push prior versions to a separate history table\n\n**Pick Type 2** unless storage cost or query simplicity dominates -- most analytics needs history.' },
  { id:'fc-sql-40', cat:'data', module:'data-warehouse', lesson:'wh-1', q:'What is the 2026 tradeoff between Snowflake, BigQuery, and Redshift?', a:'**Snowflake**\n- Separated storage and compute, per-warehouse scaling\n- Multi-cloud, strong governance and sharing\n\n**BigQuery**\n- Serverless, slot-based pricing\n- Deepest GCP and ML integration (`BigQuery ML`, Vertex)\n\n**Redshift**\n- AWS-native; `RA3` instances separate storage from compute\n- Cheapest at steady high utilization, but more tuning (sort/dist keys)\n\n**Default greenfield pick:** Snowflake or BigQuery depending on cloud.' },
  { id:'fc-dec-14', cat:'decomp', module:'decomp-101', lesson:'d-2', q:'In a 60-min Palantir-style decomp round, what is the approximate time budget per phase?', a:'- **Clarify** - 10-15 min (success metric, users, constraints, data)\n- **Stakeholder map** - 3 min\n- **Data sources** - 5 min\n- **Tradeoffs** - 10 min (two phased options, recommendation)\n- **Failure modes** - 5 min (3 specific failures with detection + rollback)\n- **Buffer** - 10-15 min for whiteboard, interviewer questions, dead ends\n\nThe **shape** matters more than the exact minutes: clarify and tradeoffs should dominate.' },
  { id:'fc-dec-15', cat:'decomp', module:'decomp-101', lesson:'d-4', q:'What are the three properties of a \'good\' clarifying question in a decomp round?', a:'1. **Specific** - names a concrete dimension (latency, user role, frequency, data volume)\n2. **Falsifiable** - has a yes/no or A/B answer the interviewer can give in one sentence\n3. **Design-relevant** - the answer changes what you would build next\n\n**Antipattern:** vague openers like \'what does success look like?\' or \'tell me more about the users\' fail all three - they invite a monologue without branching your design.' },
  { id:'fc-dec-16', cat:'decomp', module:'decomp-101', lesson:'d-5', q:'In a decomp round, what is the \'I don\'t know - you decide\' trap and the correct response?', a:'**Trap:** bouncing ambiguity back to the interviewer (\'what would you prefer?\', \'what does the team usually do?\') signals you cannot operate without a spec.\n\n**Correct response:**\n- State an explicit assumption out loud\n- Write it on the whiteboard so it is visible and correctable\n- Proceed as if it is true, then invite pushback\n\nExample: `I will assume daily batch ingestion; flag me if you want real-time.` The assumption is now a debuggable artifact, not a stalled conversation.' },
  { id:'fc-dec-17', cat:'decomp', module:'decomp-101', lesson:'d-1', q:'In a Palantir-style decomp round, what is the interviewer actually grading?', a:'**They are grading HOW you think under ambiguity, not whether you pick the \'right\' architecture.**\n\nPositive signals:\n- Clarify before solving\n- Name stakeholders beyond just end users\n- Surface tradeoffs with explicit alternatives\n- Anticipate failure modes with detection and rollback\n- State assumptions out loud\n\nKnowing the trendy tool (`LangChain`, `pgvector`, the model du jour) is irrelevant if you skipped the problem space. Process beats stack.' },
  { id:'fc-dec-18', cat:'decomp', module:'decomp-101', lesson:'d-5', q:'What are the junior vs senior signal patterns in a Palantir-style decomp round?', a:'**Junior:**\n- Names tools first (`Kafka`, `Postgres`, OpenAI API) within 60 seconds\n- Proposes one solution, no alternatives\n- Treats the prompt as a complete spec\n- \'Add monitoring\' as the only failure-mode answer\n\n**Senior:**\n- Scopes users, success metric, and constraints before drawing\n- Presents two phased options with explicit tradeoffs\n- Names 3 specific failure modes with detection + rollback\n- States assumptions out loud and invites pushback' },
  { id:'fc-dec-19', cat:'decomp', module:'decomp-101', lesson:'d-1', q:'Where did the decomposition interview format originate and where is it used today?', a:'- **Origin:** pioneered by **Palantir** for Forward Deployed Engineer (FDE) hiring, where engineers had to scope messy real-world problems with customers in the loop\n- **Today:** standard at **OpenAI**, **Anthropic**, and **Scale AI** for applied and research-engineering roles\n- **Shared bet:** messy real-world problems reveal judgment that LeetCode cannot - candidates who can scope, tradeoff, and anticipate failure beat candidates who only optimize algorithms' },
  { id:'fc-dec-20', cat:'decomp', module:'decomp-101', lesson:'d-3', q:'In a decomp round, when should you draw architecture on the whiteboard vs stay verbal?', a:'- **Stay verbal** during clarify and stakeholder mapping - drawing too early locks in a shape\n- **Draw** `Inputs -> Logic -> Outputs` once you have a scoped problem and an assumption-set the interviewer has not pushed back on\n- The diagram then anchors the **tradeoff** discussion: \'in Option A this box is batch, in Option B it is streaming\'\n\n**Antipattern:** drawing in minute 2. You commit to a shape before you know the requirements and spend the rest of the round defending it.' },
  { id:'fc-dec-21', cat:'decomp', module:'decomp-101', lesson:'d-5', q:'What are three common decomposition antipatterns that signal a coder, not an engineer?', a:'- **Tech-stack-first** - \'I would use `Spark` and `Snowflake`...\' before scoping users or success metric\n- **Tool-as-solution** - \'use an LLM\' without specifying inputs, outputs, or what the model decides\n- **Single-solution presentation** - one option, no alternative, no tradeoff named\n\nAll three skip the problem space and jump to implementation. The interviewer reads it as: this person can write code but cannot scope a project.' },
  { id:'fc-dec-22', cat:'decomp', module:'decomp-101', lesson:'d-8', q:'In a decomp round, how do you handle a silent interviewer who is not nodding or asking follow-ups?', a:'**Pattern:** treat silence as \'show me more of your reasoning\', not disapproval.\n\n- Keep thinking out loud\n- Check in with a forward-moving statement, not a question\n\nExample: `I am going to assume X and move to data sources - stop me if you want me to dig deeper here.`\n\n- Silence is rarely disapproval; it is usually the interviewer taking notes or waiting to see if you self-correct\n- Stalling out or asking \'is this right?\' converts silence into a negative signal' },
  { id:'fc-dec-23', cat:'decomp', module:'decomp-101', lesson:'d-2', q:'Why should you sequence MVP-first in a decomp answer rather than leading with the fully-featured system?', a:'**Pattern:** pitch the simplest version that delivers value first, then layer enhancements.\n\nWhat each move signals:\n- **MVP first** - you can ship under constraints and have internalized cost\n- **Enhancements layered after** - you understand the roadmap and can sequence work\n- **Fully-featured system first** - you cannot prioritize, you over-engineer, you have not thought about cost or time to value\n\nThe MVP is not the answer - it is the **anchor** that lets you discuss tradeoffs around it.' },
  { id:'fc-dec-24', cat:'decomp', module:'decomp-101', lesson:'d-7', q:'Logistics prompt: design a rerouting AI agent for a delivery fleet. What are three failure modes worth naming, each with detection and rollback?', a:'1. **GPS dropout** in tunnels or rural zones - detect with stale-timestamp checks on the location feed; fall back to last known route and notify driver\n2. **Model bias toward training-distribution cities** - monitor reroute success rate by region; if a new city underperforms, route traffic to the rule-based fallback and retrain\n3. **Cascading reroutes during incidents** (one accident triggers a storm of reroutes) - rate-limit per-driver reroutes and require human dispatcher approval above a threshold' },
  { id:'fc-dec-25', cat:'decomp', module:'decomp-101', lesson:'d-2', q:'In a decomp round, how do you frame failure modes for low-base-rate events (fraud, medical alerts, 911 high-priority calls)?', a:'**Pattern:** lead with **false-positive cost**, not raw accuracy.\n\n- At a 0.1% base rate, a 99% accurate model still drowns reviewers in false alarms (alert fatigue is the real failure)\n- Name the **precision target** explicitly, not just recall\n- Specify the **human-in-the-loop** step that gates action\n- Specify the **detect-and-rollback** mechanism for model drift (precision drops below threshold -> page on-call, route to manual review)\n\nAccuracy is a junior answer; precision under base-rate is the senior frame.' },
  { id:'fc-dec-26', cat:'decomp', module:'decomp-101', lesson:'d-2', q:'In a decomp round, what does a stakeholder map add beyond just listing users?', a:'**Users** are who interacts with the system. **Stakeholders** are a strictly larger set:\n- Who **pays** for the system (budget owner)\n- Who is **regulated** by it (compliance, legal)\n- Who is **affected** but does not log in (the 911 caller, the patient, the driver being rerouted)\n- Who can **kill the project** (executive sponsor, head of safety)\n- Who is **on-call** when it breaks\n\nNaming the procurement lead, compliance officer, and on-call engineer scopes the problem in ways a pure user-story view misses.' },
  { id:'fc-dom-11', cat:'domain', module:'dom-mkt', lesson:'dm-3', q:'When designing US money-movement, when do you pick ACH vs RTP/FedNow vs wire?', a:'**ACH**\n- Cost: **cents** per transfer; settles in **1-3 business days** (batch)\n- **Reversible** within ~60 days\n- Best for **payroll, recurring debits, B2C disbursements**\n\n**RTP / FedNow**\n- **Instant** (seconds), **24/7/365**, **irrevocable**\n- Capped (currently **$1M** on RTP)\n- Best for **payouts, just-in-time funding, instant refunds**\n\n**Wire (Fedwire, CHIPS)**\n- **Same-day**, irrevocable, **$15-30** fee\n- Best for **high-value B2B, real estate, treasury**\n\n**Implication:** speed and irreversibility are the levers; cheaper rails trade settlement time for cost.' },
  { id:'fc-dom-12', cat:'domain', module:'dom-mkt', lesson:'dm-3', q:'What\'s the cheapest practical way to stay PCI-DSS compliant when accepting card payments?', a:'**Never let raw PAN (the card number) touch your servers.** Scope is everything in PCI: the less you touch, the easier the audit.\n\n- Use a **tokenization vendor** (Stripe Elements, Spreedly, Basis Theory) via **iframe or hosted SDK**\n- Your servers see only an opaque token, never the PAN or CVV\n- This qualifies you for **SAQ-A**, the lightest self-assessment (essentially a checklist)\n- Touching PAN in plaintext pushes you into **SAQ-D** + full QSA audit + quarterly scans\n\n**Implication:** architecture choice on day one determines whether compliance costs $0 or $100K+/year.' },
  { id:'fc-dom-13', cat:'domain', module:'dom-mkt', lesson:'dm-3', q:'In fintech onboarding, what\'s the practical difference between KYC and KYB?', a:'**KYC (Know Your Customer)**\n- Verifies an **individual**\n- Inputs: government ID, selfie liveness, SSN, address\n- Screens: OFAC/sanctions, PEP, adverse media\n- Mostly **automated** (Persona, Alloy, Socure); minutes to verify\n\n**KYB (Know Your Business)**\n- Verifies a **business entity**\n- Inputs: EIN, formation docs, operating agreement\n- Requires **UBO** (ultimate beneficial owners, >25% ownership) discovery, then KYC on each UBO\n- Heavily **manual review**, document chasing; days to weeks\n\n**Implication:** KYB is the bottleneck for B2B fintech onboarding; budget for ops headcount, not just software.' },
  { id:'fc-dom-14', cat:'domain', module:'dom-dev', lesson:'dh-4', q:'For new healthcare integrations in 2026, when do you use FHIR vs HL7 v2?', a:'**FHIR (Fast Healthcare Interoperability Resources)**\n- **REST / JSON**, resource-oriented (`Patient`, `Observation`, `MedicationRequest`)\n- Modern standard; **mandated for US patient-access APIs** under ONC/CMS rules\n- Used for **greenfield apps**, patient portals, third-party integrations\n\n**HL7 v2**\n- Pipe-delimited messages over **MLLP/TCP**\n- Still **dominant inside hospital walls** for ADT (admit/discharge/transfer), orders, lab results\n- Required when integrating with legacy EHRs (Epic, Cerner via interface engines)\n\n**Implication:** real production systems speak **both**: FHIR at the edge, HL7 v2 internally via a Mirth/Rhapsody engine.' },
  { id:'fc-dom-15', cat:'domain', module:'dom-dev', lesson:'dd-1', q:'Why is **DAU/MAU** a misleading north-star metric for developer tools, and what should you use instead?', a:'Developer tools are **workflow tools, not consumer apps**. A developer using your CLI three days a week is highly engaged, but DAU/MAU would score them at 0.43 and look bad.\n\nBetter north stars:\n- **Integration depth:** commands run per active dev, languages/repos covered, % of workflow replaced\n- **Retained weekly active devs (WAU)** with cohort retention, not raw daily\n- **Time-to-first-value (TTFV):** signup -> first successful API call / build / deploy\n- **Paid seat expansion** within an org (the real PLG growth loop)\n\n**Implication:** optimizing for DAU pushes you toward notifications and engagement bait, which devs hate.' },
  { id:'fc-dom-16', cat:'domain', module:'dom-ai', lesson:'dai-1', q:'What is "eval gating" at AI-first companies (Anthropic, OpenAI, Deepgram) and why is it considered table-stakes?', a:'**Eval gating** means treating evaluations as **CI for prompts and models**. Every change must pass a frozen golden-set with regression thresholds before merge.\n\n- **Frozen golden-set** of input/output pairs; thresholds per metric (accuracy, latency, safety)\n- **Prompt versioning:** prompts are code, stored in git, addressable by hash\n- **Shadow traffic** in prod: new prompt/model runs alongside old, deltas logged before cutover\n- **Per-PR eval runs** + dashboards in code review\n\n**Implication:** without eval gating, every prompt edit silently regresses quality and you only find out from customer complaints.' },
  { id:'fc-dom-17', cat:'domain', module:'dom-ai', lesson:'dai-2', q:'Why do production AI apps need a model router, and how much does it actually save?', a:'**Mechanism:** different requests have different cost/latency/quality needs. A router classifies the request (intent, length, sensitivity) and dispatches to the **cheapest model that meets the SLO**.\n\n- **Haiku / small models:** classification, extraction, routing decisions\n- **Sonnet / mid models:** chat, summarization, most agent steps\n- **Opus / frontier:** hard reasoning, long-horizon planning, code review\n- Routing signal can be heuristic (token count, regex) or a tiny classifier\n\n**Implication:** cuts inference cost **5-10x** versus always-Opus with negligible quality loss, and gives you a graceful **fallback ladder** when a provider degrades.' },
  { id:'fc-dom-18', cat:'domain', module:'dom-hosp', lesson:'dh-1', q:'In hospitality, why does **RevPAR** beat raw occupancy as a north-star metric?', a:'**RevPAR (revenue per available room) = ADR x occupancy**, so it captures the price-vs-fill tradeoff that single metrics miss.\n\n- **Occupancy alone** rewards **fire-sale discounting**: fill rooms at any price\n- **ADR alone** (average daily rate) rewards **empty rooms** at premium prices\n- **RevPAR** forces the yield-management tradeoff and is the **industry-standard** comp metric\n- Restaurants have an analog: **RevPASH** (revenue per available seat-hour)\n\n**Implication:** when you see hotels heavily discounting on OTAs, it\'s almost always a RevPAR play, not a desperate occupancy grab.' },
  { id:'fc-dom-19', cat:'domain', module:'dom-hosp', lesson:'dh-3', q:'Why is integrating with restaurant POS systems (Toast, Square, Aloha, Micros) harder than typical SaaS API integration?', a:'**Three structural problems** make restaurant POS integration painful even when an API exists.\n\n- **Inconsistent menu modeling:** modifiers, combos, voids, comps, and 86\'d items are represented differently in every POS\n- **Partial real-time APIs:** Toast and Square are reasonable; **Aloha and Micros often require polling or on-prem agents** because the POS is a Windows box in the back office\n- **Ticket-time semantics vary:** "fired," "served," "closed" mean different things per venue and per POS\n\n**Implication:** expect to write **per-POS adapters**, reconcile menu state **nightly**, and maintain a canonical menu model your app actually queries.' },
  { id:'fc-dom-20', cat:'domain', module:'dom-dev', lesson:'dd-2', q:'What core features must an enterprise LLM gateway (Credal, Portkey, internal builds) provide, and who is the buyer?', a:'**Mechanism:** the gateway sits between internal apps and LLM providers as a single chokepoint for security, cost, and observability.\n\n- **Centralized API keys** with **per-team budgets and rate limits**\n- **PII redaction on egress** before prompts hit external providers\n- **Prompt/response logging** for audit and incident response\n- **Model abstraction:** swap providers (OpenAI to Anthropic to Bedrock) without app changes\n- **SSO + RBAC** so access follows employee status\n\n**Implication:** the buyer is **security/IT, not developers**. The pitch is observability and a kill switch, and DX is secondary to control.' },
  { id:'fc-meta-16', cat:'meta', module:'meta-prep', lesson:'me-4', q:'What is the rough industry funnel from cold application to offer at the FDE / senior-IC level?', a:'**Plan volume backward from your target offer count.**\n\n- **100 cold applications** -> 10-15 recruiter screens\n- **10-15 recruiter screens** -> 4-6 onsites\n- **4-6 onsites** -> 1-2 offers\n\nReferrals roughly **5x the top-of-funnel conversion** (so 100 referred apps -> 5-7 offers).\n\nIf you want 2 offers in hand for leverage, you need ~200 cold apps OR ~40 referred apps in the pipeline. Plan accordingly.' },
  { id:'fc-meta-17', cat:'meta', module:'meta-prep', lesson:'me-4', q:'What is the right daily application volume during a full-time job search?', a:'**10-20 quality applications per day, front-loaded into Monday through Wednesday.**\n\n- **Below 5/day:** the pipeline starves; you cannot afford to be picky on offers\n- **10-20/day:** pipeline stays full, you can prioritize referrals + tailoring\n- **Above 30/day:** quality collapses, generic cover letters, you blacklist yourself with recruiters who recognize spam\n\n**Why Mon-Wed:** recruiters review queues early in the week; Friday apps sit until Monday.' },
  { id:'fc-meta-18', cat:'meta', module:'meta-prep', lesson:'me-4', q:'How much does a warm referral beat a cold application in recruiter-response rate?', a:'**Referrals see ~5-10x the response rate of cold apps and skip ATS keyword filters entirely.**\n\n- Cold app: lands in ATS, screened by keywords, often never seen by a human\n- Referral: hits recruiter inbox flagged with internal employee name, prioritized in queue\n\n**The rule:** spend 10 minutes finding a warm intro on LinkedIn before submitting cold. Even a 2nd-degree connection asking for a referral beats a cold submission.\n\nHighest ROI-per-minute activity in the entire search.' },
  { id:'fc-meta-19', cat:'meta', module:'meta-prep', lesson:'me-4', q:'In what order should you schedule your interview loops if you have a clear dream company?', a:'**Schedule dream companies LAST, never first.**\n\nReasoning:\n\n- **First-loop nerves** cost real performance; you need 2-3 lower-stakes loops as live reps\n- A **competing offer in hand** materially shifts how you negotiate at the dream company\n- Early loops surface weak round-types you can fix before the company you most want sees you\n- Recruiter timelines are usually flexible by 2-3 weeks if you ask\n\nApply to dream companies early; interview with them late.' },
  { id:'fc-meta-20', cat:'meta', module:'meta-prep', lesson:'me-3', q:'What is the minimum mock-interview cadence during active prep, and how should mocks be reviewed?', a:'**3 mocks per week minimum, with at least one recorded and reviewed at 1.5x speed.**\n\n- **Below 2/week:** live-performance skills decay; you regress between real loops\n- **3-5/week:** sweet spot, enough reps to fix issues mocks surface\n- **Above 5/week:** no time left to actually fix the issues you found\n\n**Review protocol:** watch the recording, write down 3 fixable issues, drill those specifically in the next mock.' },
  { id:'fc-meta-21', cat:'meta', module:'meta-prep', lesson:'me-3', q:'How should you allocate prep time across your strong and weak interview round-types?', a:'**Spend 60-70% of prep time on your single weakest round-type until it is no longer the bottleneck, then rotate.**\n\nWhy it works:\n\n- Loop outcome variance is set by your **worst round**, not your best\n- Even allocation across rounds (the default) leaves the bottleneck unmoved\n- Once the former weakest hits \'passable,\' the new weakest takes the 60-70% slot\n\n**Anti-pattern:** spending more time on what you enjoy (usually your strongest) because it feels productive.' },
  { id:'fc-meta-22', cat:'meta', module:'meta-prep', lesson:'me-1', q:'What time-block structure for daily prep survives a real full-time job plus an active search?', a:'**Two fixed daily blocks, anchored to the same clock time, every weekday:**\n\n- **Morning, 45-60 min, pre-work:** high-cognitive work (algorithms, system design drills)\n- **Evening, 30 min, post-dinner:** low-cognitive work (applications, flashcards, follow-ups)\n\n**Discipline rules:**\n\n- Calendar-blocked with a real event, not a vague intention\n- Phone in another room during the morning block\n- Same time every day so the trigger becomes automatic' },
  { id:'fc-meta-23', cat:'meta', module:'meta-prep', lesson:'me-1', q:'Why does interview prep collapse around week 4 for so many candidates, and how do you survive it?', a:'**Motivation decays predictably while novelty wears off and no offers have landed yet.** The dopamine of a new plan is gone; the dopamine of an offer has not arrived.\n\nCounter with **infrastructure, not willpower:**\n\n- Fixed time, fixed place, small daily target (1 problem + 10 flashcards)\n- Track **streak length**, not total hours\n- Pre-commit Monday\'s plan on Sunday so Monday-you does not decide\n- Lower the daily floor on bad days; never break the streak' },
  { id:'fc-meta-24', cat:'meta', module:'meta-prep', lesson:'me-5', q:'How do you use a competing offer as leverage during negotiation without bluffing or burning bridges?', a:'**Share the real competing offer\'s total-comp band and decision deadline. Never invent offers; recruiters talk and the industry is small.**\n\n- **You:** "I want to be transparent. I have an offer from [Co] at roughly $X total with a Friday deadline. I would genuinely prefer to join you. Can you help me close the gap on base / equity / sign-on?"\n- **You:** "What would be possible on your end before that deadline?"\n\n**Real leverage beats fake leverage 10/10 times.** Fake offers get discovered and end careers.' },
  { id:'fc-meta-25', cat:'meta', module:'meta-prep', lesson:'me-5', q:'What are the standard equity vesting terms, and what is actually negotiable at offer time?', a:'**Standard package:** 4-year vest, 1-year cliff, monthly vest thereafter.\n\n**Negotiable levers (most engineers never ask):**\n\n- **Cliff length:** push for 6-month or no cliff (especially if leaving vested equity behind)\n- **Sign-on bonus:** explicitly to bridge the cliff period\n- **Refresh-grant language:** in writing, not \'we usually refresh top performers\'\n- **Acceleration on acquisition:** single-trigger or double-trigger clauses\n- **Early-exercise / 83(b) eligibility:** matters for tax outcome on private co equity' },
  { id:'fc-meta-26', cat:'meta', module:'meta-prep', lesson:'me-5', q:'What are the things you should NEVER say or do during compensation negotiation?', a:'**Red flags that cost you money or leverage:**\n\n- **Never give the first number** (you anchor against yourself)\n- **Never disclose your current salary** unprompted (illegal to ask in many states; never volunteer)\n- **Never say "I just need $X to live on"** (frames negotiation around your costs, not your value)\n- **Never accept verbally on the call** (always: "Let me think it over and come back tomorrow")\n- **Never fill silence after they state a number** (silence is your strongest tool)\n- **Never threaten to walk** unless you actually will' },
  { id:'fc-meta-27', cat:'meta', module:'meta-prep', lesson:'me-7', q:'For a portfolio site, is it better to ship one deep case study or five medium-quality projects?', a:'**One deep case study beats five surface-level repos.** Hiring managers spend 2-3 minutes on a portfolio maximum.\n\n**Must-haves for the deep case study:**\n\n- **Problem framing:** what was the constraint, who was the user, why did it matter\n- **Tradeoffs:** what alternatives you considered and why you rejected them\n- **Metrics:** before/after numbers (latency, accuracy, cost, adoption)\n- **Code:** readable repo with a real README, not a dump\n- **Failure honesty:** what did not work and what you would do differently' },
  { id:'fc-meta-28', cat:'meta', module:'meta-prep', lesson:'me-7', q:'For FDE / senior-IC roles, does LinkedIn or your personal site matter more for getting recruiter attention?', a:'**Both, but they do different jobs.**\n\n- **LinkedIn:** drives **top-of-funnel discovery** via recruiter search + \'open to work\' beacon. 10x more inbound than a personal site for non-FAANG roles.\n- **Personal site:** **converts** after the recruiter clicks through; depth lives here\n\n**LinkedIn optimization priorities:**\n\n- **Headline:** role keywords + specialization (not just current title)\n- **First 2 lines of About:** these are what shows in search previews\n- **Open-to-work** flag set to recruiters-only if currently employed' },
  { id:'fc-meta-29', cat:'meta', module:'meta-prep', lesson:'me-8', q:'How do you handle a recruiter going silent after what felt like a strong onsite?', a:'**Two follow-ups maximum, then move on. Two unanswered pings means the answer is no.**\n\n**Cadence:**\n\n- **Day 5-7 business:** one short, neutral follow-up. "Checking in on next steps, still very interested in the team."\n- **Day 12-14 business:** one more, equally short. Reference one specific thing from the loop.\n- **Day 14+:** silence is the answer. Do not chain a third ping.\n\n**Re-route the energy into live pipelines.** Ghosting is information about them, not about you.' },
  { id:'fc-meta-30', cat:'meta', module:'meta-prep', lesson:'me-3', q:'What is the right format and timing for a post-interview thank-you email?', a:'**Within 24 hours, one email per interviewer, short and specific.**\n\n**Required ingredients in each note:**\n\n- **One concrete thing discussed** (not generic \'enjoyed the conversation\') to demonstrate recall\n- **One new thought you had after the call** (a follow-up idea on the design, a relevant link, a corrected detail)\n- **Short:** one paragraph, no padding\n- **Sent within 24h** while you are still fresh in their mind\n\nThank-yous are **signal, not formality**: they show recall, taste, and async-writing chops.' },
  { id:'fc-sd-26', cat:'sysd', module:'sd-classic', lesson:'sd-bo', q:'What back-of-envelope latency numbers should you have memorized for capacity planning?', a:'- **`L1` cache:** `~1 ns`\n- **Main memory:** `~100 ns`\n- **SSD random read:** `~100 us`\n- **Network RTT within a DC:** `~0.5 ms`\n- **Disk seek (HDD):** `~10 ms`\n- **Cross-region RTT:** `~50-150 ms`\n\nThese numbers tell you whether a design needs **caching** (DB too slow), **replication** (cross-region too slow), or **async** (anything user-facing must be sub-second).' },
  { id:'fc-sd-27', cat:'sysd', module:'sd-classic', lesson:'sd-bo', q:'How do you quickly estimate QPS for a system with 100M DAU and 10 requests per user per day?', a:'**Math:**\n- `100M * 10 = 1B requests/day`\n- `1B / 86400 sec ~= 11.5k QPS average`\n- Peak is typically **2-5x average** -> plan for `~30-60k QPS`\n\n**Rule:** capacity-plan to **peak, not average**, and add headroom (~30%) for retries and bursts.\n\nThis kind of estimate should take 30 seconds on the whiteboard.' },
  { id:'fc-sd-28', cat:'sysd', module:'sd-classic', lesson:'sd-3', q:'Token bucket vs leaky bucket: what\'s the difference and when do you pick each?', a:'**Token bucket**\n- Tokens accumulate up to a max\n- **Bursts allowed** up to bucket size\n- Common for API quotas (Stripe, AWS)\n\n**Leaky bucket**\n- Requests drain at a **fixed rate** from a queue\n- Bursts are **smoothed but queued** (adds latency)\n- Common for traffic shaping (network routers)\n\n**Rule:** token bucket lets clients burst; leaky bucket forces them to spread out.' },
  { id:'fc-sd-29', cat:'sysd', module:'sd-classic', lesson:'sd-5', q:'Cache-aside vs write-through vs write-behind: when do you use each pattern?', a:'**Cache-aside** (lazy loading)\n- App reads cache; on miss, reads DB and populates cache\n- Most common; simple; cache can go stale\n\n**Write-through**\n- Writes go to cache + DB **synchronously**\n- Cache stays consistent; writes are slower\n- Good when reads dominate and staleness is unacceptable\n\n**Write-behind** (write-back)\n- Writes hit cache; DB is updated **async**\n- Fast writes; risks data loss on cache crash\n- Use only for tolerable-loss data (metrics, counters)' },
  { id:'fc-sd-30', cat:'sysd', module:'sd-classic', lesson:'sd-5', q:'LRU vs LFU cache eviction: when does each win?', a:'**`LRU`** (least-recently-used)\n- Evicts the entry untouched longest\n- Good for **recency-biased** workloads (news feeds, sessions, recent files)\n- Simple to implement (`O(1)` with hashmap + doubly-linked list)\n\n**`LFU`** (least-frequently-used)\n- Evicts the entry with the lowest hit count\n- Good for **stable hot sets** where one-time bursts shouldn\'t evict popular items\n- Needs **decay** (e.g., `TinyLFU`) to forget historical frequencies' },
  { id:'fc-sd-31', cat:'sysd', module:'sd-classic', lesson:'sd-raft', q:'Sync vs async replication: what\'s the tradeoff and when do you pick each?', a:'**Sync replication**\n- Primary waits for replica ack before responding\n- **Zero data loss** (`RPO = 0`) but **higher latency**\n- Write stalls if a replica is slow or down\n\n**Async replication**\n- Primary responds immediately; replicates in background\n- **Low latency** but `RPO > 0` on primary failure\n- Standard for cross-region replication\n\n**Semi-sync:** wait for **one** replica\'s ack (compromise; common in `MySQL`, `Postgres`).' },
  { id:'fc-sd-32', cat:'sysd', module:'sd-classic', lesson:'sd-raft', q:'In Raft, what triggers a new leader election?', a:'**Trigger:** a follower\'s **randomized election timeout** expires without receiving a heartbeat from the leader (typical range `150-300 ms`).\n\n**Sequence:**\n1. Follower increments its `term` and becomes a **candidate**\n2. Votes for itself, sends `RequestVote` RPCs to all peers\n3. Wins if it receives a **majority quorum** of votes\n4. On win, sends heartbeats and becomes leader\n\n**Why randomized:** prevents split votes when multiple followers time out simultaneously.' },
  { id:'fc-sd-33', cat:'sysd', module:'sd-classic', lesson:'sd-raft', q:'Raft vs Paxos: what\'s the practical difference?', a:'Both achieve consensus over an asynchronous network with **majority quorum**.\n\n**`Raft`**\n- Designed for **understandability**\n- Explicit **leader, log replication, election** as named subproblems\n- Standard in `etcd`, `Consul`, `CockroachDB`, `TiKV`\n\n**`Paxos` (Multi-Paxos)**\n- Older, more flexible\n- **Notoriously hard** to implement correctly\n- Used in `Spanner`, `Chubby`, `ZooKeeper` (ZAB is a Paxos variant)' },
  { id:'fc-sd-34', cat:'sysd', module:'sd-classic', lesson:'sd-pay', q:'2PC vs saga for distributed transactions: which dominates in microservices and why?', a:'**`2PC` (two-phase commit)**\n- `prepare` + `commit` across all participants\n- **Blocks if coordinator fails** (participants hold locks indefinitely)\n- Requires `XA`-capable resources\n- Rare in modern microservices\n\n**Saga**\n- Chain of local transactions with **compensations**\n- Non-blocking; eventually consistent; no global lock\n- Works across services, regions, and third-party APIs\n\n**Sagas dominate** because microservices can\'t afford `2PC`\'s blocking semantics.' },
  { id:'fc-sd-35', cat:'sysd', module:'sd-classic', lesson:'sd-outbox', q:'What dual-write problem does the transactional outbox pattern solve?', a:'**Problem:** if you write to the DB then publish to `Kafka` as two separate operations, a crash between them leaves DB and message broker **out of sync**.\n\n**Solution:**\n1. In the same DB transaction, write the business row AND insert into an **`outbox` table**\n2. A relay process (or `CDC`) **reads from `outbox`** and publishes to the broker\n3. Mark rows as published (or delete) after broker ack\n\n**Guarantee:** at-least-once delivery, atomic with the DB commit.' },
  { id:'fc-sd-36', cat:'sysd', module:'sd-classic', lesson:'sd-outbox', q:'CDC vs polling for draining the outbox table: which do you pick?', a:'**Polling**\n- Read the `outbox` table on a schedule\n- Simple but adds latency (poll interval)\n- Bad cursors can miss rows; needs careful watermarking\n\n**`CDC`** (Change Data Capture)\n- Tools like `Debezium` or `Postgres` logical replication tail the `WAL`\n- Streams changes in **near real-time** with no app changes\n- Handles ordering and exactly-once-per-change semantics\n\n**`CDC` is the modern default** for high-volume systems.' },
  { id:'fc-sd-37', cat:'sysd', module:'sd-classic', lesson:'sd-kafka', q:'In Kafka, how is message ordering guaranteed and what does that mean for partition-key design?', a:'**Guarantee:** ordering is guaranteed **only within a single partition**.\n\n**Mechanism:**\n- Producers pick partition by **key hash** (same key -> same partition)\n- To preserve **per-entity order** (e.g., per user, per account), use that entity\'s ID as the partition key\n- Cross-partition order is **not guaranteed**\n\n**Tradeoff:** keying narrowly preserves order but risks **hot partitions**; keying broadly distributes load but loses entity-level ordering.' },
  { id:'fc-sd-38', cat:'sysd', module:'sd-classic', lesson:'sd-kafka', q:'Kafka vs SQS vs Kinesis vs RabbitMQ: which do you pick for which workload?', a:'**`Kafka`**\n- High throughput, **replayable log**, consumer groups\n- You operate it (or `MSK`/`Confluent` Cloud)\n\n**`SQS`**\n- Simple managed queue; no ordering (standard) or `FIFO` with low throughput\n- Best for decoupling work, not event streaming\n\n**`Kinesis`**\n- AWS-managed log similar to Kafka; tight AWS integration; lower throughput ceiling\n\n**`RabbitMQ`**\n- Rich routing (topics, headers, RPC); lower throughput; classic queue semantics' },
  { id:'fc-sd-39', cat:'sysd', module:'sd-fde', lesson:'fd-2', q:'When designing webhook signature verification, what exactly goes into the HMAC?', a:'**Input:** `HMAC-SHA256(timestamp + raw_body, shared_secret)`\n\n**Receiver checks:**\n- Signature matches\n- **Timestamp within skew window** (e.g., 5 min) to block replay\n- Secret has been **rotated** within the rotation window\n\n**Critical detail:** sign the **raw body bytes**, not the parsed JSON. Re-serialization changes whitespace and key order, breaking verification.' },
  { id:'fc-sd-40', cat:'sysd', module:'sd-fde', lesson:'fd-3', q:'What\'s the difference between SAML SP-initiated and IDP-initiated flows, and which is preferred?', a:'**SP-initiated** (preferred)\n1. User visits the app (SP)\n2. SP redirects to IDP with an `AuthnRequest`\n3. User authenticates at IDP\n4. IDP posts a **signed assertion** back to the SP\'s `ACS` URL\n\n**IDP-initiated**\n1. User starts at the IDP dashboard (e.g., Okta tile)\n2. IDP posts the assertion directly to the SP\n\n**SP-init is more secure** because the SP issues the `AuthnRequest` and can validate the response was solicited (prevents unsolicited assertion attacks).' },
  { id:'fc-sd-41', cat:'sysd', module:'sd-fde', lesson:'fd-3', q:'When selling enterprise SSO, when do you pick OIDC vs SAML, and what does SCIM add?', a:'**`OIDC`** (OAuth 2.0 + identity layer)\n- `JWT` ID tokens, JSON over HTTPS\n- Pick for **modern web/mobile** apps\n\n**`SAML`** (XML assertions, older)\n- Dominant in **enterprise B2B**\n- Required when selling to customers whose IDPs (`Okta`, `Azure AD`, `ADFS`) are SAML-first\n\n**`SCIM`** (System for Cross-domain Identity Management)\n- **User provisioning/deprovisioning** protocol\n- Works alongside both `OIDC` and `SAML`\n- Required for enterprise lifecycle automation' },
  { id:'fc-sd-42', cat:'sysd', module:'sd-fde', lesson:'fd-4', q:'In a BYOC (bring-your-own-cloud) deploy, what does the vendor manage vs what stays in the customer\'s account?', a:'**Vendor\'s account** (control plane)\n- Orchestration, billing, deployment automation, vendor-side observability\n\n**Customer\'s VPC/account** (data plane)\n- Runtime workloads, customer data storage, customer-controlled networking\n- Customer data **never leaves their cloud**\n\n**Glue:** vendor uses **cross-account `IAM` roles** to deploy and manage the data plane.\n\n**Tradeoff:** costs the vendor more (per-customer infra), but unlocks regulated industries (finance, healthcare, gov).' },
  { id:'fc-sd-43', cat:'sysd', module:'sd-classic', lesson:'sd-2', q:'When designing a URL shortener, what are the main short-code generation strategies?', a:'**Strategy 1 - Hash + base62**\n- `hash(url)`, take top `N` chars, base62-encode\n- Deterministic; needs collision check\n\n**Strategy 2 - Auto-increment ID + base62**\n- Compact; sequential\n- **Leaks total volume** to anyone who looks\n\n**Strategy 3 - Pre-generated pool**\n- Generate random codes offline, hand out from a queue\n- No write contention; easy to scale\n\n**Sizing:** 7 base62 chars = `62^7 ~= 3.5T codes`.' },
  { id:'fc-sd-44', cat:'sysd', module:'sd-classic', lesson:'sd-tail', q:'How do hedged requests reduce p99 latency, and what\'s the cost?', a:'**Mechanism:**\n1. Send the request to **one replica**\n2. If no response within (e.g.) `p95` latency, send a **duplicate to a second replica**\n3. Take whichever returns first\n4. **Cancel the loser** to save work\n\n**Result:** dramatic `p99` reduction with low extra load (only the slow ~5% are duplicated).\n\n**Origin:** Google\'s \'The Tail at Scale\' paper.\n\n**Caveat:** requires idempotent reads; not safe for side-effecting calls without dedup.' },
  { id:'fc-sd-45', cat:'sysd', module:'sd-classic', lesson:'sd-tracing', q:'In W3C trace context, which header propagates the trace across service boundaries?', a:'**`traceparent` header** carries:\n- `version` (1 byte)\n- `trace-id` (16 bytes, unique per request)\n- `parent-span-id` (8 bytes, the caller\'s span)\n- `flags` (sampling, etc.)\n\n**`tracestate` header** carries vendor-specific metadata.\n\n**Rule:** every service MUST propagate `traceparent` on outgoing calls so spans across services **join into one trace**. `OpenTelemetry` SDKs handle this automatically via context propagation.' },
  { id:'fc-sd-46', cat:'sysd', module:'sd-classic', lesson:'sd-tracing', q:'What are the three pillars of observability and what question does each answer?', a:'**Logs** - \'what happened?\'\n- Discrete events; high cardinality\n- Expensive at scale; best for forensics\n\n**Metrics** - \'how much / how often?\'\n- Aggregated time series; cheap\n- Best for **alerting** and dashboards\n\n**Traces** - \'how did this request flow?\'\n- Latency breakdown per span; dependency mapping\n- Best for debugging **cross-service** slowness\n\nYou need all three; **none subsumes the others**.' },
  { id:'fc-sd-47', cat:'sysd', module:'sd-classic', lesson:'sd-cells', q:'What is a \'cell\' in cell-based architecture, and what problem does it solve?', a:'**Cell:** an isolated, full-stack slice of the system (compute + DB + cache) that serves a **partition of users**.\n\n**Properties:**\n- Cells share nothing at runtime\n- A **router** maps tenant -> cell\n- Bad deploys, noisy tenants, and bugs are contained to **one cell**\n\n**Problem solved:** **blast radius** of any failure is capped at `1/N` of users.\n\n**Used by:** `AWS` (many services), `Slack`, `Stripe`, `Shopify`.' },
  { id:'fc-sd-48', cat:'sysd', module:'sd-fde', lesson:'fd-8', q:'When picking a wire format, when do you pick gRPC vs REST vs GraphQL?', a:'**`gRPC`**\n- Internal **service-to-service**\n- Strong typing (`protobuf`), `HTTP/2` streaming, low latency\n- Bad for browsers without a proxy\n\n**`REST`**\n- **Public APIs**; broadest client support\n- HTTP caching; easy to debug with `curl`\n\n**`GraphQL`**\n- **Client-driven queries**; avoids over/under-fetching\n- Good for mobile and aggregation layers over many backends\n- Caching and rate-limiting are harder\n\n**Rule:** pick by client (browser/mobile/internal) and evolution needs.' },
  { id:'fc-sd-49', cat:'sysd', module:'sd-fde', lesson:'fd-6', q:'For vector search at billion-scale, how do HNSW, IVF, and PQ compare?', a:'**`HNSW`** (Hierarchical Navigable Small World)\n- Hierarchical graph index\n- **High recall, low latency**\n- **High memory** (full vectors in RAM)\n\n**`IVF`** (Inverted File Index)\n- Cluster vectors into Voronoi cells\n- Query scans top-`N` cells\n- **Lower memory**, tunable recall via `nprobe`\n\n**`PQ`** (Product Quantization)\n- Compress vectors into short codes\n- `8-16x smaller`; **lossy**\n\n**Production stacks** often combine **`IVF + PQ`** for billion-scale recall/cost tradeoffs.' },
  { id:'fc-sd-50', cat:'sysd', module:'sd-classic', lesson:'sd-geo', q:'What geo-indexing structure do you use for real-time ride-matching at Uber scale?', a:'**`Geohash` or `S2` cell IDs** as the shard/index key.\n\n**Mechanism:**\n1. Drivers publish `(cell_id, lat, lng)` every few seconds to `Redis` **sorted sets** keyed by cell\n2. To match a rider, query **nearby cells** (neighboring geohashes or `S2` cover of the search radius)\n3. Pick the closest driver from the union\n\n**Alternatives:**\n- **Quadtrees / R-trees** for variable-density regions (e.g., dense urban + sparse rural in one index)' },
];

